logging.basicConfig(level=logging.INFO, format="%(asctime)s - %(name)s - %(levelname)s - %(message)s")
logger = logging.getLogger("portal")


def quote_ident(name: str, dialect_name: str) -> str:
    quote = "`" if dialect_name == "mysql" else '"'
    return f"{quote}{name}{quote}"


def column_sql_type(column: Column) -> str:
    if isinstance(column.type, Text):
        return "TEXT"
    if isinstance(column.type, String):
        return f"VARCHAR({column.type.length or 255})"
    if isinstance(column.type, Integer):
        return "INTEGER"
    if isinstance(column.type, Boolean):
        return "BOOLEAN"
    return "TEXT"


async def ensure_schema_columns(conn):
    """Add columns introduced after the first SQL deployment.

    SQLAlchemy's create_all creates missing tables, but it will not alter an
    existing table. This keeps early VPS databases compatible without a full
    migration framework yet.
    """
    dialect_name = conn.dialect.name
    for table in (
        users,
        outstanding_items,
        submissions,
        pending_client_uploads,
        settings,
        client_integrations,
        integration_records,
        accounting_accounts,
        accounting_settings,
        accounting_contacts,
        accounting_ap_settings,
        accounting_ap_supplier_profiles,
        accounting_ap_supplier_addresses,
        accounting_ap_supplier_contacts,
        accounting_ap_invoices,
        accounting_ap_invoice_lines,
        accounting_ap_credit_notes,
        accounting_ap_credit_note_lines,
        accounting_ap_payments,
        accounting_ap_payment_allocations,
        accounting_ar_settings,
        accounting_ar_customer_profiles,
        accounting_ar_customer_addresses,
        accounting_ar_customer_contacts,
        accounting_ar_invoices,
        accounting_ar_invoice_lines,
        accounting_ar_credit_notes,
        accounting_ar_credit_note_lines,
        accounting_ar_receipts,
        accounting_ar_receipt_allocations,
        accounting_journal_entries,
        accounting_journal_lines,
        accounting_audit_log,
        accounting_bank_transactions,
        accounting_bank_accounts,
        accounting_bank_imports,
        accounting_bank_rules,
        accounting_bank_matches,
        accounting_bank_transfers,
        accounting_bank_settings,
        accounting_vat_returns,
        accounting_vat_settings,
        accounting_vat_codes,
        accounting_vat_periods,
        accounting_vat_adjustments,
        accounting_periods,
        accounting_financial_years,
        accounting_fixed_asset_settings,
        accounting_fixed_asset_categories,
        accounting_fixed_assets,
        accounting_fixed_asset_depreciation,
        accounting_fixed_asset_events,
        accounting_year_end_settings,
        accounting_year_end_events,
        accounting_opening_balances,
        automation_workflows,
        automation_runs,
        automation_approvals,
        automation_exceptions,
        automation_templates,
        automation_settings,
        integration_hub_connections,
        integration_hub_sync_runs,
        integration_hub_api_keys,
        integration_hub_webhooks,
        integration_hub_logs,
        integration_hub_settings,
        platform_roles,
        platform_user_roles,
        platform_background_jobs,
        platform_notifications,
        platform_activity_feed,
        platform_health_checks,
        platform_error_logs,
    ):
        existing_column_info = await conn.run_sync(
            lambda sync_conn, table_name=table.name: {
                col["name"]: col for col in inspect(sync_conn).get_columns(table_name)
            }
        )
        existing_columns = set(existing_column_info)
        for column in table.columns:
            if column.primary_key or column.name in existing_columns:
                continue
            column_def = f"{quote_ident(column.name, dialect_name)} {column_sql_type(column)}"
            if column.name == "status":
                column_def += " DEFAULT 'active'"
            elif column.name == "review_status":
                column_def += " DEFAULT 'inbox'"
            await conn.execute(
                text(
                    f"ALTER TABLE {quote_ident(table.name, dialect_name)} "
                    f"ADD COLUMN {column_def}"
                )
            )
            logger.info("Added missing column %s.%s", table.name, column.name)
        if dialect_name == "mysql":
            for column in table.columns:
                if column.name not in existing_column_info or not isinstance(column.type, Text):
                    continue
                existing_type = str(existing_column_info[column.name]["type"]).lower()
                if "text" in existing_type:
                    continue
                await conn.execute(
                    text(
                        f"ALTER TABLE {quote_ident(table.name, dialect_name)} "
                        f"MODIFY COLUMN {quote_ident(column.name, dialect_name)} TEXT"
                    )
                )
                logger.info("Widened column %s.%s to TEXT", table.name, column.name)
    submissions_info = await conn.run_sync(
        lambda sync_conn: {col["name"]: col for col in inspect(sync_conn).get_columns("submissions")}
    )
    required_submission_columns = {
        "ai_review_status": "VARCHAR",
        "ai_review_message": "TEXT",
        "ai_document_type": "VARCHAR",
        "ai_extracted_fields": "TEXT",
        "ai_client_approved": "BOOLEAN",
        "comment": "TEXT",
    }
    for column_name, expected_type in required_submission_columns.items():
        column_info = submissions_info.get(column_name)
        if not column_info:
            logger.error("submissions.%s is missing after schema migration", column_name)
            continue
        logger.info("Verified submissions.%s type=%s expected=%s", column_name, column_info.get("type"), expected_type)


async def ensure_table_columns(conn, tables: tuple[Table, ...]):
    dialect_name = conn.dialect.name
    for table in tables:
        existing_column_info = await conn.run_sync(
            lambda sync_conn, table_name=table.name: {
                col["name"]: col for col in inspect(sync_conn).get_columns(table_name)
            }
        )
        existing_columns = set(existing_column_info)
        for column in table.columns:
            if column.primary_key or column.name in existing_columns:
                continue
            column_def = f"{quote_ident(column.name, dialect_name)} {column_sql_type(column)}"
            if column.name == "status":
                column_def += " DEFAULT 'active'"
            await conn.execute(
                text(
                    f"ALTER TABLE {quote_ident(table.name, dialect_name)} "
                    f"ADD COLUMN {column_def}"
                )
            )
            logger.info("Added missing column %s.%s", table.name, column.name)


@asynccontextmanager
async def lifespan(app: FastAPI):
    for attempt in range(1, 31):
        try:
            async with engine.begin() as conn:
                await conn.run_sync(metadata.create_all)
                await ensure_schema_columns(conn)
            break
        except OperationalError:
            if attempt == 30:
                raise
            logger.info("Database not ready yet; retrying startup (%s/30)", attempt)
            await asyncio.sleep(2)

    admin_email = os.environ.get("ADMIN_EMAIL", "admin@example.com").lower().strip()
    admin_password = os.environ.get("ADMIN_PASSWORD", "admin123")
    async with SessionLocal() as session:
        existing = await get_user_by_email(session, admin_email)
        if existing is None:
            await session.execute(
                insert(users).values(
                    id=new_id(),
                    email=admin_email,
                    password_hash=hash_password(admin_password),
                    role="admin",
                    first_name="Practice",
                    last_name="Admin",
                    status="active",
                    created_at=utc_now_iso(),
                )
            )
            await session.commit()
            logger.info("Admin seeded: %s", admin_email)
        elif not verify_password(admin_password, existing["password_hash"]):
            await session.execute(
                update(users)
                .where(users.c.id == existing["id"])
                .values(password_hash=hash_password(admin_password), role="admin")
            )
            await session.commit()
            logger.info("Admin password updated.")
    yield
    await engine.dispose()


app = FastAPI(lifespan=lifespan)
api = APIRouter(prefix="/api")


@app.middleware("http")
async def correlation_id_middleware(request: Request, call_next):
    correlation_id = request.headers.get("X-Correlation-ID") or uuid.uuid4().hex[:12]
    request.state.correlation_id = correlation_id
    try:
        response = await call_next(request)
    except Exception as exc:
        logger.exception("Unhandled request error correlation_id=%s path=%s", correlation_id, request.url.path)
        try:
            async with SessionLocal() as session:
                await session.execute(
                    insert(platform_error_logs).values(
                        id=new_id(),
                        correlation_id=correlation_id,
                        path=request.url.path,
                        method=request.method,
                        status_code=500,
                        message=str(exc)[:1000],
                        details=repr(exc)[:4000],
                        created_at=utc_now_iso(),
                    )
                )
                await session.commit()
        except Exception:
            logger.exception("Failed to persist platform error log correlation_id=%s path=%s", correlation_id, request.url.path)
        return JSONResponse(
            status_code=500,
            content={
                "ok": False,
                "detail": f"Unexpected server error. Reference {correlation_id}.",
                "correlation_id": correlation_id,
            },
            headers={"X-Correlation-ID": correlation_id},
        )
    response.headers["X-Correlation-ID"] = correlation_id
    if response.status_code >= 500:
        try:
            async with SessionLocal() as session:
                await session.execute(
                    insert(platform_error_logs).values(
                        id=new_id(),
                        correlation_id=correlation_id,
                        path=request.url.path,
                        method=request.method,
                        status_code=response.status_code,
                        message=f"HTTP {response.status_code}",
                        created_at=utc_now_iso(),
                    )
                )
                await session.commit()
        except Exception:
            logger.exception("Failed to persist platform error log correlation_id=%s path=%s", correlation_id, request.url.path)
    return response


