# ---------- Helpers ----------
def new_id() -> str:
    return str(uuid.uuid4())


def utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def row_dict(row) -> Optional[dict]:
    return dict(row) if row else None


async def get_db():
    async with SessionLocal() as session:
        yield session


async def one(session: AsyncSession, stmt) -> Optional[dict]:
    result = await session.execute(stmt)
    return row_dict(result.mappings().first())


async def many(session: AsyncSession, stmt) -> list[dict]:
    result = await session.execute(stmt)
    return [dict(row) for row in result.mappings().all()]


def money(value: Any, default: str = "0.00") -> Decimal:
    raw = str(value if value not in (None, "") else default).strip()
    raw = raw.replace("£", "").replace(",", "")
    if not raw:
        raw = default
    try:
        return Decimal(raw).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    except (InvalidOperation, ValueError):
        return Decimal(default).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def money_str(value: Decimal) -> str:
    return str(value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))


def clean_accounting_destination(value: Optional[str], native_enabled: bool = False) -> str:
    destination = (value or "").strip().lower()
    if destination == "epos_native":
        destination = "native"
    if destination in {"native", "external"}:
        return destination
    if native_enabled:
        return "native"
    return "external"


def is_native_accounting_client(client: Optional[dict]) -> bool:
    if not client:
        return False
    destination = str(client.get("accounting_destination") or "").strip().lower()
    if destination == "epos_native":
        destination = "native"
    if destination in {"native", "external"}:
        return destination == "native"
    return bool(client.get("native_accounting_enabled"))


def account_matches(account: dict, value: Optional[str]) -> bool:
    candidate = (value or "").strip().lower()
    if not candidate:
        return False
    return candidate in {
        str(account.get("code") or "").strip().lower(),
        str(account.get("name") or "").strip().lower(),
        f"{account.get('code') or ''} - {account.get('name') or ''}".strip().lower(),
    }


def payload_bool_alias(payload: dict, aliases: tuple[str, ...], default: bool = False) -> bool:
    for key in aliases:
        if key not in payload:
            continue
        value = payload.get(key)
        if isinstance(value, bool):
            return value
        if isinstance(value, (int, float)):
            return bool(value)
        if isinstance(value, str):
            return value.strip().lower() in {"1", "true", "yes", "y", "on"}
        return bool(value)
    return default


def account_banking_enabled(row: dict) -> bool:
    return bool(row.get("banking_enabled")) or bool(row.get("show_in_banking")) or bool(row.get("show_in_banking_page"))


def apply_banking_account_defaults(values: dict) -> dict:
    if not bool(values.get("banking_enabled")):
        return values
    values["category"] = "Asset"
    values["purpose"] = "Bank Account"
    values["normal_balance"] = "debit"
    account_type = str(values.get("account_type") or "").strip()
    if account_type.lower() not in {"bank", "current asset"}:
        values["account_type"] = "Bank"
    return values


def is_bank_compatible_account(row: dict) -> bool:
    if account_statement_section(row) != "balance_sheet":
        return False
    account_type = str(row.get("account_type") or "").strip().lower()
    purpose = str(row.get("purpose") or "").strip().lower()
    name = str(row.get("name") or "").strip().lower()
    return (
        account_type in {"bank", "current asset", "cash", "credit card", "clearing", "suspense"}
        or purpose in {"bank account", "cash account", "card account", "clearing account"}
        or any(term in name for term in ("bank", "cash", "card", "clearing"))
    )


async def ensure_native_accounting_client(session: AsyncSession, client_id: str) -> list[dict]:
    now = utc_now_iso()
    existing = await many(
        session,
        select(accounting_accounts)
        .where(accounting_accounts.c.client_id == client_id)
        .order_by(accounting_accounts.c.code.asc()),
    )
    if existing:
        defaults_by_code = {item["code"]: item for item in DEFAULT_NATIVE_ACCOUNTS}
        existing_codes = {str(item.get("code") or "") for item in existing}
        for default_account in DEFAULT_NATIVE_ACCOUNTS:
            if default_account["code"] in existing_codes:
                continue
            await session.execute(
                insert(accounting_accounts).values(
                    id=new_id(),
                    client_id=client_id,
                    created_at=now,
                    updated_at=now,
                    active=True,
                    **default_account,
                )
            )
        for account in existing:
            defaults = defaults_by_code.get(str(account.get("code") or ""), {})
            values = {}
            if not account.get("category"):
                values["category"] = defaults.get("category") or infer_account_category(account.get("account_type"))
            if not account.get("purpose"):
                values["purpose"] = defaults.get("purpose") or infer_account_purpose(account)
            if not account.get("description") and defaults.get("description"):
                values["description"] = defaults.get("description")
            if not account.get("name") and defaults.get("name"):
                values["name"] = defaults.get("name")
            if account.get("is_control_account") is None:
                values["is_control_account"] = bool(account.get("control_account")) or bool(defaults.get("is_control_account"))
            if bool(defaults.get("banking_enabled")) and not bool(account.get("banking_enabled")):
                values["banking_enabled"] = True
            if values:
                values["updated_at"] = now
                await session.execute(update(accounting_accounts).where(accounting_accounts.c.id == account["id"]).values(**values))
        await ensure_accounting_settings(session, client_id)
        await ensure_vat_settings(session, client_id)
        await ensure_vat_codes(session, client_id)
        await session.flush()
        return await many(
            session,
            select(accounting_accounts)
            .where(accounting_accounts.c.client_id == client_id)
            .order_by(accounting_accounts.c.code.asc()),
        )
    for account in DEFAULT_NATIVE_ACCOUNTS:
        await session.execute(
            insert(accounting_accounts).values(
                id=new_id(),
                client_id=client_id,
                created_at=now,
                updated_at=now,
                active=True,
                **account,
            )
        )
    await session.execute(
        update(users)
        .where(users.c.id == client_id, users.c.role == "client")
        .values(
            accounting_destination="native",
            native_accounting_enabled=True,
            native_accounting_created_at=now,
        )
    )
    await session.flush()
    await ensure_accounting_settings(session, client_id)
    await ensure_vat_settings(session, client_id)
    await ensure_vat_codes(session, client_id)
    await session.flush()
    return await many(
        session,
        select(accounting_accounts)
        .where(accounting_accounts.c.client_id == client_id)
        .order_by(accounting_accounts.c.code.asc()),
    )


def find_native_account(accounts: list[dict], preferred: Optional[str], fallback_code: str) -> dict:
    for account in accounts:
        if account_matches(account, preferred):
            return account
    for account in accounts:
        if str(account.get("code") or "") == fallback_code:
            return account
    raise HTTPException(status_code=400, detail=f"Native accounting account {fallback_code} is missing.")


async def get_or_create_native_contact(session: AsyncSession, client_id: str, name: str, contact_type: str) -> Optional[dict]:
    clean_name = (name or "").strip()
    if not clean_name:
        return None
    existing = await one(
        session,
        select(accounting_contacts).where(
            accounting_contacts.c.client_id == client_id,
            accounting_contacts.c.contact_type == contact_type,
            func.lower(accounting_contacts.c.name) == clean_name.lower(),
        ),
    )
    if existing:
        return existing
    now = utc_now_iso()
    contact = {
        "id": new_id(),
        "client_id": client_id,
        "contact_type": contact_type,
        "name": clean_name,
        "active": True,
        "created_at": now,
        "updated_at": now,
    }
    await session.execute(insert(accounting_contacts).values(**contact))
    return contact


def submission_entry_date(submission: dict, coding_fields: dict) -> str:
    return quickbooks_date(coding_fields.get("date") or submission.get("date")) or datetime.now(timezone.utc).date().isoformat()


async def post_native_journal(
    session: AsyncSession,
    client_id: str,
    source_type: str,
    source_id: str,
    entry_date: str,
    reference: str,
    description: str,
    lines: list[dict],
    actor_id: Optional[str] = None,
) -> dict:
    locked_period = await one(
        session,
        select(accounting_periods).where(
            accounting_periods.c.client_id == client_id,
            accounting_periods.c.period_start <= entry_date,
            accounting_periods.c.period_end >= entry_date,
            accounting_periods.c.status.in_(["locked", "closed"]),
        ),
    )
    if locked_period:
        raise HTTPException(status_code=400, detail=f"Accounting period is {locked_period.get('status')}; reopen it before posting.")
    total_debit = sum((money(line.get("debit")) for line in lines), Decimal("0.00"))
    total_credit = sum((money(line.get("credit")) for line in lines), Decimal("0.00"))
    if total_debit <= Decimal("0.00") or total_credit <= Decimal("0.00"):
        raise HTTPException(status_code=400, detail="Native accounting journal needs debit and credit values.")
    if total_debit != total_credit:
        raise HTTPException(status_code=400, detail=f"Native accounting journal is not balanced: debit {money_str(total_debit)} / credit {money_str(total_credit)}.")
    now = utc_now_iso()
    entry_id = new_id()
    await session.execute(
        insert(accounting_journal_entries).values(
            id=entry_id,
            client_id=client_id,
            source_type=source_type,
            source_id=source_id,
            entry_date=entry_date,
            reference=reference[:255],
            description=description,
            status="posted",
            total_debit=money_str(total_debit),
            total_credit=money_str(total_credit),
            created_at=now,
            posted_at=now,
        )
    )
    for line in lines:
        account = line["account"]
        await session.execute(
            insert(accounting_journal_lines).values(
                id=new_id(),
                entry_id=entry_id,
                client_id=client_id,
                account_id=account.get("id"),
                account_code=account.get("code"),
                account_name=account.get("name"),
                contact_id=(line.get("contact") or {}).get("id"),
                debit=money_str(money(line.get("debit"))),
                credit=money_str(money(line.get("credit"))),
                vat_code=line.get("vat_code"),
                description=line.get("description"),
                created_at=now,
            )
        )
    await session.execute(
        insert(accounting_audit_log).values(
            id=new_id(),
            client_id=client_id,
            actor_id=actor_id,
            action="journal_posted",
            entity_type="journal_entry",
            entity_id=entry_id,
            details_json=json.dumps({"source_type": source_type, "source_id": source_id, "debit": money_str(total_debit), "credit": money_str(total_credit)}),
            created_at=now,
        )
    )
    return {
        "provider": "epos_native",
        "entity": "JournalEntry",
        "id": entry_id,
        "reference": reference,
        "total_debit": money_str(total_debit),
        "total_credit": money_str(total_credit),
        "posted_at": now,
    }


async def reverse_native_journal(session: AsyncSession, client_id: str, journal_id: str, source_type: str, source_id: str, actor_id: Optional[str]) -> dict:
    original = await one(session, select(accounting_journal_entries).where(accounting_journal_entries.c.client_id == client_id, accounting_journal_entries.c.id == journal_id))
    if not original:
        raise HTTPException(status_code=400, detail="The original posted journal could not be found.")
    original_lines = await many(session, select(accounting_journal_lines).where(accounting_journal_lines.c.client_id == client_id, accounting_journal_lines.c.entry_id == journal_id).order_by(accounting_journal_lines.c.created_at.asc()))
    if not original_lines:
        raise HTTPException(status_code=400, detail="The original journal has no lines to reverse.")
    reversal_lines = [{
        "account": {"id": line.get("account_id"), "code": line.get("account_code"), "name": line.get("account_name")},
        "contact": {"id": line.get("contact_id")} if line.get("contact_id") else {},
        "debit": line.get("credit"),
        "credit": line.get("debit"),
        "vat_code": line.get("vat_code"),
        "description": f"Reversal: {line.get('description') or original.get('description') or ''}",
    } for line in original_lines]
    return await post_native_journal(session, client_id, source_type, source_id, datetime.now(timezone.utc).date().isoformat(), f"REV-{original.get('reference') or journal_id}"[:255], f"Reversal of {original.get('description') or journal_id}", reversal_lines, actor_id)


async def count_rows(session: AsyncSession, table: Table, *conditions) -> int:
    stmt = select(func.count()).select_from(table)
    if conditions:
        stmt = stmt.where(and_(*conditions))
    result = await session.execute(stmt)
    return int(result.scalar_one())


def pagination_params(page: int = 1, page_size: int = 50) -> tuple[int, int]:
    try:
        page_value = int(page or 1)
    except (TypeError, ValueError):
        page_value = 1
    try:
        size_value = int(page_size or 50)
    except (TypeError, ValueError):
        size_value = 50
    return max(page_value, 1), min(max(size_value, 1), 250)


def paginated_payload(rows: list[dict], page: int, page_size: int, total_rows: int, summary: Optional[dict] = None) -> dict:
    total_pages = (total_rows + page_size - 1) // page_size if total_rows else 0
    return {
        "rows": rows,
        "page": page,
        "page_size": page_size,
        "total_rows": total_rows,
        "total_pages": total_pages,
        "summary": summary or {},
    }


def approximate_payload_size(payload: Any) -> int:
    try:
        return len(json.dumps(payload, default=str))
    except Exception:
        return 0


async def paginated_select(
    session: AsyncSession,
    table: Table,
    conditions: list[Any],
    order_by: list[Any],
    page: int,
    page_size: int,
) -> tuple[list[dict], int]:
    stmt = select(table)
    count_stmt = select(func.count()).select_from(table)
    if conditions:
        where_clause = and_(*conditions)
        stmt = stmt.where(where_clause)
        count_stmt = count_stmt.where(where_clause)
    total = int((await session.execute(count_stmt)).scalar_one() or 0)
    rows = await many(session, stmt.order_by(*order_by).offset((page - 1) * page_size).limit(page_size))
    return rows, total


def lower_like(column: Any, search: str):
    return func.lower(column).like(f"%{str(search or '').strip().lower()}%")


def text_search_condition(search: Optional[str], *columns: Any) -> Optional[Any]:
    needle = str(search or "").strip()
    if not needle:
        return None
    return or_(*[lower_like(column, needle) for column in columns])


def date_range_conditions(column: Any, date_from: Optional[str], date_to: Optional[str]) -> list[Any]:
    conditions: list[Any] = []
    if date_from:
        conditions.append(column >= str(date_from))
    if date_to:
        conditions.append(column <= str(date_to))
    return conditions


async def get_user_by_email(session: AsyncSession, email: str) -> Optional[dict]:
    return await one(session, select(users).where(users.c.email == email.lower().strip()))


async def get_user_by_id(session: AsyncSession, user_id: str) -> Optional[dict]:
    return await one(session, select(users).where(users.c.id == user_id))


def parse_ses_region(host: str) -> Optional[str]:
    """Extract AWS region from an SES SMTP host like email-smtp.eu-west-2.amazonaws.com."""
    parts = (host or "").lower().strip().split(".")
    if len(parts) >= 4 and parts[0] == "email-smtp" and parts[-2] == "amazonaws" and parts[-1] == "com":
        return parts[1]
    return None


def derive_ses_smtp_password(secret_access_key: str, region: str) -> str:
    """Convert an AWS IAM secret access key into an Amazon SES SMTP password (AWS-documented algorithm)."""
    def sign(key: bytes, msg: str) -> bytes:
        return hmac.new(key, msg.encode("utf-8"), hashlib.sha256).digest()
    sig = sign(("AWS4" + secret_access_key).encode("utf-8"), "11111111")
    sig = sign(sig, region)
    sig = sign(sig, "ses")
    sig = sign(sig, "aws4_request")
    sig = sign(sig, "SendRawEmail")
    return base64.b64encode(bytes([0x04]) + sig).decode("utf-8")


def hash_password(password: str) -> str:
    return bcrypt.hashpw(password.encode("utf-8"), bcrypt.gensalt()).decode("utf-8")


def verify_password(plain: str, hashed: str) -> bool:
    try:
        return bcrypt.checkpw(plain.encode("utf-8"), hashed.encode("utf-8"))
    except Exception:
        return False


def get_jwt_secret() -> str:
    return os.environ["JWT_SECRET"]


def create_access_token(user_id: str, role: str) -> str:
    payload = {
        "sub": user_id,
        "role": role,
        "exp": datetime.now(timezone.utc) + timedelta(hours=8),
        "type": "access",
    }
    return jwt.encode(payload, get_jwt_secret(), algorithm=JWT_ALGORITHM)


def create_ai_review_token(user_id: str, image_hash: str, review: dict) -> str:
    payload = {
        "sub": user_id,
        "type": "ai_review",
        "image_hash": image_hash,
        "status": review.get("status"),
        "message": review.get("message", ""),
        "document_type": review.get("document_type", ""),
        "payment_method": review.get("payment_method", "not_clear"),
        "coding_fields": review.get("coding_fields") or {},
        "exp": datetime.now(timezone.utc) + timedelta(minutes=20),
    }
    return jwt.encode(payload, get_jwt_secret(), algorithm=JWT_ALGORITHM)


def verify_ai_review_token(token: str, user_id: str, image_hash: str) -> Optional[dict]:
    try:
        payload = jwt.decode(token, get_jwt_secret(), algorithms=[JWT_ALGORITHM])
    except jwt.InvalidTokenError:
        return None
    if (
        payload.get("type") != "ai_review"
        or payload.get("sub") != user_id
        or payload.get("image_hash") != image_hash
        or payload.get("status") not in ("needs_review", "rejected")
    ):
        return None
    return {
        "status": payload.get("status"),
        "message": payload.get("message", ""),
        "document_type": payload.get("document_type", ""),
        "payment_method": payload.get("payment_method", "not_clear"),
        "coding_fields": payload.get("coding_fields") or {},
        "confidence": "medium",
    }


def set_auth_cookie(response: Response, token: str):
    secure_cookie = os.environ.get("COOKIE_SECURE", "false").lower() == "true"
    response.set_cookie(
        key="access_token",
        value=token,
        httponly=True,
        secure=secure_cookie,
        samesite="none" if secure_cookie else "lax",
        max_age=8 * 3600,
        path="/",
    )


def clear_auth_cookie(response: Response):
    response.delete_cookie("access_token", path="/")


async def get_current_user(request: Request, session: AsyncSession = Depends(get_db)) -> dict:
    token = request.cookies.get("access_token")
    if not token:
        auth = request.headers.get("Authorization", "")
        if auth.startswith("Bearer "):
            token = auth[7:]
    if not token:
        raise HTTPException(status_code=401, detail="Not authenticated")
    try:
        payload = jwt.decode(token, get_jwt_secret(), algorithms=[JWT_ALGORITHM])
        if payload.get("type") != "access":
            raise HTTPException(status_code=401, detail="Invalid token type")
        user = await get_user_by_id(session, payload["sub"])
        if not user:
            raise HTTPException(status_code=401, detail="User not found")
        user.pop("password_hash", None)
        return user
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail="Token expired")
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail="Invalid token")


async def require_admin(user: dict = Depends(get_current_user)) -> dict:
    if user.get("role") != "admin":
        raise HTTPException(status_code=403, detail="Admin only")
    return user


async def require_client(user: dict = Depends(get_current_user)) -> dict:
    if user.get("role") != "client":
        raise HTTPException(status_code=403, detail="Client only")
    return user


