async def invoice_source_document_reference(session: AsyncSession, client_id: str, invoice: dict, attachment_url: str, label: str) -> dict:
    filename = str(invoice.get("attachment_path") or "").strip()
    original_filename = str(invoice.get("original_filename") or "").strip()
    submission_id = str(invoice.get("source_submission_id") or "").strip()
    if submission_id:
        submission = await one(session, select(submissions).where(submissions.c.id == submission_id, submissions.c.client_id == client_id))
        if submission:
            filename = str(submission.get("image_filename") or filename or "").strip()
            original_filename = str(submission.get("original_filename") or original_filename or filename).strip()
    has_reference = bool(submission_id or filename)
    available = bool(resolve_upload_path(filename)) if filename else False
    status = "available" if available else ("missing" if has_reference else "none")
    message = ""
    if status == "missing":
        message = f"{label} source document file not found"
    return {
        "source_submission_id": submission_id,
        "attachment_path": filename,
        "original_filename": Path(original_filename or Path(str(filename)).name).name if (original_filename or filename) else "",
        "attachment_url": attachment_url if has_reference else "",
        "document_url": attachment_url if has_reference else "",
        "available": available,
        "missing": status == "missing",
        "status": status,
        "message": message,
    }


def ap_line_values(raw_line: dict, default_account: str = "5000") -> dict:
    quantity = money(first_present(raw_line, "quantity", "units"), "1.00")
    unit_price = money(first_present(raw_line, "unit_price", "price", "rate"))
    discount = money(first_present(raw_line, "discount_amount", "discount"))
    explicit_net = first_present(raw_line, "net_amount", "net", "subtotal")
    net_amount = money(explicit_net) if explicit_net not in (None, "") else (quantity * unit_price - discount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    vat_amount = money(first_present(raw_line, "vat_amount", "vat", "tax_amount", "tax"))
    explicit_gross = first_present(raw_line, "gross_amount", "gross", "total", "amount")
    gross_amount = money(explicit_gross) if explicit_gross not in (None, "") else net_amount + vat_amount
    nominal_source = first_present(
        raw_line,
        "nominal_account_code",
        "purchase_nominal_account_code",
        "purchase_nominal",
        "purchase_account_code",
        "account_code",
        "category_code",
        "nominal_code",
        "nominal",
        "category",
        "account",
    )
    vat_source = first_present(raw_line, "vat_code", "tax_code", "tax_rate_code")
    return {
        "description": str(raw_line.get("description") or "").strip(),
        "nominal_account_code": nominal_account_code_value(nominal_source, default_account or "5000"),
        "quantity": money_str(quantity),
        "unit_price": money_str(unit_price),
        "discount_amount": money_str(discount),
        "vat_code": vat_code_value(vat_source),
        "net_amount": money_str(net_amount),
        "vat_amount": money_str(vat_amount),
        "gross_amount": money_str(gross_amount),
    }


def ap_totals(lines: list[dict]) -> dict:
    net = sum((money(line.get("net_amount")) for line in lines), Decimal("0.00"))
    vat = sum((money(line.get("vat_amount")) for line in lines), Decimal("0.00"))
    gross = sum((money(line.get("gross_amount")) for line in lines), Decimal("0.00"))
    if gross == Decimal("0.00") and (net or vat):
        gross = net + vat
    return {"net_amount": money_str(net), "vat_amount": money_str(vat), "gross_amount": money_str(gross)}


def serialize_ap_settings(row: dict) -> dict:
    return dict(row)


def serialize_native_contact(row: dict) -> dict:
    row = dict(row)
    row["raw_json"] = parse_json_object(row.get("raw_json")) or {}
    return row


def serialize_ap_supplier(profile: dict, contact: Optional[dict] = None, balance: Decimal = Decimal("0.00")) -> dict:
    row = dict(profile)
    contact = contact or {}
    row["name"] = contact.get("name") or profile.get("trading_name") or profile.get("supplier_code") or "Supplier"
    row["email"] = contact.get("email") or ""
    row["external_id"] = contact.get("external_id") or ""
    row["account_code"] = contact.get("account_code") or ""
    row["supplier_id"] = row.get("id")
    row["supplier_name"] = row["name"]
    row["code"] = row.get("supplier_code") or row["account_code"] or ""
    row["active"] = bool(contact.get("active", True)) and str(row.get("status") or "active").lower() == "active"
    row["balance"] = money_str(balance)
    return row


def serialize_ap_invoice(row: dict, lines: Optional[list[dict]] = None, supplier: Optional[dict] = None) -> dict:
    item = dict(row)
    if str(item.get("status") or "").lower() == "draft":
        item["status"] = "awaiting_approval"
    item["extracted_json"] = parse_json_object(item.get("extracted_json")) or {}
    item["lines"] = [dict(line) for line in (lines or [])]
    item["bill_number"] = item.get("invoice_number") or ""
    item["source_submission_id"] = item.get("source_submission_id") or ""
    item["attachment_path"] = item.get("attachment_path") or ""
    item["original_filename"] = item.get("original_filename") or ""
    item["attachment_url"] = ap_invoice_attachment_url(item.get("client_id"), item)
    item["document_url"] = item["attachment_url"]
    has_source_reference = bool(item["source_submission_id"] or item["attachment_path"])
    has_source_file = bool(resolve_upload_path(item["attachment_path"]))
    item["source_document_status"] = "available" if has_source_file else ("missing" if has_source_reference else "none")
    item["source_document_missing"] = item["source_document_status"] == "missing"
    item["editable"] = item.get("status") in AP_EDITABLE_STATUSES
    item["view_only"] = not item["editable"]
    if supplier:
        item["supplier"] = supplier
        item["supplier_name"] = supplier.get("name")
        item["supplier_code"] = supplier.get("supplier_code")
    return item


def serialize_ap_credit_note(row: dict, lines: Optional[list[dict]] = None, supplier: Optional[dict] = None) -> dict:
    item = dict(row)
    if str(item.get("status") or "").lower() == "draft":
        item["status"] = "awaiting_approval"
    item["lines"] = [dict(line) for line in (lines or [])]
    if supplier:
        item["supplier_name"] = supplier.get("name")
        item["supplier_code"] = supplier.get("supplier_code")
    return item


def serialize_ap_payment(row: dict, allocations: Optional[list[dict]] = None, supplier: Optional[dict] = None) -> dict:
    item = dict(row)
    if str(item.get("status") or "").lower() == "draft":
        item["status"] = "awaiting_approval"
    item["allocations"] = [dict(allocation) for allocation in (allocations or [])]
    if supplier:
        item["supplier_name"] = supplier.get("name")
        item["supplier_code"] = supplier.get("supplier_code")
    return item


def accounting_display_status(status: str) -> str:
    value = str(status or "").strip().lower().replace(" ", "_").replace("-", "_")
    labels = {
        "awaiting_approval": "Awaiting Approval",
        "part_paid": "Part Paid",
        "over_allocated": "Over Allocated",
    }
    return labels.get(value, value.replace("_", " ").title())


def invoice_allocation_values(invoice: dict, allocated: Decimal) -> dict:
    invoice_value = money(invoice.get("gross_amount"))
    paid_allocated = money(allocated)
    balance = invoice_value - paid_allocated
    persisted_status = str(invoice.get("status") or "").strip().lower()
    is_over_allocated = paid_allocated > invoice_value
    if is_over_allocated:
        status = "over_allocated"
    elif persisted_status in {"awaiting_approval", "draft", "reversed", "cancelled", "void"} and paid_allocated == 0:
        status = "awaiting_approval" if persisted_status == "draft" else persisted_status
    elif paid_allocated == 0:
        status = "posted" if invoice.get("posted_journal_id") else (persisted_status or "posted")
    elif balance == 0:
        status = "paid"
    else:
        status = "part_paid"
    return {
        "invoice_value": money_str(invoice_value),
        "paid_allocated": money_str(paid_allocated),
        "invoice_balance": money_str(balance),
        "status": status,
        "display_status": accounting_display_status(status),
        "is_over_allocated": is_over_allocated,
    }


AP_EDITABLE_STATUSES = {"draft", "awaiting_approval"}
AR_EDITABLE_STATUSES = {"draft", "awaiting_approval"}


def require_ap_editable(row: dict, label: str) -> None:
    if row.get("status") not in AP_EDITABLE_STATUSES:
        raise HTTPException(status_code=400, detail=f"{label} cannot be edited from status {row.get('status')}.")


def require_ar_editable(row: dict, label: str) -> None:
    if row.get("status") not in AR_EDITABLE_STATUSES:
        raise HTTPException(status_code=400, detail=f"{label} cannot be edited from status {row.get('status')}.")


def ap_document_response(document_type: str, document: dict, lines: Optional[list[dict]] = None) -> dict:
    key = "credit_note" if document_type == "supplier_credit_note" else "invoice"
    document_lines = lines if lines is not None else document.get("lines", [])
    totals = {key_name: document.get(key_name) for key_name in ("net_amount", "vat_amount", "gross_amount") if key_name in document}
    source_document = document.get("source_document") or {
        "source_submission_id": document.get("source_submission_id") or "",
        "attachment_path": document.get("attachment_path") or "",
        "original_filename": document.get("original_filename") or "",
        "attachment_url": document.get("attachment_url") or "",
        "document_url": document.get("document_url") or "",
        "status": document.get("source_document_status") or ("missing" if document.get("source_document_missing") else "none"),
        "missing": bool(document.get("source_document_missing", False)),
    }
    return {
        "ok": True,
        "transaction_type": document_type,
        "document_type": document_type,
        "destination": "accounts_payable",
        key: document,
        "invoice_or_transaction": document,
        "lines": document_lines,
        "totals": totals,
        "ledger_impact": document.get("ledger_impact") or ap_ledger_effect(document_type),
        "source_document": source_document,
        "audit_trail": document.get("audit_trail", []),
        "status": document.get("status"),
    }


def ar_document_response(document_type: str, document: dict, lines: Optional[list[dict]] = None) -> dict:
    key = "receipt" if document_type == "customer_receipt" else "credit_note" if document_type == "customer_credit_note" else "invoice"
    document_lines = lines if lines is not None else document.get("lines", [])
    totals = {key_name: document.get(key_name) for key_name in ("net_amount", "vat_amount", "gross_amount", "amount") if key_name in document}
    source_document = document.get("source_document") or {
        "source_submission_id": document.get("source_submission_id") or "",
        "attachment_path": document.get("attachment_path") or "",
        "original_filename": document.get("original_filename") or "",
        "attachment_url": document.get("attachment_url") or "",
        "document_url": document.get("document_url") or "",
        "status": document.get("source_document_status") or ("missing" if document.get("source_document_missing") else "none"),
        "missing": bool(document.get("source_document_missing", False)),
    }
    return {
        "ok": True,
        "transaction_type": document_type,
        "document_type": document_type,
        "destination": "accounts_receivable",
        key: document,
        "invoice_or_transaction": document,
        "lines": document_lines,
        "totals": totals,
        "ledger_impact": document.get("ledger_impact") or ar_ledger_effect(document_type),
        "source_document": source_document,
        "audit_trail": document.get("audit_trail", []),
        "status": document.get("status"),
    }


def ap_ledger_effect(document_type: str) -> dict:
    if document_type == "supplier_credit_note":
        return {"debit": ["creditors control"], "credit": ["purchase nominal", "VAT control"]}
    if document_type == "supplier_payment":
        return {"debit": ["creditors control"], "credit": ["bank account"]}
    return {"debit": ["purchase nominal", "VAT control"], "credit": ["creditors control"]}


def ar_ledger_effect(document_type: str) -> dict:
    if document_type == "customer_credit_note":
        return {"debit": ["sales nominal", "VAT control"], "credit": ["debtors control"]}
    if document_type == "customer_receipt":
        return {"debit": ["bank account"], "credit": ["debtors control"]}
    return {"debit": ["debtors control"], "credit": ["sales nominal", "VAT control"]}


def validate_ap_document_totals(header: dict, lines: list[dict], label: str) -> dict:
    if not lines:
        raise HTTPException(status_code=400, detail=f"{label} needs at least one line item.")
    totals = ap_totals(lines)
    for key in ("net_amount", "vat_amount", "gross_amount"):
        header_value = header.get(key)
        if header_value in (None, ""):
            continue
        if money(header_value) != money(totals[key]):
            raise HTTPException(status_code=400, detail=f"{label} {key.replace('_', ' ')} does not match line totals.")
    if money(totals["gross_amount"]) <= 0:
        raise HTTPException(status_code=400, detail=f"{label} gross amount must be greater than zero.")
    return totals


def validate_ar_document_totals(header: dict, lines: list[dict], label: str) -> dict:
    return validate_ap_document_totals(header, lines, label)


async def ap_audit_events(session: AsyncSession, client_id: str, record_id: str) -> list[dict]:
    events = await many(
        session,
        select(accounting_audit_log)
        .where(accounting_audit_log.c.client_id == client_id, accounting_audit_log.c.entity_id == record_id)
        .order_by(accounting_audit_log.c.created_at.desc())
        .limit(5),
    )
    return [serialize_audit_event(event) for event in events]


def ap_invoice_needs_submission_backfill(invoice: dict, lines: list[dict]) -> bool:
    if not invoice.get("source_submission_id"):
        return False
    if not invoice.get("attachment_path") or not invoice.get("vat_code"):
        return True
    if any(not invoice.get(key) or money(invoice.get(key)) == Decimal("0.00") for key in ("net_amount", "gross_amount")):
        return True
    if not lines:
        return True
    for line in lines:
        if not line.get("nominal_account_code") or not line.get("vat_code"):
            return True
        if money(line.get("net_amount")) == Decimal("0.00") and money(line.get("gross_amount")) == Decimal("0.00"):
            return True
    return False


async def backfill_ap_invoice_from_submission(
    session: AsyncSession,
    client_id: str,
    invoice: dict,
    lines: list[dict],
    actor_id: Optional[str] = None,
) -> tuple[dict, list[dict], bool]:
    if not ap_invoice_needs_submission_backfill(invoice, lines):
        return invoice, lines, False
    submission_id = str(invoice.get("source_submission_id") or "").strip()
    submission = await one(session, select(submissions).where(submissions.c.id == submission_id, submissions.c.client_id == client_id))
    if not submission:
        return invoice, lines, False
    fields = purchase_submission_fields(submission)
    line_items = fields.get("line_items") if isinstance(fields.get("line_items"), list) else []
    default_account = first_present(fields, "nominal_account_code", "purchase_nominal_account_code", "purchase_account_code", "account_code", "category_code", "category") or "5000"
    normalized_lines = [ap_line_values(line, default_account) for line in line_items]
    if normalized_lines and lines:
        current_missing = any(
            not line.get("nominal_account_code")
            or not line.get("vat_code")
            or (money(line.get("net_amount")) == Decimal("0.00") and money(line.get("gross_amount")) == Decimal("0.00"))
            for line in lines
        )
        if not current_missing:
            normalized_lines = lines
    if not normalized_lines and not lines:
        normalized_lines = [
            ap_line_values(
                {
                    "description": fields.get("description") or submission.get("description") or invoice.get("description") or invoice.get("invoice_number"),
                    "nominal_account_code": default_account,
                    "vat_code": first_present(fields, "vat_code", "tax_code", "tax_rate_code"),
                    "net_amount": first_present(fields, "net_amount", "net"),
                    "vat_amount": first_present(fields, "vat_amount", "vat"),
                    "gross_amount": first_present(fields, "gross_amount", "gross", "total") or submission.get("amount"),
                },
                default_account,
            )
        ]
    totals_source = normalized_lines or lines
    line_totals = ap_totals(totals_source) if totals_source else {"net_amount": "0.00", "vat_amount": "0.00", "gross_amount": "0.00"}
    header_net = first_present(fields, "net_amount", "net") or invoice.get("net_amount") or line_totals["net_amount"]
    header_vat = first_present(fields, "vat_amount", "vat") or invoice.get("vat_amount") or line_totals["vat_amount"]
    header_gross = first_present(fields, "gross_amount", "gross", "total") or invoice.get("gross_amount") or submission.get("amount") or line_totals["gross_amount"]
    now = utc_now_iso()
    values = {
        "attachment_path": invoice.get("attachment_path") or submission.get("image_filename") or "",
        "original_filename": invoice.get("original_filename") or submission.get("original_filename") or submission.get("image_filename") or "",
        "vat_code": invoice.get("vat_code") or str(first_present(fields, "vat_code", "tax_code", "tax_rate_code") or "").strip(),
        "description": invoice.get("description") or str(fields.get("description") or submission.get("description") or "").strip(),
        "net_amount": money_str(money(header_net)),
        "vat_amount": money_str(money(header_vat)),
        "gross_amount": money_str(money(header_gross)),
        "outstanding_amount": invoice.get("outstanding_amount") if money(invoice.get("outstanding_amount")) else money_str(money(header_gross)),
        "updated_at": now,
    }
    changed_lines = False
    changed_invoice = any(str(invoice.get(key) or "") != str(value or "") for key, value in values.items() if key != "updated_at")
    if normalized_lines and normalized_lines != lines:
        await session.execute(delete(accounting_ap_invoice_lines).where(accounting_ap_invoice_lines.c.invoice_id == invoice["id"]))
        for index, line in enumerate(normalized_lines, start=1):
            await session.execute(insert(accounting_ap_invoice_lines).values(id=new_id(), client_id=client_id, invoice_id=invoice["id"], line_number=index, created_at=now, updated_at=now, **line))
        changed_lines = True
    if not changed_invoice and not changed_lines:
        return invoice, lines, False
    await session.execute(update(accounting_ap_invoices).where(accounting_ap_invoices.c.id == invoice["id"]).values(**values))
    await add_accounting_audit(session, client_id, actor_id, "purchase_invoice_backfilled_from_submission", "accounts_payable", invoice["id"], {"source_submission_id": submission_id, "lines_backfilled": changed_lines})
    await session.flush()
    fresh_invoice = await one(session, select(accounting_ap_invoices).where(accounting_ap_invoices.c.id == invoice["id"]))
    fresh_lines = await many(session, select(accounting_ap_invoice_lines).where(accounting_ap_invoice_lines.c.invoice_id == invoice["id"]).order_by(accounting_ap_invoice_lines.c.line_number.asc()))
    return fresh_invoice, fresh_lines, True


async def ar_audit_events(session: AsyncSession, client_id: str, record_id: str) -> list[dict]:
    return await ap_audit_events(session, client_id, record_id)


async def accounting_journal_with_lines(session: AsyncSession, client_id: str, journal_id: Optional[str]) -> dict:
    if not journal_id:
        return {}
    journal = await one(
        session,
        select(accounting_journal_entries).where(
            accounting_journal_entries.c.client_id == client_id,
            accounting_journal_entries.c.id == journal_id,
        ),
    )
    if not journal:
        return {}
    lines = await many(
        session,
        select(accounting_journal_lines)
        .where(accounting_journal_lines.c.client_id == client_id, accounting_journal_lines.c.entry_id == journal_id)
        .order_by(accounting_journal_lines.c.created_at.asc()),
    )
    return {**journal, "lines": lines}


async def accounts_payable_workspace(session: AsyncSession, client_id: str) -> dict:
    ap_settings = await ensure_ap_settings(session, client_id)
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.client_id == client_id, accounting_contacts.c.contact_type == "supplier"))
    contact_by_id = {str(contact.get("id")): contact for contact in contacts}
    profiles = await many(
        session,
        select(accounting_ap_supplier_profiles).where(accounting_ap_supplier_profiles.c.client_id == client_id).order_by(accounting_ap_supplier_profiles.c.supplier_code.asc(), accounting_ap_supplier_profiles.c.created_at.asc()),
    )
    existing_profile_contact_ids = {str(profile.get("contact_id")) for profile in profiles}
    now = utc_now_iso()
    for contact in contacts:
        if str(contact.get("id")) in existing_profile_contact_ids:
            continue
        profile = {
            "id": new_id(),
            "client_id": client_id,
            "contact_id": contact.get("id"),
            "supplier_code": contact.get("account_code") or "",
            "trading_name": contact.get("name"),
            "payment_terms_days": int(ap_settings.get("default_payment_terms_days") or 30),
            "default_currency": "GBP",
            "default_purchase_account": ap_settings.get("default_purchase_account") or "5000",
            "default_vat_code": ap_settings.get("default_vat_code") or "",
            "status": "active" if contact.get("active", True) else "inactive",
            "created_at": now,
            "updated_at": now,
        }
        await session.execute(insert(accounting_ap_supplier_profiles).values(**profile))
        profiles.append(profile)
        existing_profile_contact_ids.add(str(contact.get("id")))
    await session.flush()

    supplier_by_id: dict[str, dict] = {}
    supplier_by_contact: dict[str, dict] = {}
    for profile in profiles:
        contact = contact_by_id.get(str(profile.get("contact_id"))) or {}
        supplier = serialize_ap_supplier(profile, contact)
        supplier_by_id[str(profile["id"])] = supplier
        supplier_by_contact[str(profile.get("contact_id"))] = supplier

    invoices = await many(
        session,
        select(accounting_ap_invoices).where(accounting_ap_invoices.c.client_id == client_id).order_by(accounting_ap_invoices.c.invoice_date.desc(), accounting_ap_invoices.c.created_at.desc()),
    )
    invoice_ids = [str(row["id"]) for row in invoices]
    invoice_lines = []
    if invoice_ids:
        invoice_lines = await many(session, select(accounting_ap_invoice_lines).where(accounting_ap_invoice_lines.c.invoice_id.in_(invoice_ids)).order_by(accounting_ap_invoice_lines.c.line_number.asc()))
    invoice_lines_by_id: dict[str, list[dict]] = {}
    for line in invoice_lines:
        invoice_lines_by_id.setdefault(str(line.get("invoice_id")), []).append(line)

    credit_notes = await many(
        session,
        select(accounting_ap_credit_notes).where(accounting_ap_credit_notes.c.client_id == client_id).order_by(accounting_ap_credit_notes.c.credit_note_date.desc(), accounting_ap_credit_notes.c.created_at.desc()),
    )
    credit_ids = [str(row["id"]) for row in credit_notes]
    credit_lines = []
    if credit_ids:
        credit_lines = await many(session, select(accounting_ap_credit_note_lines).where(accounting_ap_credit_note_lines.c.credit_note_id.in_(credit_ids)).order_by(accounting_ap_credit_note_lines.c.line_number.asc()))
    credit_lines_by_id: dict[str, list[dict]] = {}
    for line in credit_lines:
        credit_lines_by_id.setdefault(str(line.get("credit_note_id")), []).append(line)

    payments = await many(
        session,
        select(accounting_ap_payments).where(accounting_ap_payments.c.client_id == client_id).order_by(accounting_ap_payments.c.payment_date.desc(), accounting_ap_payments.c.created_at.desc()),
    )
    payment_ids = [str(row["id"]) for row in payments]
    allocations = []
    if payment_ids:
        allocations = await many(session, select(accounting_ap_payment_allocations).where(accounting_ap_payment_allocations.c.payment_id.in_(payment_ids)))
    allocations_by_payment: dict[str, list[dict]] = {}
    for allocation in allocations:
        allocations_by_payment.setdefault(str(allocation.get("payment_id")), []).append(allocation)

    supplier_balances: dict[str, Decimal] = {}
    for invoice in invoices:
        supplier_balances[str(invoice.get("supplier_id"))] = supplier_balances.get(str(invoice.get("supplier_id")), Decimal("0.00")) + money(invoice.get("outstanding_amount"))
    for credit in credit_notes:
        supplier_balances[str(credit.get("supplier_id"))] = supplier_balances.get(str(credit.get("supplier_id")), Decimal("0.00")) - money(credit.get("unallocated_amount"))

    serialized_suppliers = []
    for profile in profiles:
        contact = contact_by_id.get(str(profile.get("contact_id"))) or {}
        serialized_suppliers.append(serialize_ap_supplier(profile, contact, supplier_balances.get(str(profile.get("id")), Decimal("0.00"))))

    today = datetime.now(timezone.utc).date()
    aged: dict[str, dict] = {}
    for invoice in invoices:
        outstanding = money(invoice.get("outstanding_amount"))
        if outstanding <= 0 or invoice.get("status") in {"void", "draft"}:
            continue
        supplier = supplier_by_id.get(str(invoice.get("supplier_id"))) or {}
        due_raw = str(invoice.get("due_date") or invoice.get("invoice_date") or "")[:10]
        try:
            due_date = datetime.fromisoformat(due_raw).date()
            age_days = max(0, (today - due_date).days)
        except Exception:
            age_days = 0
        bucket = "current" if age_days <= 0 else "days_1_30" if age_days <= 30 else "days_31_60" if age_days <= 60 else "days_61_90" if age_days <= 90 else "days_90_plus"
        row = aged.setdefault(str(invoice.get("supplier_id")), {
            "supplier_id": invoice.get("supplier_id"),
            "supplier_name": supplier.get("name") or "Supplier",
            "current": Decimal("0.00"),
            "days_1_30": Decimal("0.00"),
            "days_31_60": Decimal("0.00"),
            "days_61_90": Decimal("0.00"),
            "days_90_plus": Decimal("0.00"),
            "total": Decimal("0.00"),
        })
        row[bucket] += outstanding
        row["total"] += outstanding

    dashboard = {
        "supplier_count": len(serialized_suppliers),
        "draft_invoices": len([i for i in invoices if i.get("status") == "draft"]),
        "awaiting_approval": len([i for i in invoices if i.get("status") == "awaiting_approval"]),
        "posted_invoices": len([i for i in invoices if i.get("status") in {"posted", "part_paid", "paid"}]),
        "overdue_invoices": len([i for i in invoices if money(i.get("outstanding_amount")) > 0 and str(i.get("due_date") or "9999-99-99") < today.isoformat()]),
        "outstanding_total": money_str(sum((money(i.get("outstanding_amount")) for i in invoices), Decimal("0.00"))),
        "unallocated_credits": money_str(sum((money(c.get("unallocated_amount")) for c in credit_notes), Decimal("0.00"))),
        "payments_total": money_str(sum((money(p.get("amount")) for p in payments), Decimal("0.00"))),
    }

    return {
        "settings": serialize_ap_settings(ap_settings),
        "dashboard": dashboard,
        "suppliers": serialized_suppliers,
        "invoices": [serialize_ap_invoice(row, invoice_lines_by_id.get(str(row["id"]), []), supplier_by_id.get(str(row.get("supplier_id")))) for row in invoices],
        "credit_notes": [serialize_ap_credit_note(row, credit_lines_by_id.get(str(row["id"]), []), supplier_by_id.get(str(row.get("supplier_id")))) for row in credit_notes],
        "payments": [serialize_ap_payment(row, allocations_by_payment.get(str(row["id"]), []), supplier_by_id.get(str(row.get("supplier_id")))) for row in payments],
        "aged_creditors": [
            {**item, **{key: money_str(value) for key, value in item.items() if isinstance(value, Decimal)}}
            for item in sorted(aged.values(), key=lambda x: str(x.get("supplier_name") or ""))
        ],
    }


def default_ar_settings(client_id: str, accounting_defaults: Optional[dict] = None, now: Optional[str] = None) -> dict:
    defaults = accounting_defaults or {}
    timestamp = now or utc_now_iso()
    return {
        "id": new_id(),
        "client_id": client_id,
        "approval_required": True,
        "default_payment_terms_days": 30,
        "default_sales_account": defaults.get("default_sales_account") or "4000",
        "default_vat_code": "",
        "invoice_number_prefix": "SINV",
        "next_invoice_number": 1,
        "duplicate_invoice_warning": True,
        "credit_limit_warnings": True,
        "automatic_customer_numbering": True,
        "customer_numbering": "Automatic",
        "receipt_on_account_behaviour": "Keep unallocated until matched",
        "sales_behaviour": "Post sales invoices to selected nominal",
        "credit_control_behaviour": "Use customer credit control settings",
        "created_at": timestamp,
        "updated_at": timestamp,
    }


async def ensure_ar_settings(session: AsyncSession, client_id: str) -> dict:
    existing = await one(session, select(accounting_ar_settings).where(accounting_ar_settings.c.client_id == client_id))
    if existing:
        return existing
    accounting_defaults = await ensure_accounting_settings(session, client_id)
    row = default_ar_settings(client_id, accounting_defaults)
    await session.execute(insert(accounting_ar_settings).values(**row))
    await session.flush()
    return row


def ar_line_values(raw_line: dict, default_account: str = "4000") -> dict:
    return ap_line_values(raw_line, default_account or "4000")


def ar_totals(lines: list[dict]) -> dict:
    return ap_totals(lines)


def serialize_ar_settings(row: dict) -> dict:
    item = dict(row)
    item["customer_numbering"] = item.get("customer_numbering") or ("Automatic" if item.get("automatic_customer_numbering", True) else "Manual")
    item["receipt_on_account_behaviour"] = item.get("receipt_on_account_behaviour") or "Keep unallocated until matched"
    item["sales_behaviour"] = item.get("sales_behaviour") or "Post sales invoices to selected nominal"
    item["credit_control_behaviour"] = item.get("credit_control_behaviour") or "Use customer credit control settings"
    return item


def serialize_ar_customer(
    profile: dict,
    contact: Optional[dict] = None,
    balance: Decimal = Decimal("0.00"),
    invoices: Optional[list[dict]] = None,
    receipts: Optional[list[dict]] = None,
    on_account_credit: Decimal = Decimal("0.00"),
) -> dict:
    row = dict(profile)
    contact = contact or {}
    invoices = invoices or []
    receipts = receipts or []
    row["name"] = contact.get("name") or profile.get("trading_name") or profile.get("customer_code") or "Customer"
    row["email"] = contact.get("email") or ""
    row["external_id"] = contact.get("external_id") or ""
    row["account_code"] = contact.get("account_code") or ""
    row["customer_id"] = row.get("id")
    row["customer_name"] = row["name"]
    row["code"] = row.get("customer_code") or row["account_code"] or ""
    row["active"] = bool(contact.get("active", True)) and str(row.get("status") or "active").lower() == "active"
    row["outstanding_balance"] = money_str(balance)
    row["on_account_credit"] = money_str(on_account_credit)
    row["net_balance"] = money_str(balance - on_account_credit)
    row["current_balance"] = money_str(balance)
    row["last_invoice"] = max([str(invoice.get("invoice_date") or "") for invoice in invoices] or [""])
    row["last_receipt"] = max([str(receipt.get("receipt_date") or "") for receipt in receipts] or [""])
    return row


def serialize_ar_invoice(row: dict, lines: Optional[list[dict]] = None, customer: Optional[dict] = None) -> dict:
    item = dict(row)
    if str(item.get("status") or "").lower() == "draft":
        item["status"] = "awaiting_approval"
    item["extracted_json"] = parse_json_object(item.get("extracted_json")) or {}
    item["lines"] = [dict(line) for line in (lines or [])]
    item["source_submission_id"] = item.get("source_submission_id") or ""
    item["attachment_path"] = item.get("attachment_path") or ""
    item["original_filename"] = item.get("original_filename") or ""
    item["attachment_url"] = ar_invoice_attachment_url(item.get("client_id"), item)
    item["document_url"] = item["attachment_url"]
    has_source_reference = bool(item["source_submission_id"] or item["attachment_path"])
    has_source_file = bool(resolve_upload_path(item["attachment_path"]))
    item["source_document_status"] = "available" if has_source_file else ("missing" if has_source_reference else "none")
    item["source_document_missing"] = item["source_document_status"] == "missing"
    item["editable"] = item.get("status") in AR_EDITABLE_STATUSES
    item["view_only"] = not item["editable"]
    if customer:
        item["customer"] = dict(customer)
        item["customer_name"] = customer.get("name")
        item["customer_code"] = customer.get("customer_code")
    return item


def serialize_ar_credit_note(row: dict, lines: Optional[list[dict]] = None, customer: Optional[dict] = None) -> dict:
    item = dict(row)
    if str(item.get("status") or "").lower() == "draft":
        item["status"] = "awaiting_approval"
    item["lines"] = [dict(line) for line in (lines or [])]
    if customer:
        item["customer_name"] = customer.get("name")
        item["customer_code"] = customer.get("customer_code")
    return item


def serialize_ar_receipt(row: dict, allocations: Optional[list[dict]] = None, customer: Optional[dict] = None) -> dict:
    item = dict(row)
    if str(item.get("status") or "").lower() == "draft":
        item["status"] = "awaiting_approval"
    item["allocations"] = [dict(allocation) for allocation in (allocations or [])]
    if customer:
        item["customer_name"] = customer.get("name")
        item["customer_code"] = customer.get("customer_code")
    return item


def ar_sales_summary(invoices: list[dict]) -> dict:
    today = datetime.now(timezone.utc).date()
    week_start = today - timedelta(days=today.weekday())
    month_start = today.replace(day=1)
    year_start = today.replace(month=1, day=1)

    def total_since(start: date) -> str:
        total = Decimal("0.00")
        for invoice in invoices:
            try:
                invoice_date = datetime.fromisoformat(str(invoice.get("invoice_date") or "")[:10]).date()
            except Exception:
                continue
            if invoice_date >= start and invoice.get("status") not in {"void", "draft"}:
                total += money(invoice.get("gross_amount"))
        return money_str(total)

    return {
        "today": total_since(today),
        "this_week": total_since(week_start),
        "this_month": total_since(month_start),
        "financial_year": total_since(year_start),
    }


async def accounts_receivable_workspace(session: AsyncSession, client_id: str) -> dict:
    ar_settings = await ensure_ar_settings(session, client_id)
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.client_id == client_id, accounting_contacts.c.contact_type == "customer"))
    contact_by_id = {str(contact.get("id")): contact for contact in contacts}
    profiles = await many(
        session,
        select(accounting_ar_customer_profiles).where(accounting_ar_customer_profiles.c.client_id == client_id).order_by(accounting_ar_customer_profiles.c.customer_code.asc(), accounting_ar_customer_profiles.c.created_at.asc()),
    )
    existing_profile_contact_ids = {str(profile.get("contact_id")) for profile in profiles}
    now = utc_now_iso()
    for contact in contacts:
        if str(contact.get("id")) in existing_profile_contact_ids:
            continue
        profile = {
            "id": new_id(),
            "client_id": client_id,
            "contact_id": contact.get("id"),
            "customer_code": contact.get("account_code") or "",
            "trading_name": contact.get("name"),
            "payment_terms_days": int(ar_settings.get("default_payment_terms_days") or 30),
            "default_currency": "GBP",
            "default_sales_account": ar_settings.get("default_sales_account") or "4000",
            "default_vat_code": ar_settings.get("default_vat_code") or "",
            "credit_limit": "0.00",
            "status": "active" if contact.get("active", True) else "inactive",
            "created_at": now,
            "updated_at": now,
        }
        await session.execute(insert(accounting_ar_customer_profiles).values(**profile))
        profiles.append(profile)
        existing_profile_contact_ids.add(str(contact.get("id")))
    await session.flush()

    customer_by_id: dict[str, dict] = {}
    for profile in profiles:
        customer_by_id[str(profile["id"])] = serialize_ar_customer(profile, contact_by_id.get(str(profile.get("contact_id"))) or {})

    invoices = await many(
        session,
        select(accounting_ar_invoices).where(accounting_ar_invoices.c.client_id == client_id).order_by(accounting_ar_invoices.c.invoice_date.desc(), accounting_ar_invoices.c.created_at.desc()),
    )
    invoice_ids = [str(row["id"]) for row in invoices]
    invoice_lines = []
    if invoice_ids:
        invoice_lines = await many(session, select(accounting_ar_invoice_lines).where(accounting_ar_invoice_lines.c.invoice_id.in_(invoice_ids)).order_by(accounting_ar_invoice_lines.c.line_number.asc()))
    invoice_lines_by_id: dict[str, list[dict]] = {}
    for line in invoice_lines:
        invoice_lines_by_id.setdefault(str(line.get("invoice_id")), []).append(line)

    credit_notes = await many(
        session,
        select(accounting_ar_credit_notes).where(accounting_ar_credit_notes.c.client_id == client_id).order_by(accounting_ar_credit_notes.c.credit_note_date.desc(), accounting_ar_credit_notes.c.created_at.desc()),
    )
    credit_ids = [str(row["id"]) for row in credit_notes]
    credit_lines = []
    if credit_ids:
        credit_lines = await many(session, select(accounting_ar_credit_note_lines).where(accounting_ar_credit_note_lines.c.credit_note_id.in_(credit_ids)).order_by(accounting_ar_credit_note_lines.c.line_number.asc()))
    credit_lines_by_id: dict[str, list[dict]] = {}
    for line in credit_lines:
        credit_lines_by_id.setdefault(str(line.get("credit_note_id")), []).append(line)

    receipts = await many(
        session,
        select(accounting_ar_receipts).where(accounting_ar_receipts.c.client_id == client_id).order_by(accounting_ar_receipts.c.receipt_date.desc(), accounting_ar_receipts.c.created_at.desc()),
    )
    receipt_ids = [str(row["id"]) for row in receipts]
    allocations = []
    if receipt_ids:
        allocations = await many(session, select(accounting_ar_receipt_allocations).where(accounting_ar_receipt_allocations.c.receipt_id.in_(receipt_ids)))
    allocations_by_receipt: dict[str, list[dict]] = {}
    for allocation in allocations:
        allocations_by_receipt.setdefault(str(allocation.get("receipt_id")), []).append(allocation)
    allocated_by_receipt: dict[str, Decimal] = {}
    for allocation in allocations:
        receipt_id = str(allocation.get("receipt_id") or "")
        allocated_by_receipt[receipt_id] = allocated_by_receipt.get(receipt_id, Decimal("0.00")) + money(allocation.get("amount"))

    invoices_by_customer: dict[str, list[dict]] = {}
    receipts_by_customer: dict[str, list[dict]] = {}
    balances_by_customer: dict[str, Decimal] = {}
    on_account_by_customer: dict[str, Decimal] = {}
    for invoice in invoices:
        customer_id = str(invoice.get("customer_id"))
        invoices_by_customer.setdefault(customer_id, []).append(invoice)
        balances_by_customer[customer_id] = balances_by_customer.get(customer_id, Decimal("0.00")) + money(invoice.get("outstanding_amount"))
    for credit in credit_notes:
        customer_id = str(credit.get("customer_id"))
        balances_by_customer[customer_id] = balances_by_customer.get(customer_id, Decimal("0.00")) - money(credit.get("unallocated_amount"))
    for receipt in receipts:
        customer_id = str(receipt.get("customer_id"))
        receipts_by_customer.setdefault(customer_id, []).append(receipt)
        unallocated = money(receipt.get("amount")) - allocated_by_receipt.get(str(receipt.get("id")), Decimal("0.00"))
        if unallocated > 0:
            on_account_by_customer[customer_id] = on_account_by_customer.get(customer_id, Decimal("0.00")) + unallocated

    serialized_customers = []
    for profile in profiles:
        customer_id = str(profile.get("id"))
        serialized_customers.append(
            serialize_ar_customer(
                profile,
                contact_by_id.get(str(profile.get("contact_id"))) or {},
                balances_by_customer.get(customer_id, Decimal("0.00")),
                invoices_by_customer.get(customer_id, []),
                receipts_by_customer.get(customer_id, []),
                on_account_by_customer.get(customer_id, Decimal("0.00")),
            )
        )

    today = datetime.now(timezone.utc).date()
    aged: dict[str, dict] = {}
    overdue_invoices = []
    collection_days = []
    for invoice in invoices:
        outstanding = money(invoice.get("outstanding_amount"))
        if outstanding <= 0 or invoice.get("status") in {"void", "draft", "archived"}:
            continue
        customer = customer_by_id.get(str(invoice.get("customer_id"))) or {}
        due_raw = str(invoice.get("due_date") or invoice.get("invoice_date") or "")[:10]
        try:
            due_date = datetime.fromisoformat(due_raw).date()
            age_days = max(0, (today - due_date).days)
        except Exception:
            due_date = today
            age_days = 0
        bucket = "current" if age_days <= 0 else "days_1_30" if age_days <= 30 else "days_31_60" if age_days <= 60 else "days_61_90" if age_days <= 90 else "days_90_plus"
        row = aged.setdefault(str(invoice.get("customer_id")), {
            "customer_id": invoice.get("customer_id"),
            "customer_name": customer.get("name") or "Customer",
            "current": Decimal("0.00"),
            "days_1_30": Decimal("0.00"),
            "days_31_60": Decimal("0.00"),
            "days_61_90": Decimal("0.00"),
            "days_90_plus": Decimal("0.00"),
            "total": Decimal("0.00"),
        })
        row[bucket] += outstanding
        row["total"] += outstanding
        if due_date < today:
            overdue_invoices.append({**serialize_ar_invoice(invoice, invoice_lines_by_id.get(str(invoice["id"]), []), customer), "days_overdue": age_days})
    for invoice in invoices:
        if invoice.get("status") == "paid":
            try:
                collection_days.append(max(0, (datetime.fromisoformat(str(invoice.get("updated_at") or "")[:10]).date() - datetime.fromisoformat(str(invoice.get("invoice_date") or "")[:10]).date()).days))
            except Exception:
                pass

    customer_attention = []
    for customer in serialized_customers:
        balance = money(customer.get("outstanding_balance"))
        credit_limit = money(customer.get("credit_limit"))
        old_total = money((aged.get(str(customer.get("id"))) or {}).get("days_90_plus"))
        reasons = []
        if balance > 0:
            reasons.append("High balance")
        if old_total > 0:
            reasons.append("Long outstanding")
        if credit_limit > 0 and balance > credit_limit:
            reasons.append("Credit limit exceeded")
        if reasons:
            customer_attention.append({"customer_id": customer.get("id"), "customer_name": customer.get("name"), "balance": money_str(balance), "reasons": reasons})

    current_month = datetime.now(timezone.utc).date().strftime("%Y-%m")
    dashboard = {
        "customer_count": len(serialized_customers),
        "outstanding_invoices": len([i for i in invoices if money(i.get("outstanding_amount")) > 0 and i.get("status") not in {"void", "draft"}]),
        "overdue_invoices": len(overdue_invoices),
        "customers_with_balances": len([c for c in serialized_customers if money(c.get("outstanding_balance")) > 0]),
        "receipts_this_month": money_str(sum((money(r.get("amount")) for r in receipts if str(r.get("receipt_date") or "").startswith(current_month)), Decimal("0.00"))),
        "average_collection_days": int(sum(collection_days) / len(collection_days)) if collection_days else 0,
        "sales_this_month": ar_sales_summary(invoices)["this_month"],
        "outstanding_total": money_str(sum((money(i.get("outstanding_amount")) for i in invoices), Decimal("0.00"))),
        "unallocated_credits": money_str(sum((money(c.get("unallocated_amount")) for c in credit_notes), Decimal("0.00"))),
        "on_account_receipts": money_str(sum(on_account_by_customer.values(), Decimal("0.00"))),
    }
    recent_activity = []
    for customer in serialized_customers:
        recent_activity.append({"date": customer.get("created_at"), "type": "Customer Created", "description": customer.get("name")})
    for invoice in invoices:
        recent_activity.append({"date": invoice.get("created_at"), "type": "Invoice Raised", "description": invoice.get("invoice_number"), "amount": invoice.get("gross_amount")})
        if invoice.get("posted_at"):
            recent_activity.append({"date": invoice.get("posted_at"), "type": "Invoice Posted", "description": invoice.get("invoice_number"), "amount": invoice.get("gross_amount")})
    for receipt in receipts:
        recent_activity.append({"date": receipt.get("created_at"), "type": "Receipt Allocated", "description": receipt.get("reference"), "amount": receipt.get("amount")})
    for credit in credit_notes:
        recent_activity.append({"date": credit.get("created_at"), "type": "Credit Note Issued", "description": credit.get("credit_note_number"), "amount": credit.get("gross_amount")})
    recent_activity = sorted([item for item in recent_activity if item.get("date")], key=lambda item: str(item.get("date")), reverse=True)[:12]

    serialized_invoices = [serialize_ar_invoice(row, invoice_lines_by_id.get(str(row["id"]), []), customer_by_id.get(str(row.get("customer_id")))) for row in invoices]
    serialized_receipts = [serialize_ar_receipt(row, allocations_by_receipt.get(str(row["id"]), []), customer_by_id.get(str(row.get("customer_id")))) for row in receipts]
    return {
        "settings": serialize_ar_settings(ar_settings),
        "dashboard": dashboard,
        "customers": serialized_customers,
        "invoices": serialized_invoices,
        "credit_notes": [serialize_ar_credit_note(row, credit_lines_by_id.get(str(row["id"]), []), customer_by_id.get(str(row.get("customer_id")))) for row in credit_notes],
        "receipts": serialized_receipts,
        "aged_debtors": [
            {**item, **{key: money_str(value) for key, value in item.items() if isinstance(value, Decimal)}}
            for item in sorted(aged.values(), key=lambda x: str(x.get("customer_name") or ""))
        ],
        "recent_activity": recent_activity,
        "overdue_invoices": sorted(overdue_invoices, key=lambda item: int(item.get("days_overdue") or 0), reverse=True),
        "customers_requiring_attention": customer_attention,
        "sales_summary": ar_sales_summary(invoices),
        "reports": {
            "sales_day_book": serialized_invoices,
            "outstanding_invoices": [invoice for invoice in serialized_invoices if money(invoice.get("outstanding_amount")) > 0],
            "receipts_analysis": serialized_receipts,
            "sales_analysis": ar_sales_summary(invoices),
        },
    }


async def native_accounting_summary(session: AsyncSession, client_id: str) -> dict:
    async def count_rows(table, *conditions) -> int:
        row = await one(session, select(func.count().label("count")).select_from(table).where(*conditions))
        return int((row or {}).get("count") or 0)

    journals_count = await count_rows(accounting_journal_entries, accounting_journal_entries.c.client_id == client_id)
    bank_transactions_count = await count_rows(accounting_bank_transactions, accounting_bank_transactions.c.client_id == client_id)
    unreconciled_bank_count = await count_rows(
        accounting_bank_transactions,
        accounting_bank_transactions.c.client_id == client_id,
        or_(accounting_bank_transactions.c.status != "reconciled", accounting_bank_transactions.c.status.is_(None)),
    )
    vat_returns_count = await count_rows(accounting_vat_returns, accounting_vat_returns.c.client_id == client_id)
    draft_vat_returns_count = await count_rows(
        accounting_vat_returns,
        accounting_vat_returns.c.client_id == client_id,
        accounting_vat_returns.c.status == "draft",
    )
    ap_invoice_totals = await one(
        session,
        select(
            func.count().label("count"),
            func.sum(accounting_ap_invoices.c.outstanding_amount).label("outstanding"),
        ).where(
            accounting_ap_invoices.c.client_id == client_id,
            accounting_ap_invoices.c.outstanding_amount > "0",
        ),
    ) or {}
    ar_invoice_totals = await one(
        session,
        select(
            func.count().label("count"),
            func.sum(accounting_ar_invoices.c.outstanding_amount).label("outstanding"),
        ).where(
            accounting_ar_invoices.c.client_id == client_id,
            accounting_ar_invoices.c.outstanding_amount > "0",
        ),
    ) or {}
    line_totals = await many(
        session,
        select(
            accounting_journal_lines.c.account_code,
            func.sum(accounting_journal_lines.c.debit).label("debit"),
            func.sum(accounting_journal_lines.c.credit).label("credit"),
        )
        .where(
            accounting_journal_lines.c.client_id == client_id,
            accounting_journal_lines.c.account_code.in_(["2000", "1100", "2200", "1200"]),
        )
        .group_by(accounting_journal_lines.c.account_code)
    )
    payables = Decimal("0.00")
    receivables = Decimal("0.00")
    vat = Decimal("0.00")
    bank = Decimal("0.00")
    for line in line_totals:
        code = str(line.get("account_code") or "")
        movement = money(line.get("debit")) - money(line.get("credit"))
        if code == "2000":
            payables += -movement
        elif code == "1100":
            receivables += movement
        elif code == "2200":
            vat += -movement
        elif code == "1200":
            bank += movement
    return {
        "journals": journals_count,
        "payables": money_str(payables),
        "receivables": money_str(receivables),
        "vat": money_str(vat),
        "vat_balance": money_str(vat),
        "bank": money_str(bank),
        "bank_balance": money_str(bank),
        "bank_transactions": bank_transactions_count,
        "unreconciled_bank_transactions": unreconciled_bank_count,
        "vat_returns": vat_returns_count,
        "draft_vat_returns": draft_vat_returns_count,
        "ap_open_invoices": int(ap_invoice_totals.get("count") or 0),
        "ap_outstanding": money_str(money(ap_invoice_totals.get("outstanding"))),
        "ar_open_invoices": int(ar_invoice_totals.get("count") or 0),
        "ar_outstanding": money_str(money(ar_invoice_totals.get("outstanding"))),
    }


async def add_accounting_audit(
    session: AsyncSession,
    client_id: str,
    actor_id: Optional[str],
    action: str,
    entity_type: str,
    entity_id: str,
    details: Optional[dict] = None,
):
    summary = f"{action.replace('_', ' ').title()} in {entity_type.replace('_', ' ')}"
    await session.execute(
        insert(accounting_audit_log).values(
            id=new_id(),
            client_id=client_id,
            actor_id=actor_id,
            module=entity_type,
            record_type=entity_type,
            record_id=entity_id,
            action=action,
            entity_type=entity_type,
            entity_id=entity_id,
            previous_value=None,
            new_value=json.dumps(details or {}),
            ip_address=None,
            details_json=json.dumps(details or {}),
            created_at=utc_now_iso(),
        )
    )
    await session.execute(
        insert(platform_activity_feed).values(
            id=new_id(),
            client_id=client_id,
            actor_id=actor_id,
            module=entity_type,
            record_type=entity_type,
            record_id=entity_id,
            action=action,
            summary=summary,
            details_json=json.dumps(details or {}),
            correlation_id=None,
            created_at=utc_now_iso(),
        )
    )


