def serialize_vat_code(row: dict) -> dict:
    row = dict(row)
    code = str(row.get("code") or "").strip()
    description = str(row.get("description") or "").strip()
    percentage = money_str(money(row.get("percentage")))
    net_box = str(row.get("box_purchase_net") or row.get("box_sales_net") or "").strip()
    vat_box = str(row.get("box_purchase_vat") or row.get("box_sales_vat") or "").strip()
    row["code"] = code
    row["description"] = description
    row["percentage"] = percentage
    row["rate"] = percentage
    row["purchase_behaviour"] = row.get("purchase_behavior") or ""
    row["sales_behaviour"] = row.get("sales_behavior") or ""
    row["net_box"] = net_box
    row["vat_box"] = vat_box
    row["display_label"] = coding_option_label(code, description)
    row["active"] = bool(row.get("active", True))
    row["system_code"] = bool(row.get("system_code", False))
    return row


def serialize_vat_period(row: dict) -> dict:
    row = dict(row)
    for key in ("output_vat", "input_vat", "net_vat"):
        row[key] = money_str(money(row.get(key)))
    return row


def serialize_vat_adjustment(row: dict) -> dict:
    row = dict(row)
    for key in ("net_amount", "vat_amount", "gross_amount"):
        row[key] = money_str(money(row.get(key)))
    return row


async def ensure_vat_settings(session: AsyncSession, client_id: str) -> dict:
    row = await one(session, select(accounting_vat_settings).where(accounting_vat_settings.c.client_id == client_id))
    if row:
        return row
    today = datetime.now(timezone.utc).date()
    quarter_start_month = (((today.month - 1) // 3) * 3) + 1
    now = utc_now_iso()
    row = {
        "id": new_id(),
        "client_id": client_id,
        "vat_registration_number": "",
        "vat_scheme": "standard",
        "vat_frequency": "quarterly",
        "vat_start_date": date(today.year, quarter_start_month, 1).isoformat(),
        "default_purchase_vat_code": "20% S",
        "default_sales_vat_code": "20% S",
        "default_bank_vat_code": "NO VAT",
        "flat_rate_percentage": "0.00",
        "cash_accounting": False,
        "accrual_accounting": True,
        "mtd_enabled": False,
        "hmrc_connection_status": "not_connected",
        "created_at": now,
        "updated_at": now,
    }
    await session.execute(insert(accounting_vat_settings).values(**row))
    return row


async def ensure_vat_codes(session: AsyncSession, client_id: str) -> list[dict]:
    existing = await many(session, select(accounting_vat_codes).where(accounting_vat_codes.c.client_id == client_id).order_by(accounting_vat_codes.c.code.asc()))
    if existing:
        deduped: dict[str, dict] = {}
        for row in existing:
            code_key = str(row.get("code") or "").strip().lower()
            if code_key and code_key not in deduped:
                deduped[code_key] = row
        return list(deduped.values())
    now = utc_now_iso()
    rows = []
    for item in DEFAULT_NATIVE_VAT_CODES:
        row = {"id": new_id(), "client_id": client_id, "active": True, "system_code": True, "created_at": now, "updated_at": now, **item}
        rows.append(row)
    await session.execute(insert(accounting_vat_codes), rows)
    return rows


def vat_period_months(frequency: str) -> int:
    value = str(frequency or "quarterly").lower()
    if value == "monthly":
        return 1
    if value == "annual":
        return 12
    return 3


def vat_period_due_date(period_end: date) -> date:
    return add_months_to_date(period_end, 1) + timedelta(days=7)


def find_vat_period_for_date(periods: list[dict], value: str) -> Optional[dict]:
    iso = str(value or "")[:10]
    for period in periods:
        if str(period.get("period_start") or "") <= iso <= str(period.get("period_end") or ""):
            return period
    return None


async def ensure_vat_periods(session: AsyncSession, client_id: str, settings_row: Optional[dict] = None) -> list[dict]:
    settings_row = settings_row or await ensure_vat_settings(session, client_id)
    periods = await many(session, select(accounting_vat_periods).where(accounting_vat_periods.c.client_id == client_id).order_by(accounting_vat_periods.c.period_start.asc()))
    today = datetime.now(timezone.utc).date()
    if periods:
        return periods
    start = parse_date_or_today(settings_row.get("vat_start_date") or today.isoformat())
    months = vat_period_months(settings_row.get("vat_frequency"))
    rows = []
    now = utc_now_iso()
    cursor = start
    while cursor <= add_months_to_date(today, 18):
        period_end = add_months_to_date(cursor, months) - timedelta(days=1)
        rows.append({
            "id": new_id(),
            "client_id": client_id,
            "period_start": cursor.isoformat(),
            "period_end": period_end.isoformat(),
            "due_date": vat_period_due_date(period_end).isoformat(),
            "status": "open",
            "created_at": now,
            "updated_at": now,
        })
        cursor = period_end + timedelta(days=1)
    await session.execute(insert(accounting_vat_periods), rows)
    return rows


def vat_source_module(source_type: str) -> str:
    if source_type.startswith("ap_"):
        return "Accounts Payable"
    if source_type.startswith("ar_"):
        return "Accounts Receivable"
    if source_type.startswith("bank_"):
        return "Banking"
    return "General Ledger"


def vat_document_type(source_type: str) -> str:
    labels = {
        "ap_invoice": "Purchase Invoice",
        "ap_credit_note": "Purchase Credit Note",
        "ar_invoice": "Sales Invoice",
        "ar_credit_note": "Sales Credit Note",
        "vat_adjustment": "VAT Adjustment",
    }
    return labels.get(source_type, source_type.replace("_", " ").title())


def apply_vat_box(boxes: dict[str, Decimal], box: str, amount: Decimal) -> None:
    if not box:
        return
    key = f"box{box}"
    if key in boxes:
        boxes[key] += amount


async def vat_transactions_for_client(session: AsyncSession, client_id: str) -> list[dict]:
    codes = {str(c.get("code") or "").lower(): c for c in await ensure_vat_codes(session, client_id)}
    periods = await ensure_vat_periods(session, client_id)
    transactions: list[dict] = []

    def add_transaction(row: dict, line: dict, date_key: str, number_key: str, source_type: str, direction: str, sign: Decimal = Decimal("1")):
        net = money(line.get("net_amount")) * sign
        vat = money(line.get("vat_amount")) * sign
        gross = money(line.get("gross_amount")) * sign
        code = str(line.get("vat_code") or "").strip()
        if not code and vat == 0 and net == 0:
            return
        code_row = codes.get(code.lower(), {})
        period = find_vat_period_for_date(periods, str(row.get(date_key) or ""))
        transactions.append({
            "id": str(line.get("id") or new_id()),
            "date": str(row.get(date_key) or ""),
            "source_module": vat_source_module(source_type),
            "source_type": source_type,
            "document_type": vat_document_type(source_type),
            "document_number": str(row.get(number_key) or row.get("reference") or row.get("id") or ""),
            "source_id": str(row.get("id") or ""),
            "account": str(line.get("nominal_account_code") or ""),
            "vat_code": code,
            "vat_code_description": str(code_row.get("description") or ""),
            "net": money_str(net),
            "vat": money_str(vat),
            "gross": money_str(gross),
            "direction": direction,
            "vat_period_id": period.get("id") if period else None,
            "vat_period": f"{period.get('period_start')} to {period.get('period_end')}" if period else "Unassigned",
            "status": period.get("status") if period else "unassigned",
            "box_sales_vat": code_row.get("box_sales_vat") or "",
            "box_purchase_vat": code_row.get("box_purchase_vat") or "",
            "box_sales_net": code_row.get("box_sales_net") or "",
            "box_purchase_net": code_row.get("box_purchase_net") or "",
        })

    ap_invoices = await many(session, select(accounting_ap_invoices).where(accounting_ap_invoices.c.client_id == client_id, accounting_ap_invoices.c.posted_journal_id.isnot(None)))
    if ap_invoices:
        rows = await many(session, select(accounting_ap_invoice_lines).where(accounting_ap_invoice_lines.c.invoice_id.in_([r["id"] for r in ap_invoices])))
        by_id = {str(r["id"]): r for r in ap_invoices}
        for line in rows:
            add_transaction(by_id.get(str(line.get("invoice_id")), {}), line, "invoice_date", "invoice_number", "ap_invoice", "purchase")

    ap_credits = await many(session, select(accounting_ap_credit_notes).where(accounting_ap_credit_notes.c.client_id == client_id, accounting_ap_credit_notes.c.posted_journal_id.isnot(None)))
    if ap_credits:
        rows = await many(session, select(accounting_ap_credit_note_lines).where(accounting_ap_credit_note_lines.c.credit_note_id.in_([r["id"] for r in ap_credits])))
        by_id = {str(r["id"]): r for r in ap_credits}
        for line in rows:
            add_transaction(by_id.get(str(line.get("credit_note_id")), {}), line, "credit_note_date", "credit_note_number", "ap_credit_note", "purchase", Decimal("-1"))

    ar_invoices = await many(session, select(accounting_ar_invoices).where(accounting_ar_invoices.c.client_id == client_id, accounting_ar_invoices.c.posted_journal_id.isnot(None)))
    if ar_invoices:
        rows = await many(session, select(accounting_ar_invoice_lines).where(accounting_ar_invoice_lines.c.invoice_id.in_([r["id"] for r in ar_invoices])))
        by_id = {str(r["id"]): r for r in ar_invoices}
        for line in rows:
            add_transaction(by_id.get(str(line.get("invoice_id")), {}), line, "invoice_date", "invoice_number", "ar_invoice", "sales")

    ar_credits = await many(session, select(accounting_ar_credit_notes).where(accounting_ar_credit_notes.c.client_id == client_id, accounting_ar_credit_notes.c.posted_journal_id.isnot(None)))
    if ar_credits:
        rows = await many(session, select(accounting_ar_credit_note_lines).where(accounting_ar_credit_note_lines.c.credit_note_id.in_([r["id"] for r in ar_credits])))
        by_id = {str(r["id"]): r for r in ar_credits}
        for line in rows:
            add_transaction(by_id.get(str(line.get("credit_note_id")), {}), line, "credit_note_date", "credit_note_number", "ar_credit_note", "sales", Decimal("-1"))

    adjustments = await many(session, select(accounting_vat_adjustments).where(accounting_vat_adjustments.c.client_id == client_id).order_by(accounting_vat_adjustments.c.adjustment_date.desc()))
    for adjustment in adjustments:
        period = find_vat_period_for_date(periods, str(adjustment.get("adjustment_date") or ""))
        code = str(adjustment.get("vat_code") or "").strip()
        code_row = codes.get(code.lower(), {})
        transactions.append({
            "id": str(adjustment.get("id")),
            "date": adjustment.get("adjustment_date"),
            "source_module": "VAT",
            "source_type": "vat_adjustment",
            "document_type": "VAT Adjustment",
            "document_number": adjustment.get("reason") or adjustment.get("id"),
            "source_id": adjustment.get("id"),
            "account": "2200",
            "vat_code": code,
            "vat_code_description": code_row.get("description") or "",
            "net": money_str(money(adjustment.get("net_amount"))),
            "vat": money_str(money(adjustment.get("vat_amount"))),
            "gross": money_str(money(adjustment.get("gross_amount"))),
            "direction": "adjustment",
            "vat_period_id": period.get("id") if period else None,
            "vat_period": f"{period.get('period_start')} to {period.get('period_end')}" if period else "Unassigned",
            "status": period.get("status") if period else "unassigned",
            "box_sales_vat": code_row.get("box_sales_vat") or "1",
            "box_purchase_vat": "",
            "box_sales_net": "",
            "box_purchase_net": "",
        })

    return sorted(transactions, key=lambda item: (str(item.get("date") or ""), str(item.get("document_number") or "")), reverse=True)


def calculate_vat_boxes(transactions: list[dict]) -> dict[str, Decimal]:
    boxes = {f"box{i}": Decimal("0.00") for i in range(1, 10)}
    for item in transactions:
        direction = str(item.get("direction") or "")
        net = money(item.get("net")).copy_abs()
        vat = money(item.get("vat")).copy_abs()
        sign = Decimal("-1") if money(item.get("net")) < 0 or money(item.get("vat")) < 0 else Decimal("1")
        if direction == "sales":
            apply_vat_box(boxes, str(item.get("box_sales_vat") or ""), vat * sign)
            apply_vat_box(boxes, str(item.get("box_sales_net") or ""), net * sign)
        elif direction == "purchase":
            apply_vat_box(boxes, str(item.get("box_purchase_vat") or ""), vat * sign)
            apply_vat_box(boxes, str(item.get("box_purchase_net") or ""), net * sign)
        else:
            apply_vat_box(boxes, str(item.get("box_sales_vat") or "1"), money(item.get("vat")))
    boxes["box3"] = boxes["box1"] + boxes["box2"]
    boxes["box5"] = boxes["box3"] - boxes["box4"]
    return boxes


async def vat_engine_workspace(session: AsyncSession, client_id: str) -> dict:
    settings_row = await ensure_vat_settings(session, client_id)
    codes = await ensure_vat_codes(session, client_id)
    periods = await ensure_vat_periods(session, client_id, settings_row)
    serialized_periods = [serialize_vat_period(period) for period in periods]
    today = datetime.now(timezone.utc).date().isoformat()
    current_period = next((p for p in serialized_periods if str(p.get("period_start")) <= today <= str(p.get("period_end"))), serialized_periods[0] if serialized_periods else None)
    latest_return = await one(session, select(accounting_vat_returns).where(accounting_vat_returns.c.client_id == client_id).order_by(accounting_vat_returns.c.period_end.desc(), accounting_vat_returns.c.created_at.desc()).limit(1))
    boxes = {f"box{i}": money((latest_return or {}).get(f"box{i}")) for i in range(1, 10)}
    returns = [serialize_vat_return(r) for r in await many(session, select(accounting_vat_returns).where(accounting_vat_returns.c.client_id == client_id).order_by(accounting_vat_returns.c.period_end.desc(), accounting_vat_returns.c.created_at.desc()).limit(50))]
    dashboard = {
        "current_vat_liability": money_str(boxes["box5"]),
        "vat_due_to_hmrc": money_str(max(boxes["box5"], Decimal("0.00"))),
        "vat_recoverable": money_str(boxes["box4"]),
        "current_period": f"{current_period.get('period_start')} to {current_period.get('period_end')}" if current_period else "-",
        "next_return_due": current_period.get("due_date") if current_period else None,
        "outstanding_returns": len([p for p in serialized_periods if p.get("status") == "open" and str(p.get("due_date") or "") <= today]),
        "progress": 0,
        "output_vat": money_str(boxes["box1"] + boxes["box2"]),
        "input_vat": money_str(boxes["box4"]),
        "net_vat_due": money_str(boxes["box5"]),
    }
    return {
        "settings": dict(settings_row),
        "codes": [serialize_vat_code(c) for c in codes],
        "periods": serialized_periods,
        "transactions": [],
        "returns": returns,
        "adjustments": [],
        "current_boxes": {key: money_str(value) for key, value in boxes.items()},
        "dashboard": dashboard,
        "reports": {"lazy_loaded": True},
    }


def serialize_period(row: dict) -> dict:
    return dict(row)


def serialize_audit_event(row: dict) -> dict:
    row = dict(row)
    row["details_json"] = parse_json_object(row.get("details_json")) or {}
    return row


def serialize_accounting_settings(row: dict) -> dict:
    return dict(row)


def serialize_financial_year(row: dict) -> dict:
    return dict(row)


async def accounting_period_transaction_counts(session: AsyncSession, client_id: str) -> dict[str, int]:
    periods = await many(session, select(accounting_periods).where(accounting_periods.c.client_id == client_id))
    journals = await many(session, select(accounting_journal_entries).where(accounting_journal_entries.c.client_id == client_id))
    counts: dict[str, int] = {}
    for period in periods:
        start = str(period.get("period_start") or "")
        end = str(period.get("period_end") or "")
        counts[str(period.get("id"))] = len([
            journal for journal in journals
            if start <= str(journal.get("entry_date") or "") <= end and journal.get("status") == "posted"
        ])
    return counts


async def native_account_balances(session: AsyncSession, client_id: str) -> dict[str, Decimal]:
    balances: dict[str, Decimal] = {}
    lines = await many(session, select(accounting_journal_lines).where(accounting_journal_lines.c.client_id == client_id))
    for line in lines:
        code = str(line.get("account_code") or "")
        if not code:
            continue
        balances[code] = balances.get(code, Decimal("0.00")) + money(line.get("debit")) - money(line.get("credit"))
    return balances


def serialize_year_end_settings(row: dict) -> dict:
    item = dict(row)
    item["checklist_requirements"] = parse_json_object(item.get("checklist_requirements")) or {
        "no_draft_transactions": True,
        "bank_reconciliations_complete": True,
        "vat_periods_reviewed": True,
        "trial_balance_reviewed": True,
        "profit_and_loss_reviewed": True,
    }
    return item


def serialize_year_end_event(row: dict) -> dict:
    item = dict(row)
    item["payload"] = parse_json_object(item.get("payload_json")) or {}
    return item


def serialize_opening_balance(row: dict) -> dict:
    item = dict(row)
    item["debit"] = money_str(money(item.get("debit")))
    item["credit"] = money_str(money(item.get("credit")))
    return item


async def ensure_year_end_settings(session: AsyncSession, client_id: str) -> dict:
    existing = await one(session, select(accounting_year_end_settings).where(accounting_year_end_settings.c.client_id == client_id))
    if existing:
        return existing
    now = utc_now_iso()
    accounting_defaults = await ensure_accounting_settings(session, client_id)
    row = {
        "id": new_id(),
        "client_id": client_id,
        "retained_earnings_account": accounting_defaults.get("default_retained_earnings_account") or "3200",
        "allow_period_reopen": True,
        "automatic_opening_balances": True,
        "year_end_approval_required": False,
        "checklist_requirements": json.dumps({
            "no_draft_transactions": True,
            "bank_reconciliations_complete": True,
            "vat_periods_reviewed": True,
            "trial_balance_reviewed": True,
            "profit_and_loss_reviewed": True,
        }),
        "created_at": now,
        "updated_at": now,
    }
    await session.execute(insert(accounting_year_end_settings).values(**row))
    await session.flush()
    return row


async def record_year_end_event(
    session: AsyncSession,
    client_id: str,
    event_type: str,
    user_id: Optional[str],
    reason: str = "",
    financial_year_id: Optional[str] = None,
    period_id: Optional[str] = None,
    journal_entry_id: Optional[str] = None,
    payload: Optional[dict] = None,
) -> dict:
    row = {
        "id": new_id(),
        "client_id": client_id,
        "event_type": event_type,
        "financial_year_id": financial_year_id,
        "period_id": period_id,
        "journal_entry_id": journal_entry_id,
        "user_id": user_id,
        "reason": reason,
        "payload_json": json.dumps(payload or {}),
        "created_at": utc_now_iso(),
    }
    await session.execute(insert(accounting_year_end_events).values(**row))
    await add_accounting_audit(session, client_id, user_id, event_type, "year_end", row["id"], {**(payload or {}), "reason": reason})
    return row


def period_contains_date(period: dict, value: str) -> bool:
    entry_date = str(value or "")[:10]
    return bool(entry_date and str(period.get("period_start") or "") <= entry_date <= str(period.get("period_end") or ""))


def financial_year_contains_date(year: dict, value: str) -> bool:
    entry_date = str(value or "")[:10]
    return bool(entry_date and str(year.get("start_date") or "") <= entry_date <= str(year.get("end_date") or ""))


def account_balance_direction(account: dict, balance: Decimal) -> tuple[Decimal, Decimal]:
    if balance >= Decimal("0.00"):
        return balance, Decimal("0.00")
    return Decimal("0.00"), -balance


async def account_balances_for_financial_year(session: AsyncSession, client_id: str, year: dict) -> dict[str, Decimal]:
    entries = await many(
        session,
        select(accounting_journal_entries).where(
            accounting_journal_entries.c.client_id == client_id,
            accounting_journal_entries.c.status == "posted",
            accounting_journal_entries.c.entry_date >= str(year.get("start_date") or ""),
            accounting_journal_entries.c.entry_date <= str(year.get("end_date") or ""),
        ),
    )
    entry_ids = [str(entry.get("id")) for entry in entries]
    if not entry_ids:
        return {}
    lines = await many(
        session,
        select(accounting_journal_lines).where(
            accounting_journal_lines.c.client_id == client_id,
            accounting_journal_lines.c.entry_id.in_(entry_ids),
        ),
    )
    balances: dict[str, Decimal] = {}
    for line in lines:
        code = str(line.get("account_code") or "")
        if not code:
            continue
        balances[code] = balances.get(code, Decimal("0.00")) + money(line.get("debit")) - money(line.get("credit"))
    return balances


async def year_end_trial_balance(session: AsyncSession, client_id: str, year: dict, accounts: list[dict]) -> list[dict]:
    balances = await account_balances_for_financial_year(session, client_id, year)
    rows = []
    for account in accounts:
        balance = balances.get(str(account.get("code") or ""), Decimal("0.00"))
        if balance == Decimal("0.00"):
            continue
        debit, credit = account_balance_direction(account, balance)
        rows.append({
            "code": account.get("code"),
            "name": account.get("name"),
            "category": account.get("category"),
            "debit": money_str(debit),
            "credit": money_str(credit),
        })
    return rows


def year_end_profit_and_loss(accounts: list[dict], balances: dict[str, Decimal]) -> dict:
    income = Decimal("0.00")
    expense = Decimal("0.00")
    rows = []
    for account in accounts:
        code = str(account.get("code") or "")
        balance = balances.get(code, Decimal("0.00"))
        category = str(account.get("category") or "")
        if category == "Income":
            amount = -balance
            income += amount
        elif category == "Expense":
            amount = balance
            expense += amount
        else:
            continue
        if amount != Decimal("0.00"):
            rows.append({"code": code, "name": account.get("name"), "category": category, "amount": money_str(amount)})
    return {"income": money_str(income), "expenses": money_str(expense), "profit": money_str(income - expense), "rows": rows}


async def build_opening_balance_preview(session: AsyncSession, client_id: str, source_year: dict, target_year: Optional[dict], accounts: list[dict]) -> list[dict]:
    if not target_year:
        return []
    balances = await native_account_balances(session, client_id)
    rows = []
    for account in accounts:
        category = str(account.get("category") or "")
        if category not in {"Asset", "Liability", "Equity"}:
            continue
        balance = balances.get(str(account.get("code") or ""), Decimal("0.00"))
        if balance == Decimal("0.00"):
            continue
        debit, credit = account_balance_direction(account, balance)
        rows.append({
            "account_code": account.get("code"),
            "account_name": account.get("name"),
            "category": category,
            "debit": money_str(debit),
            "credit": money_str(credit),
            "source_financial_year_id": source_year.get("id"),
            "financial_year_id": target_year.get("id"),
            "status": "preview",
        })
    return rows


async def year_end_workspace(session: AsyncSession, client_id: str, accounts: list[dict], periods: list[dict], financial_years: list[dict]) -> dict:
    settings_row = await ensure_year_end_settings(session, client_id)
    today = datetime.now(timezone.utc).date().isoformat()
    ordered_years = sorted(financial_years, key=lambda row: str(row.get("start_date") or ""), reverse=True)
    current_year = next((year for year in ordered_years if str(year.get("start_date") or "") <= today <= str(year.get("end_date") or "")), None) or (ordered_years[0] if ordered_years else None)
    last_closed = next((year for year in ordered_years if str(year.get("status") or "") == "closed"), None)
    period_counts = await accounting_period_transaction_counts(session, client_id)
    period_rows = []
    for period in periods:
        item = serialize_period(period)
        item["transactions_posted"] = period_counts.get(str(period.get("id")), 0)
        period_rows.append(item)
    draft_journals = await many(session, select(accounting_journal_entries).where(accounting_journal_entries.c.client_id == client_id, accounting_journal_entries.c.status == "draft"))
    unreconciled_bank = await count_rows(session, accounting_bank_transactions, accounting_bank_transactions.c.client_id == client_id, accounting_bank_transactions.c.status != "reconciled", accounting_bank_transactions.c.ignored == False)  # noqa: E712
    open_vat_periods = await count_rows(session, accounting_vat_periods, accounting_vat_periods.c.client_id == client_id, accounting_vat_periods.c.status == "open")
    trial_balance = await year_end_trial_balance(session, client_id, current_year, accounts) if current_year else []
    balances = await account_balances_for_financial_year(session, client_id, current_year) if current_year else {}
    profit_loss = year_end_profit_and_loss(accounts, balances)
    next_year = None
    if current_year:
        next_year = next((year for year in financial_years if str(year.get("start_date") or "") > str(current_year.get("end_date") or "")), None)
    opening_preview = await build_opening_balance_preview(session, client_id, current_year, next_year, accounts) if current_year else []
    opening_rows = await many(session, select(accounting_opening_balances).where(accounting_opening_balances.c.client_id == client_id).order_by(accounting_opening_balances.c.created_at.desc()))
    events = await many(session, select(accounting_year_end_events).where(accounting_year_end_events.c.client_id == client_id).order_by(accounting_year_end_events.c.created_at.desc()).limit(100))
    closing_journals = await many(
        session,
        select(accounting_journal_entries).where(
            accounting_journal_entries.c.client_id == client_id,
            accounting_journal_entries.c.source_type.in_(["year_end_close", "year_end_adjustment", "opening_balance"]),
        ).order_by(accounting_journal_entries.c.entry_date.desc(), accounting_journal_entries.c.created_at.desc()),
    )
    validation_errors = []
    warnings = []
    if draft_journals:
        validation_errors.append(f"{len(draft_journals)} draft journal(s) must be posted or voided before year end close.")
    if unreconciled_bank:
        validation_errors.append(f"{unreconciled_bank} bank transaction(s) are still unreconciled.")
    if open_vat_periods:
        warnings.append(f"{open_vat_periods} VAT period(s) are still open. This is a warning, not a blocker.")
    outstanding_tasks = len(validation_errors) + len(warnings)
    return {
        "settings": serialize_year_end_settings(settings_row),
        "dashboard": {
            "current_financial_year": current_year.get("name") if current_year else "-",
            "open_periods": len([p for p in period_rows if p.get("status") == "open"]),
            "locked_periods": len([p for p in period_rows if p.get("status") == "locked"]),
            "closed_years": len([y for y in financial_years if y.get("status") == "closed"]),
            "outstanding_tasks": outstanding_tasks,
            "last_year_closed": last_closed.get("name") if last_closed else "-",
        },
        "current_year": serialize_financial_year(current_year) if current_year else None,
        "next_year": serialize_financial_year(next_year) if next_year else None,
        "financial_years": [serialize_financial_year(y) for y in financial_years],
        "periods": period_rows,
        "checklist": {
            "errors": validation_errors,
            "warnings": warnings,
            "items": [
                {"label": "No draft transactions remain", "complete": not draft_journals, "count": len(draft_journals)},
                {"label": "Bank reconciliations complete", "complete": unreconciled_bank == 0, "count": unreconciled_bank},
                {"label": "VAT periods reviewed", "complete": open_vat_periods == 0, "count": open_vat_periods, "warning_only": True},
                {"label": "Trial Balance reviewed", "complete": bool(trial_balance) or not current_year},
                {"label": "Profit and Loss reviewed", "complete": True},
            ],
        },
        "trial_balance": trial_balance,
        "profit_and_loss": profit_loss,
        "opening_balance_preview": opening_preview,
        "opening_balances": [serialize_opening_balance(row) for row in opening_rows],
        "closing_journals": closing_journals,
        "retained_earnings": {
            "account_code": settings_row.get("retained_earnings_account") or "3200",
            "current_year_profit": profit_loss.get("profit"),
            "automatic_transfer": True,
        },
        "lock_history": [serialize_year_end_event(e) for e in events],
        "reports": {
            "year_end_checklist": [
                {"item": row["label"], "status": "Complete" if row.get("complete") else "Open", "count": row.get("count", 0)}
                for row in [
                    {"label": "Draft transactions", "complete": not draft_journals, "count": len(draft_journals)},
                    {"label": "Unreconciled bank transactions", "complete": unreconciled_bank == 0, "count": unreconciled_bank},
                    {"label": "Open VAT periods", "complete": open_vat_periods == 0, "count": open_vat_periods},
                ]
            ],
            "closing_journal_report": closing_journals,
            "opening_balance_report": opening_preview,
            "period_lock_report": [serialize_year_end_event(e) for e in events if "period" in str(e.get("event_type") or "")],
            "financial_year_summary": [serialize_financial_year(y) for y in financial_years],
        },
        "ai_alerts": [
            {"module": "Year End", "type": "Validation", "detail": item, "target_tab": "Financial Year Close"}
            for item in validation_errors + warnings
        ],
    }


async def native_accounting_reports(
    session: AsyncSession,
    client_id: str,
    accounts: Optional[list[dict]] = None,
    ap: Optional[dict] = None,
    ar: Optional[dict] = None,
    banking: Optional[dict] = None,
    vat: Optional[dict] = None,
) -> dict:
    accounts = accounts or await many(session, select(accounting_accounts).where(accounting_accounts.c.client_id == client_id))
    account_by_code = {str(account.get("code") or ""): account for account in accounts}
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.client_id == client_id))
    contact_by_id = {str(contact.get("id") or ""): contact for contact in contacts}
    journals = await many(session, select(accounting_journal_entries).where(accounting_journal_entries.c.client_id == client_id))
    journal_by_id = {str(journal.get("id") or ""): journal for journal in journals}
    lines = await many(session, select(accounting_journal_lines).where(accounting_journal_lines.c.client_id == client_id))
    ap = ap or await accounts_payable_workspace(session, client_id)
    ar = ar or await accounts_receivable_workspace(session, client_id)
    banking = banking or await banking_workspace(session, client_id, accounts)
    vat = vat or await vat_engine_workspace(session, client_id)

    balances: dict[str, Decimal] = {}
    movements: dict[str, Decimal] = {}
    account_activity: dict[str, list[dict]] = {}
    aged_receivables: dict[str, dict] = {}
    aged_payables: dict[str, dict] = {}
    today = datetime.now(timezone.utc).date()
    month_start = today.replace(day=1)

    def parse_entry_date(value: str) -> Optional[date]:
        try:
            return datetime.fromisoformat(str(value or "")[:10]).date()
        except Exception:
            return None

    def account_type_for(code: str) -> str:
        account = account_by_code.get(code) or {}
        return str(account.get("account_type") or account.get("category") or "").lower()

    def account_category_for(code: str) -> str:
        account = account_by_code.get(code) or {}
        return str(account.get("category") or account.get("account_type") or "").lower()

    def account_purpose_for(code: str) -> str:
        account = account_by_code.get(code) or {}
        return str(account.get("purpose") or "").lower()

    def signed_account_value(code: str, balance: Decimal) -> Decimal:
        kind = account_type_for(code)
        category = account_category_for(code)
        if kind in ("income", "sales") or category == "income":
            return -balance
        if kind in ("liability", "payable", "vat", "equity") or category in ("liability", "equity"):
            return -balance
        return balance

    def is_income(code: str) -> bool:
        return account_type_for(code) in ("income", "sales") or account_category_for(code) == "income"

    def is_expense(code: str) -> bool:
        return account_type_for(code) in ("expense", "purchases", "cost of sales", "overheads") or account_category_for(code) == "expense"

    def is_asset(code: str) -> bool:
        return account_type_for(code) in ("asset", "bank", "receivable") or account_category_for(code) == "asset"

    def is_liability(code: str) -> bool:
        return account_type_for(code) in ("liability", "payable", "vat", "tax", "payroll") or account_category_for(code) == "liability"

    def is_equity(code: str) -> bool:
        return account_type_for(code) == "equity" or account_category_for(code) == "equity"

    def report_row(account: dict, balance: Decimal) -> dict:
        code = str(account.get("code") or "")
        return {
            "account_id": account.get("id"),
            "code": code,
            "name": account.get("name"),
            "category": account.get("category"),
            "account_type": account.get("account_type"),
            "purpose": account.get("purpose"),
            "balance": money_str(signed_account_value(code, balance)),
            "raw_balance": money_str(balance),
            "activity": account_activity.get(code, []),
        }

    monthly: dict[str, dict[str, Decimal]] = {}
    for line in lines:
        code = str(line.get("account_code") or "")
        if not code:
            continue
        debit = money(line.get("debit"))
        credit = money(line.get("credit"))
        balances[code] = balances.get(code, Decimal("0.00")) + debit - credit
        journal = journal_by_id.get(str(line.get("entry_id") or "")) or {}
        entry_date = str(journal.get("entry_date") or "")[:10]
        entry_day = parse_entry_date(entry_date)
        if entry_day and entry_day >= month_start:
            movements[code] = movements.get(code, Decimal("0.00")) + debit - credit
        month_key = entry_date[:7] if entry_date else "undated"
        monthly.setdefault(month_key, {"income": Decimal("0.00"), "expenses": Decimal("0.00"), "profit": Decimal("0.00")})
        if is_income(code):
            monthly[month_key]["income"] += credit - debit
        elif is_expense(code):
            monthly[month_key]["expenses"] += debit - credit
        monthly[month_key]["profit"] = monthly[month_key]["income"] - monthly[month_key]["expenses"]
        account_activity.setdefault(code, []).append({
            "date": entry_date,
            "reference": journal.get("reference"),
            "description": line.get("description") or journal.get("description"),
            "source_type": journal.get("source_type"),
            "source_id": journal.get("source_id"),
            "debit": money_str(debit),
            "credit": money_str(credit),
        })
        if code not in ("1100", "2000"):
            continue
        contact_id = str(line.get("contact_id") or "")
        contact = contact_by_id.get(contact_id) or {}
        contact_name = contact.get("name") or line.get("contact_name") or "Unassigned"
        try:
            age_days = max(0, (today - datetime.fromisoformat(entry_date).date()).days)
        except Exception:
            age_days = 0
        bucket = "current" if age_days <= 30 else "days_31_60" if age_days <= 60 else "days_61_90" if age_days <= 90 else "days_90_plus"
        target = aged_receivables if code == "1100" else aged_payables
        movement = debit - credit if code == "1100" else credit - debit
        if not movement:
            continue
        key = contact_id or contact_name.lower()
        row = target.setdefault(key, {
            "contact_id": contact_id or None,
            "contact_name": contact_name,
            "current": Decimal("0.00"),
            "days_31_60": Decimal("0.00"),
            "days_61_90": Decimal("0.00"),
            "days_90_plus": Decimal("0.00"),
            "total": Decimal("0.00"),
        })
        row[bucket] += movement
        row["total"] += movement

    trial_balance = []
    income_total = Decimal("0.00")
    expense_total = Decimal("0.00")
    asset_total = Decimal("0.00")
    liability_total = Decimal("0.00")
    equity_total = Decimal("0.00")
    current_month_income = Decimal("0.00")
    current_month_expenses = Decimal("0.00")
    sections = {"income": [], "expenses": [], "assets": [], "liabilities": [], "equity": []}

    for account in sorted(accounts, key=lambda item: str(item.get("code") or "")):
        code = str(account.get("code") or "")
        balance = balances.get(code, Decimal("0.00"))
        movement = movements.get(code, Decimal("0.00"))
        account_type = str(account.get("account_type") or "").lower()
        row = report_row(account, balance)
        if is_income(code):
            income_total += -balance
            current_month_income += -movement
            sections["income"].append(row)
        elif is_expense(code):
            expense_total += balance
            current_month_expenses += movement
            sections["expenses"].append(row)
        elif is_asset(code):
            asset_total += balance
            sections["assets"].append(row)
        elif is_liability(code):
            liability_total += -balance
            sections["liabilities"].append(row)
        elif is_equity(code):
            equity_total += -balance
            sections["equity"].append(row)
        if balance:
            trial_balance.append({
                "account_id": account.get("id"),
                "code": code,
                "name": account.get("name"),
                "type": account_type,
                "category": account.get("category"),
                "purpose": account.get("purpose"),
                "debit": money_str(balance if balance > 0 else Decimal("0.00")),
                "credit": money_str(-balance if balance < 0 else Decimal("0.00")),
                "movement": money_str(movement),
                "activity": account_activity.get(code, []),
            })

    month_rows = []
    for key in sorted([k for k in monthly.keys() if k != "undated"])[-12:]:
        values = monthly[key]
        month_rows.append({
            "period": key,
            "income": money_str(values["income"]),
            "expenses": money_str(values["expenses"]),
            "profit": money_str(values["profit"]),
        })

    cash_at_bank = sum(
        (signed_account_value(code, balance) for code, balance in balances.items() if account_purpose_for(code) == "bank account" or account_type_for(code) == "bank"),
        Decimal("0.00"),
    )
    ar_total = sum((row["total"] for row in aged_receivables.values()), Decimal("0.00"))
    ap_total = sum((row["total"] for row in aged_payables.values()), Decimal("0.00"))
    vat_liability = money(vat.get("dashboard", {}).get("net_vat_due"))
    gross_profit = income_total - sum(
        (balances.get(str(account.get("code") or ""), Decimal("0.00")) for account in accounts if str(account.get("account_type") or "").lower() == "cost of sales"),
        Decimal("0.00"),
    )
    net_profit = income_total - expense_total
    recent_activity = []
    for journal in sorted(journals, key=lambda item: (str(item.get("entry_date") or ""), str(item.get("created_at") or "")), reverse=True)[:12]:
        recent_activity.append({
            "date": str(journal.get("entry_date") or "")[:10],
            "module": vat_source_module(str(journal.get("source_type") or "")),
            "record_type": str(journal.get("source_type") or "journal").replace("_", " ").title(),
            "reference": journal.get("reference"),
            "description": journal.get("description"),
            "amount": money_str(money(journal.get("total_debit"))),
        })

    vat_transactions = vat.get("transactions", [])
    vat_by_code: dict[str, dict] = {}
    for item in vat_transactions:
        key = str(item.get("vat_code") or "No VAT")
        row = vat_by_code.setdefault(key, {"vat_code": key, "net": Decimal("0.00"), "vat": Decimal("0.00"), "gross": Decimal("0.00"), "transactions": 0})
        row["net"] += money(item.get("net"))
        row["vat"] += money(item.get("vat"))
        row["gross"] += money(item.get("gross"))
        row["transactions"] += 1

    def serialize_totals(rows: dict[str, dict]) -> list[dict]:
        return [
            {**row, "net": money_str(row["net"]), "vat": money_str(row["vat"]), "gross": money_str(row["gross"])}
            for row in sorted(rows.values(), key=lambda item: item["vat_code"])
        ]

    def percent_str(value: Decimal) -> str:
        return f"{value.quantize(Decimal('0.01'))}%"

    bank_reports = banking.get("reports", {})
    bank_transactions = banking.get("transactions", [])
    purchase_invoices = ap.get("invoices", [])
    sales_invoices = ar.get("invoices", [])
    supplier_spend = []
    for row in ap.get("suppliers", []):
        supplier_spend.append({
            "supplier": row.get("name"),
            "outstanding": row.get("outstanding_balance") or "0.00",
            "invoice_count": len([i for i in purchase_invoices if str(i.get("supplier_id") or "") == str(row.get("id") or "")]),
        })
    customer_sales = []
    for row in ar.get("customers", []):
        customer_sales.append({
            "customer": row.get("name"),
            "outstanding": row.get("outstanding_balance") or "0.00",
            "invoice_count": len([i for i in sales_invoices if str(i.get("customer_id") or "") == str(row.get("id") or "")]),
        })

    return {
        "dashboard": {
            "revenue_this_month": money_str(current_month_income),
            "expenses_this_month": money_str(current_month_expenses),
            "gross_profit": money_str(gross_profit),
            "net_profit": money_str(net_profit),
            "cash_at_bank": money_str(cash_at_bank),
            "vat_liability": money_str(vat_liability),
            "accounts_receivable": money_str(ar_total),
            "accounts_payable": money_str(ap_total),
            "financial_performance": month_rows,
            "bank_balances": banking.get("bank_accounts", []),
            "working_capital": {
                "debtors": money_str(ar_total),
                "creditors": money_str(ap_total),
                "cash": money_str(cash_at_bank),
                "net_working_capital": money_str(ar_total + cash_at_bank - ap_total),
            },
            "recent_activity": recent_activity,
        },
        "profit_and_loss": {
            "income": money_str(income_total),
            "expenses": money_str(expense_total),
            "profit": money_str(income_total - expense_total),
            "gross_profit": money_str(gross_profit),
            "sections": {
                "income": sections["income"],
                "expenses": sections["expenses"],
            },
            "monthly": month_rows,
        },
        "balance_sheet": {
            "assets": money_str(asset_total),
            "liabilities": money_str(liability_total),
            "equity": money_str(equity_total),
            "net_assets": money_str(asset_total - liability_total),
            "current_year_profit": money_str(net_profit),
            "sections": {
                "assets": sections["assets"],
                "liabilities": sections["liabilities"],
                "equity": sections["equity"],
            },
        },
        "trial_balance": trial_balance,
        "cash_flow": {
            "operating_activities": money_str(net_profit),
            "investing_activities": money_str(Decimal("0.00")),
            "financing_activities": money_str(Decimal("0.00")),
            "net_cash_movement": money_str(sum((bank_transaction_amount(t) for t in bank_transactions), Decimal("0.00"))),
            "rows": bank_transactions[:50],
        },
        "statement_of_changes_in_equity": {
            "opening_equity": money_str(equity_total - net_profit),
            "current_year_profit": money_str(net_profit),
            "closing_equity": money_str(equity_total),
        },
        "management": {
            "department_summary": [],
            "income_vs_expenses": month_rows,
            "monthly_performance": month_rows,
            "trend_analysis": month_rows,
            "kpi_summary": {
                "gross_margin": percent_str((gross_profit / income_total * Decimal("100")) if income_total else Decimal("0.00")),
                "net_margin": percent_str((net_profit / income_total * Decimal("100")) if income_total else Decimal("0.00")),
                "working_capital": money_str(ar_total + cash_at_bank - ap_total),
            },
        },
        "vat_reports": {
            "return_summary": vat.get("current_boxes", {}),
            "detail": vat_transactions,
            "audit": vat_transactions,
            "exceptions": vat.get("reports", {}).get("exceptions", []),
            "by_code": serialize_totals(vat_by_code),
        },
        "sales_reports": {
            "sales_analysis": sales_invoices,
            "customer_sales": customer_sales,
            "invoice_analysis": sales_invoices,
            "receipts_analysis": ar.get("receipts", []),
            "aged_debtors": serialize_aged_balances(aged_receivables),
        },
        "purchase_reports": {
            "purchase_analysis": purchase_invoices,
            "supplier_spend": supplier_spend,
            "outstanding_bills": [i for i in purchase_invoices if money(i.get("outstanding_amount")) > Decimal("0.00")],
            "purchase_vat": [t for t in vat_transactions if t.get("direction") == "purchase"],
            "payment_forecast": ap.get("payments", []),
            "aged_creditors": serialize_aged_balances(aged_payables),
        },
        "bank_reports": {
            "cashbook": banking.get("cashbook", []),
            "reconciliation": bank_reports.get("unreconciled_items", []),
            "bank_charges": bank_reports.get("bank_charges", []),
            "interest": bank_reports.get("interest", []),
            "bank_activity": bank_transactions,
            "outstanding_transactions": bank_reports.get("unreconciled_items", []),
            "balances": banking.get("bank_accounts", []),
        },
        "custom_reports": {
            "available_columns": ["Date", "Reference", "Account", "Contact", "Net", "VAT", "Gross", "Source Module", "Status"],
            "saved_reports": [],
            "grouping_options": ["Account", "Contact", "VAT Code", "Month", "Source Module"],
            "sorting_options": ["Date", "Amount", "Reference", "Account"],
        },
        "report_scheduler": {
            "frequencies": ["Daily", "Weekly", "Monthly", "Quarterly"],
            "delivery_methods": ["Download", "Email (future)", "Client Portal (future)"],
            "scheduled_reports": [],
        },
        "exports": {
            "formats": ["PDF", "Excel", "CSV"],
            "print_layout": "EPOS standard report layout",
            "generated": [],
        },
        "settings": {
            "report_basis": "accrual",
            "default_date_range": "current_financial_year",
            "comparative_periods": True,
            "currency": "GBP",
            "pdf_branding": "EPOS Accountancy",
        },
        "aged_receivables": serialize_aged_balances(aged_receivables),
        "aged_payables": serialize_aged_balances(aged_payables),
        "account_count": len(account_by_code),
    }


def serialize_aged_balances(rows: dict[str, dict]) -> list[dict]:
    result = []
    for row in rows.values():
        if row["total"] == Decimal("0.00"):
            continue
        result.append({
            "contact_id": row.get("contact_id"),
            "contact_name": row.get("contact_name"),
            "current": money_str(row["current"]),
            "days_31_60": money_str(row["days_31_60"]),
            "days_61_90": money_str(row["days_61_90"]),
            "days_90_plus": money_str(row["days_90_plus"]),
            "total": money_str(row["total"]),
        })
    return sorted(result, key=lambda item: str(item.get("contact_name") or "").lower())


FIXED_ASSET_DEFAULT_CATEGORIES = [
    ("Plant & Machinery", 60),
    ("Motor Vehicles", 48),
    ("Office Equipment", 36),
    ("Computer Equipment", 36),
    ("Furniture & Fixtures", 60),
    ("Buildings", 300),
    ("Leasehold Improvements", 120),
]


def default_fixed_asset_settings(client_id: str, now: Optional[str] = None) -> dict:
    timestamp = now or utc_now_iso()
    return {
        "id": new_id(),
        "client_id": client_id,
        "default_depreciation_method": "straight_line",
        "posting_frequency": "monthly",
        "asset_number_prefix": "FA",
        "next_asset_number": 1,
        "capitalisation_threshold": "500.00",
        "default_fixed_asset_account": "1500",
        "default_accumulated_depreciation_account": "1590",
        "default_depreciation_expense_account": "7500",
        "default_disposal_account": "7010",
        "created_at": timestamp,
        "updated_at": timestamp,
    }


async def ensure_fixed_asset_settings(session: AsyncSession, client_id: str) -> dict:
    existing = await one(session, select(accounting_fixed_asset_settings).where(accounting_fixed_asset_settings.c.client_id == client_id))
    if existing:
        return existing
    row = default_fixed_asset_settings(client_id)
    await session.execute(insert(accounting_fixed_asset_settings).values(**row))
    return row


async def ensure_fixed_asset_categories(session: AsyncSession, client_id: str, settings_row: Optional[dict] = None) -> list[dict]:
    existing = await many(
        session,
        select(accounting_fixed_asset_categories)
        .where(accounting_fixed_asset_categories.c.client_id == client_id)
        .order_by(accounting_fixed_asset_categories.c.name.asc()),
    )
    if existing:
        return existing
    settings_row = settings_row or await ensure_fixed_asset_settings(session, client_id)
    now = utc_now_iso()
    for name, life_months in FIXED_ASSET_DEFAULT_CATEGORIES:
        await session.execute(
            insert(accounting_fixed_asset_categories).values(
                id=new_id(),
                client_id=client_id,
                name=name,
                description=f"Default category for {name.lower()}",
                default_depreciation_method=settings_row.get("default_depreciation_method") or "straight_line",
                default_useful_life_months=life_months,
                default_residual_value="0.00",
                fixed_asset_account=settings_row.get("default_fixed_asset_account") or "1500",
                accumulated_depreciation_account=settings_row.get("default_accumulated_depreciation_account") or "1590",
                depreciation_expense_account=settings_row.get("default_depreciation_expense_account") or "7500",
                active=True,
                created_at=now,
                updated_at=now,
            )
        )
    return await many(
        session,
        select(accounting_fixed_asset_categories)
        .where(accounting_fixed_asset_categories.c.client_id == client_id)
        .order_by(accounting_fixed_asset_categories.c.name.asc()),
    )


def serialize_fixed_asset(row: dict) -> dict:
    item = dict(row)
    item["purchase_cost"] = money_str(money(item.get("purchase_cost")))
    item["residual_value"] = money_str(money(item.get("residual_value")))
    item["accumulated_depreciation"] = money_str(money(item.get("accumulated_depreciation")))
    item["net_book_value"] = money_str(money(item.get("net_book_value") or item.get("purchase_cost")))
    item["disposal_proceeds"] = money_str(money(item.get("disposal_proceeds")))
    return item


def serialize_fixed_asset_category(row: dict) -> dict:
    item = dict(row)
    item["default_residual_value"] = money_str(money(item.get("default_residual_value")))
    return item


def serialize_fixed_asset_event(row: dict) -> dict:
    item = dict(row)
    item["amount"] = money_str(money(item.get("amount")))
    return item


def next_asset_code(settings_row: dict) -> str:
    prefix = str(settings_row.get("asset_number_prefix") or "FA").strip() or "FA"
    number = int(settings_row.get("next_asset_number") or 1)
    return f"{prefix}-{number:05d}"


def account_from_code(accounts: list[dict], code: str, label: str) -> dict:
    account = next((a for a in accounts if str(a.get("code") or "") == str(code or "")), None)
    if not account:
        raise HTTPException(status_code=400, detail=f"{label} account {code or ''} is missing from the chart of accounts.")
    return account


def build_asset_schedule(asset: dict, months: int = 24) -> list[dict]:
    if str(asset.get("status") or "active") != "active":
        return []
    purchase_cost = money(asset.get("purchase_cost"))
    residual = money(asset.get("residual_value"))
    accumulated = money(asset.get("accumulated_depreciation"))
    life_months = max(1, int(asset.get("useful_life_months") or 36))
    start_date = parse_date_or_today(asset.get("in_service_date") or asset.get("capitalisation_date") or asset.get("purchase_date"))
    depreciable = max(Decimal("0.00"), purchase_cost - residual)
    straight_charge = (depreciable / Decimal(life_months)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    current_nbv = money(asset.get("net_book_value"))
    opening_nbv = max(residual, current_nbv if current_nbv else purchase_cost - accumulated)
    ytd = Decimal("0.00")
    schedule = []
    cursor = date(start_date.year, start_date.month, 1)
    for index in range(months):
        period_start = add_months_to_date(cursor, index)
        period_end = add_months_to_date(period_start, 1) - timedelta(days=1)
        if str(asset.get("depreciation_method") or "straight_line") == "reducing_balance":
            charge = (opening_nbv * Decimal("0.25") / Decimal("12")).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
            charge = min(charge, max(Decimal("0.00"), opening_nbv - residual))
        else:
            charge = min(straight_charge, max(Decimal("0.00"), purchase_cost - residual - accumulated - ytd))
        closing = max(residual, opening_nbv - charge)
        ytd += charge
        schedule.append({
            "asset_id": asset.get("id"),
            "asset_code": asset.get("asset_code"),
            "asset_name": asset.get("asset_name"),
            "period_label": period_start.strftime("%b %Y"),
            "period_start": period_start.isoformat(),
            "period_end": period_end.isoformat(),
            "opening_nbv": money_str(opening_nbv),
            "charge": money_str(charge),
            "ytd_depreciation": money_str(ytd),
            "accumulated_depreciation": money_str(accumulated + ytd),
            "closing_nbv": money_str(closing),
            "status": "scheduled",
        })
        opening_nbv = closing
        if charge <= Decimal("0.00"):
            break
    return schedule


async def fixed_assets_workspace(session: AsyncSession, client_id: str, accounts: Optional[list[dict]] = None, ap: Optional[dict] = None) -> dict:
    settings_row = await ensure_fixed_asset_settings(session, client_id)
    categories = await ensure_fixed_asset_categories(session, client_id, settings_row)
    assets = await many(
        session,
        select(accounting_fixed_assets)
        .where(accounting_fixed_assets.c.client_id == client_id)
        .order_by(accounting_fixed_assets.c.created_at.desc()),
    )
    events = await many(
        session,
        select(accounting_fixed_asset_events)
        .where(accounting_fixed_asset_events.c.client_id == client_id)
        .order_by(accounting_fixed_asset_events.c.created_at.desc())
        .limit(100),
    )
    posted_depreciation = await many(
        session,
        select(accounting_fixed_asset_depreciation)
        .where(accounting_fixed_asset_depreciation.c.client_id == client_id)
        .order_by(accounting_fixed_asset_depreciation.c.period_start.desc(), accounting_fixed_asset_depreciation.c.created_at.desc())
        .limit(200),
    )
    active_assets = [serialize_fixed_asset(a) for a in assets if str(a.get("status") or "active") == "active"]
    disposed_assets = [serialize_fixed_asset(a) for a in assets if str(a.get("status") or "") in {"disposed", "scrapped", "written_off"}]
    schedules = []
    for asset in active_assets:
        schedules.extend(build_asset_schedule(asset, 12))
    today = datetime.now(timezone.utc).date()
    current_month = today.strftime("%Y-%m")
    total_cost = sum((money(a.get("purchase_cost")) for a in active_assets), Decimal("0.00"))
    accumulated = sum((money(a.get("accumulated_depreciation")) for a in active_assets), Decimal("0.00"))
    nbv = sum((money(a.get("net_book_value")) for a in active_assets), Decimal("0.00"))
    added_this_year = len([a for a in assets if str(a.get("purchase_date") or "").startswith(str(today.year))])
    depreciation_this_month = sum((money(r.get("charge")) for r in posted_depreciation if str(r.get("period_start") or "").startswith(current_month)), Decimal("0.00"))
    category_totals: dict[str, dict] = {}
    for asset in active_assets:
        name = asset.get("category_name") or "Uncategorised"
        row = category_totals.setdefault(name, {"category": name, "count": 0, "cost": Decimal("0.00"), "nbv": Decimal("0.00")})
        row["count"] += 1
        row["cost"] += money(asset.get("purchase_cost"))
        row["nbv"] += money(asset.get("net_book_value"))
    threshold = money(settings_row.get("capitalisation_threshold"))
    existing_invoice_ids = {str(a.get("purchase_invoice_id") or "") for a in assets if a.get("purchase_invoice_id")}
    suggestions = []
    for invoice in (ap or {}).get("invoices", []):
        if str(invoice.get("id") or "") in existing_invoice_ids:
            continue
        gross = money(invoice.get("gross_amount"))
        net = money(invoice.get("net_amount"))
        candidate = gross if gross > Decimal("0.00") else net
        if candidate >= threshold:
            suggestions.append({
                "purchase_invoice_id": invoice.get("id"),
                "supplier_id": invoice.get("supplier_id"),
                "supplier_name": invoice.get("supplier_name"),
                "asset_name": invoice.get("description") or invoice.get("invoice_number") or "Purchase invoice asset",
                "purchase_date": invoice.get("invoice_date"),
                "purchase_cost": money_str(net if net > Decimal("0.00") else candidate),
                "reference": invoice.get("invoice_number") or invoice.get("reference"),
                "confidence": 72,
                "reason": f"Purchase is above the capitalisation threshold of {money_str(threshold)}.",
            })
    return {
        "settings": dict(settings_row),
        "categories": [serialize_fixed_asset_category(c) for c in categories],
        "assets": [serialize_fixed_asset(a) for a in assets],
        "events": [serialize_fixed_asset_event(e) for e in events],
        "depreciation_schedule": schedules,
        "posted_depreciation": [serialize_fixed_asset_event(r) if "event_type" in r else dict(r) for r in posted_depreciation],
        "suggestions": suggestions[:20],
        "dashboard": {
            "total_asset_cost": money_str(total_cost),
            "net_book_value": money_str(nbv),
            "accumulated_depreciation": money_str(accumulated),
            "assets_added_this_year": added_this_year,
            "assets_disposed": len(disposed_assets),
            "depreciation_this_month": money_str(depreciation_this_month),
            "awaiting_depreciation": len([s for s in schedules if money(s.get("charge")) > Decimal("0.00")]),
        },
        "panels": {
            "awaiting_depreciation": [s for s in schedules if money(s.get("charge")) > Decimal("0.00")][:8],
            "recently_acquired": active_assets[:8],
            "upcoming_disposals": [a for a in active_assets if "dispose" in str(a.get("notes") or "").lower()][:8],
            "fully_depreciated": [a for a in active_assets if money(a.get("net_book_value")) <= money(a.get("residual_value"))][:8],
        },
        "reports": {
            "asset_register": active_assets,
            "depreciation_schedule": schedules,
            "asset_additions": [serialize_fixed_asset(a) for a in assets if str(a.get("purchase_date") or "").startswith(str(today.year))],
            "asset_disposals": disposed_assets,
            "revaluations": [serialize_fixed_asset_event(e) for e in events if str(e.get("event_type") or "") == "revaluation"],
            "nbv_summary": [{"category": row["category"], "count": row["count"], "cost": money_str(row["cost"]), "nbv": money_str(row["nbv"])} for row in category_totals.values()],
            "category_analysis": [{"category": row["category"], "count": row["count"], "cost": money_str(row["cost"]), "nbv": money_str(row["nbv"])} for row in category_totals.values()],
        },
    }


def build_ai_accounting_workspace(
    client_id: str,
    summary: dict,
    accounts: list[dict],
    contacts: list[dict],
    journals: list[dict],
    periods: list[dict],
    audit_events: list[dict],
    ap: dict,
    ar: dict,
    banking: dict,
    vat: dict,
    reports: dict,
) -> dict:
    today = datetime.now(timezone.utc).date()
    ap_dashboard = ap.get("dashboard", {})
    ar_dashboard = ar.get("dashboard", {})
    banking_dashboard = banking.get("dashboard", {})
    vat_dashboard = vat.get("dashboard", {})
    report_dashboard = reports.get("dashboard", {})

    def amount_value(value) -> Decimal:
        return money(value)

    def due_days(value) -> Optional[int]:
        try:
            due = datetime.fromisoformat(str(value or "")[:10]).date()
            return (due - today).days
        except Exception:
            return None

    def dated_item_date(row: dict, *keys: str) -> str:
        for key in keys:
            value = str(row.get(key) or "")[:10]
            if value:
                return value
        return ""

    def queue_item(priority: str, module: str, title: str, detail: str, action: str, tab: str = "") -> dict:
        return {
            "id": new_id(),
            "priority": priority,
            "module": module,
            "title": title,
            "detail": detail,
            "action": action,
            "target_tab": tab,
        }

    work_queue: dict[str, list[dict]] = {"high": [], "medium": [], "low": []}
    exceptions: list[dict] = []
    approvals: list[dict] = []
    deadlines: list[dict] = []
    insights: list[dict] = []

    unreconciled = int(banking_dashboard.get("unreconciled_transactions") or 0)
    awaiting_match = int(banking_dashboard.get("awaiting_match") or 0)
    vat_outstanding = int(vat_dashboard.get("outstanding_returns") or 0)
    ap_awaiting = int(ap_dashboard.get("awaiting_approval") or 0)
    ar_awaiting = len([i for i in ar.get("invoices", []) if i.get("status") in {"draft", "awaiting_approval", "approved"}])
    ap_overdue = int(ap_dashboard.get("overdue_invoices") or 0)
    ar_overdue = int(ar_dashboard.get("overdue_invoices") or 0)

    if vat_outstanding:
        work_queue["high"].append(queue_item("High", "VAT", f"{vat_outstanding} VAT return needs attention", "A VAT period is open and at or past its return due date.", "Review VAT Returns", "VAT Returns"))
    if unreconciled:
        work_queue["high"].append(queue_item("High", "Banking", f"{unreconciled} unreconciled bank transactions", "Reconcile imported and manual bank transactions before reporting.", "Open Reconciliation", "Reconciliation"))
    if ar_overdue:
        work_queue["high"].append(queue_item("High", "Accounts Receivable", f"{ar_overdue} overdue customer invoices", "Customer cash collection needs review.", "Open Aged Debtors", "Aged Debtors"))
    if ap_overdue:
        work_queue["medium"].append(queue_item("Medium", "Accounts Payable", f"{ap_overdue} overdue supplier bills", "Supplier balances have passed their due date.", "Open Aged Creditors", "Aged Creditors"))
    if ap_awaiting:
        work_queue["medium"].append(queue_item("Medium", "Accounts Payable", f"{ap_awaiting} purchase invoices awaiting approval", "Approve or reject purchase invoices before posting.", "Open Purchase Invoices", "Purchase Invoices"))
    if ar_awaiting:
        work_queue["medium"].append(queue_item("Medium", "Accounts Receivable", f"{ar_awaiting} sales invoices awaiting posting", "Review sales invoices so income and debtors are up to date.", "Open Sales Invoices", "Sales Invoices"))
    if awaiting_match:
        work_queue["low"].append(queue_item("Low", "Banking", f"{awaiting_match} suggested bank matches", "Suggested matches are available for approval.", "Review Suggested Matches", "Reconciliation"))

    for invoice in ap.get("invoices", []):
        status = str(invoice.get("status") or "")
        if status in {"draft", "awaiting_approval", "approved"}:
            approvals.append({
                "module": "Accounts Payable",
                "record_type": "Purchase Invoice",
                "reference": invoice.get("invoice_number") or invoice.get("reference") or "Purchase invoice",
                "contact": invoice.get("supplier_name"),
                "amount": invoice.get("gross_amount"),
                "status": status.replace("_", " ").title(),
                "date": dated_item_date(invoice, "invoice_date", "created_at"),
            })
    for invoice in ar.get("invoices", []):
        status = str(invoice.get("status") or "")
        if status in {"draft", "awaiting_approval", "approved"}:
            approvals.append({
                "module": "Accounts Receivable",
                "record_type": "Sales Invoice",
                "reference": invoice.get("invoice_number") or invoice.get("reference") or "Sales invoice",
                "contact": invoice.get("customer_name"),
                "amount": invoice.get("gross_amount"),
                "status": status.replace("_", " ").title(),
                "date": dated_item_date(invoice, "invoice_date", "created_at"),
            })

    invoice_keys: dict[str, list[str]] = {}
    for invoice in ap.get("invoices", []):
        key = f"ap:{invoice.get('supplier_id')}:{str(invoice.get('invoice_number') or '').strip().lower()}:{money_str(money(invoice.get('gross_amount')))}"
        if invoice.get("invoice_number"):
            invoice_keys.setdefault(key, []).append(invoice.get("invoice_number"))
    for key, values in invoice_keys.items():
        if len(values) > 1:
            exceptions.append({"severity": "High", "module": "Accounts Payable", "type": "Possible duplicate", "detail": f"{len(values)} purchase invoices share supplier, number and amount.", "reference": values[0]})

    for item in vat.get("reports", {}).get("exceptions", []):
        exceptions.append({
            "severity": "Medium",
            "module": "VAT",
            "type": "Missing VAT data",
            "detail": "A VAT transaction is missing a VAT code or VAT period.",
            "reference": item.get("document_number") or item.get("source_id") or item.get("id"),
        })

    suspense_accounts = {str(a.get("code") or "") for a in accounts if str(a.get("purpose") or "").lower() == "suspense" or "suspense" in str(a.get("name") or "").lower()}
    for journal in journals:
        total = amount_value(journal.get("total_debit"))
        if total >= Decimal("5000.00"):
            exceptions.append({"severity": "Medium", "module": "General Ledger", "type": "Large journal", "detail": f"Journal total is {money_str(total)}.", "reference": journal.get("reference") or journal.get("id")})
        for line in journal.get("lines", []) or []:
            if str(line.get("account_code") or "") in suspense_accounts:
                exceptions.append({"severity": "High", "module": "General Ledger", "type": "Suspense posting", "detail": "A journal line has been posted to suspense.", "reference": journal.get("reference") or journal.get("id")})
                break

    for period in periods:
        if period.get("status") == "open":
            days = due_days(period.get("period_end"))
            if days is not None and 0 <= days <= 14:
                deadlines.append({"module": "General Ledger", "title": f"{period.get('period_name') or 'Accounting period'} ends soon", "start_date": period.get("period_start"), "due_date": period.get("period_end"), "status": period.get("status"), "days": days})
    for row in vat.get("periods", []):
        days = due_days(row.get("due_date"))
        if days is not None and days <= 45 and row.get("status") == "open":
            deadlines.append({"module": "VAT", "title": "VAT return due", "start_date": row.get("period_start"), "due_date": row.get("due_date"), "status": row.get("status"), "days": days})
    for invoice in ar.get("overdue_invoices", [])[:10]:
        deadlines.append({"module": "Accounts Receivable", "title": f"Customer invoice overdue: {invoice.get('invoice_number')}", "start_date": invoice.get("invoice_date"), "due_date": invoice.get("due_date"), "status": invoice.get("status"), "days": -int(invoice.get("days_overdue") or 0)})
    for invoice in ap.get("invoices", []):
        if money(invoice.get("outstanding_amount")) > Decimal("0.00"):
            days = due_days(invoice.get("due_date"))
            if days is not None and days <= 14:
                deadlines.append({"module": "Accounts Payable", "title": f"Supplier bill due: {invoice.get('invoice_number')}", "start_date": invoice.get("invoice_date"), "due_date": invoice.get("due_date"), "status": invoice.get("status"), "days": days})

    if amount_value(report_dashboard.get("net_profit")) < Decimal("0.00"):
        net_profit = report_dashboard.get("net_profit") or "0.00"
        insights.append({"tone": "warning", "module": "Reports", "title": "Profit is negative this month", "detail": f"Net profit is {net_profit}. Review high expense categories and unposted income."})
    if amount_value(ap_dashboard.get("outstanding_total")) > amount_value(ar_dashboard.get("outstanding_total")) and amount_value(ap_dashboard.get("outstanding_total")) > 0:
        insights.append({"tone": "warning", "module": "Cash", "title": "Supplier exposure is higher than customer debt", "detail": "Outstanding payables exceed outstanding receivables. Check short-term cash position before payment runs."})
    if banking_dashboard.get("last_bank_import"):
        insights.append({"tone": "info", "module": "Banking", "title": "Bank data is available", "detail": f"Last bank import was {banking_dashboard.get('last_bank_import')}. Review suggested matches while they are fresh."})
    if not insights:
        insights.append({"tone": "success", "module": "AI Workspace", "title": "No major accounting issues detected", "detail": "The current ledgers do not show urgent rule-based exceptions."})

    health_penalty = (
        min(25, len(exceptions) * 4)
        + min(20, unreconciled)
        + min(20, vat_outstanding * 8)
        + min(15, ap_awaiting + ar_awaiting)
        + min(20, ap_overdue + ar_overdue)
    )
    health_score = max(0, 100 - health_penalty)
    health_categories = [
        {"area": "Banking", "score": max(0, 100 - min(60, unreconciled * 5)), "status": "Healthy" if unreconciled == 0 else "Needs reconciliation"},
        {"area": "VAT", "score": max(0, 100 - min(70, vat_outstanding * 25 + len(vat.get("reports", {}).get("exceptions", [])) * 10)), "status": "Healthy" if not vat_outstanding else "Return due"},
        {"area": "Approvals", "score": max(0, 100 - min(60, (ap_awaiting + ar_awaiting) * 8)), "status": "Clear" if not (ap_awaiting + ar_awaiting) else "Waiting"},
        {"area": "Debtors/Creditors", "score": max(0, 100 - min(70, (ap_overdue + ar_overdue) * 10)), "status": "Healthy" if not (ap_overdue + ar_overdue) else "Overdue items"},
    ]

    def search_row(kind: str, label: str, reference: str = "", amount: str = "", module: str = "") -> dict:
        return {"type": kind, "label": label, "reference": reference or "", "amount": amount or "", "module": module or kind}

    search_index = []
    search_index += [search_row("Contact", c.get("name"), c.get("email"), "", str(c.get("contact_type") or "Contact").title()) for c in contacts]
    search_index += [search_row("Purchase Invoice", i.get("invoice_number") or "Purchase invoice", i.get("supplier_name"), i.get("gross_amount"), "Accounts Payable") for i in ap.get("invoices", [])]
    search_index += [search_row("Sales Invoice", i.get("invoice_number") or "Sales invoice", i.get("customer_name"), i.get("gross_amount"), "Accounts Receivable") for i in ar.get("invoices", [])]
    search_index += [search_row("Bank Transaction", t.get("description") or t.get("reference") or "Bank transaction", t.get("reference"), t.get("amount"), "Banking") for t in banking.get("transactions", [])]
    search_index += [search_row("Journal", j.get("reference") or "Journal", j.get("description"), j.get("total_debit"), "General Ledger") for j in journals]
    search_index += [search_row("VAT Return", str(r.get("period_end") or "VAT return"), r.get("status"), r.get("box5"), "VAT") for r in vat.get("returns", [])]

    assistant_answers = {
        "What needs my attention first?": (work_queue["high"][0]["detail"] if work_queue["high"] else "There is no high priority work in the current accounting workspace."),
        "Are bank transactions reconciled?": f"{unreconciled} bank transactions are unreconciled and {awaiting_match} have suggested matches.",
        "Is VAT ready?": f"Current VAT period: {vat_dashboard.get('current_period') or '-'}; net VAT due: {vat_dashboard.get('net_vat_due') or '0.00'}; outstanding returns: {vat_outstanding}.",
        "How is cash looking?": f"Cash at bank is {report_dashboard.get('cash_at_bank') or summary.get('bank_balance') or '0.00'}. Outstanding debtors are {ar_dashboard.get('outstanding_total') or '0.00'} and creditors are {ap_dashboard.get('outstanding_total') or '0.00'}.",
    }

    return {
        "kpis": [
            {"label": "Documents Awaiting Review", "value": ap_dashboard.get("draft_invoices", 0) + ar_awaiting, "module": "AI Workspace"},
            {"label": "Purchase Invoices Awaiting Approval", "value": ap_awaiting, "module": "Accounts Payable"},
            {"label": "Sales Invoices Awaiting Approval", "value": ar_awaiting, "module": "Accounts Receivable"},
            {"label": "Bank Transactions Awaiting Reconciliation", "value": unreconciled, "module": "Banking"},
            {"label": "VAT Return Status", "value": "Due" if vat_outstanding else "Current", "module": "VAT"},
            {"label": "Overdue Customer Invoices", "value": ar_overdue, "module": "Accounts Receivable"},
            {"label": "Overdue Supplier Bills", "value": ap_overdue, "module": "Accounts Payable"},
            {"label": "Cash Position", "value": report_dashboard.get("cash_at_bank") or summary.get("bank_balance") or "0.00", "module": "Reports"},
            {"label": "Profit This Month", "value": report_dashboard.get("net_profit") or reports.get("profit_and_loss", {}).get("profit") or "0.00", "module": "Reports"},
        ],
        "work_queue": work_queue,
        "insights": insights,
        "exceptions": exceptions,
        "approvals": approvals,
        "deadlines": sorted(deadlines, key=lambda item: str(item.get("due_date") or "9999-99-99")),
        "health_check": {"score": health_score, "categories": health_categories, "exception_count": len(exceptions)},
        "assistant": {"suggested_questions": list(assistant_answers.keys()), "answers": assistant_answers},
        "global_search": {"index": search_index[:500]},
        "notifications": (work_queue["high"] + exceptions)[:12],
        "settings": {
            "default_landing_tab": "Overview",
            "kpi_visibility": [item["label"] for item in [
                {"label": "Documents Awaiting Review"},
                {"label": "Bank Transactions Awaiting Reconciliation"},
                {"label": "VAT Return Status"},
                {"label": "Cash Position"},
                {"label": "Profit This Month"},
            ]],
            "work_queue_priorities": ["High", "Medium", "Low"],
            "assistant_mode": "Rule-based now, LLM-ready later",
        },
    }


def pick_csv_value(row: dict, candidates: list[str]) -> str:
    lookup = {str(k or "").strip().lower(): v for k, v in row.items()}
    for candidate in candidates:
        if candidate in lookup and lookup[candidate] not in (None, ""):
            return str(lookup[candidate]).strip()
    return ""


def parse_bank_csv_amount(value: str) -> Decimal:
    text_value = str(value or "").strip()
    if not text_value:
        return Decimal("0.00")
    negative = text_value.startswith("(") and text_value.endswith(")")
    text_value = text_value.replace("£", "").replace(",", "").replace("(", "").replace(")", "")
    parsed = money(text_value)
    return -parsed if negative else parsed


def normalize_csv_date(value: str) -> str:
    text_value = str(value or "").strip()
    if not text_value:
        return datetime.now(timezone.utc).date().isoformat()
    for fmt in ("%Y-%m-%d", "%d/%m/%Y", "%d-%m-%Y", "%d.%m.%Y", "%d/%m/%y", "%d-%m-%y"):
        try:
            return datetime.strptime(text_value, fmt).date().isoformat()
        except ValueError:
            pass
    return text_value


def add_months_to_date(value: date, months: int) -> date:
    month_index = value.month - 1 + months
    year = value.year + month_index // 12
    month = month_index % 12 + 1
    last_day = calendar.monthrange(year, month)[1]
    return date(year, month, min(value.day, last_day))


def parse_iso_date(value: str, field_name: str) -> date:
    try:
        return datetime.fromisoformat(str(value or "")[:10]).date()
    except Exception:
        raise HTTPException(status_code=400, detail=f"{field_name} must be a valid date.")


@api.get("/admin/automation")
async def get_automation_workspace(
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    return await automation_workspace(session)


@api.post("/admin/automation/workflows")
async def create_automation_workflow(
    payload: dict,
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    name = str(payload.get("name") or "").strip()
    trigger_type = str(payload.get("trigger_type") or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="Workflow name is required.")
    if not trigger_type:
        raise HTTPException(status_code=400, detail="Workflow trigger is required.")
    now = utc_now_iso()
    workflow_id = new_id()
    await session.execute(
        insert(automation_workflows).values(
            id=workflow_id,
            name=name,
            description=str(payload.get("description") or ""),
            trigger_type=trigger_type,
            status=str(payload.get("status") or "active"),
            permission_role=str(payload.get("permission_role") or "admin"),
            blocks_json=automation_json(payload.get("blocks") or []),
            conditions_json=automation_json(payload.get("conditions") or []),
            actions_json=automation_json(payload.get("actions") or []),
            approval_required=bool(payload.get("approval_required")),
            time_saved_minutes=int(payload.get("time_saved_minutes") or 10),
            created_by=str(user.get("id") or ""),
            created_at=now,
            updated_at=now,
        )
    )
    await add_accounting_audit(session, "platform", str(user.get("id") or ""), "automation_workflow_created", "automation", workflow_id, {"name": name})
    await session.commit()
    return {"workflow": serialize_automation_workflow((await one(session, select(automation_workflows).where(automation_workflows.c.id == workflow_id))) or {})}


@api.put("/admin/automation/workflows/{workflow_id}")
async def update_automation_workflow(
    workflow_id: str,
    payload: dict,
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    existing = await one(session, select(automation_workflows).where(automation_workflows.c.id == workflow_id))
    if not existing:
        raise HTTPException(status_code=404, detail="Workflow not found.")
    values = {
        "name": str(payload.get("name") or existing.get("name") or "").strip(),
        "description": str(payload.get("description") if payload.get("description") is not None else existing.get("description") or ""),
        "trigger_type": str(payload.get("trigger_type") or existing.get("trigger_type") or ""),
        "status": str(payload.get("status") or existing.get("status") or "active"),
        "permission_role": str(payload.get("permission_role") or existing.get("permission_role") or "admin"),
        "approval_required": bool(payload.get("approval_required")) if "approval_required" in payload else bool(existing.get("approval_required")),
        "time_saved_minutes": int(payload.get("time_saved_minutes") if payload.get("time_saved_minutes") is not None else existing.get("time_saved_minutes") or 0),
        "updated_at": utc_now_iso(),
    }
    if "blocks" in payload:
        values["blocks_json"] = automation_json(payload.get("blocks") or [])
    if "conditions" in payload:
        values["conditions_json"] = automation_json(payload.get("conditions") or [])
    if "actions" in payload:
        values["actions_json"] = automation_json(payload.get("actions") or [])
    await session.execute(update(automation_workflows).where(automation_workflows.c.id == workflow_id).values(**values))
    await add_accounting_audit(session, "platform", str(user.get("id") or ""), "automation_workflow_updated", "automation", workflow_id, {"name": values["name"], "status": values["status"]})
    await session.commit()
    return {"workflow": serialize_automation_workflow((await one(session, select(automation_workflows).where(automation_workflows.c.id == workflow_id))) or {})}


@api.post("/admin/automation/workflows/{workflow_id}/execute")
async def execute_automation_workflow(
    workflow_id: str,
    payload: dict = {},
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    workflow = await one(session, select(automation_workflows).where(automation_workflows.c.id == workflow_id))
    if not workflow:
        raise HTTPException(status_code=404, detail="Workflow not found.")
    if workflow.get("status") != "active":
        raise HTTPException(status_code=400, detail="Only active workflows can be executed.")
    run = await create_automation_run(session, workflow, str(user.get("id") or ""), payload or {"manual": True})
    await session.commit()
    return {"run": run, "workspace": await automation_workspace(session)}


@api.post("/admin/automation/approvals/{approval_id}/{action}")
async def resolve_automation_approval(
    approval_id: str,
    action: str,
    payload: dict = {},
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    if action not in {"approve", "reject"}:
        raise HTTPException(status_code=400, detail="Approval action must be approve or reject.")
    approval = await one(session, select(automation_approvals).where(automation_approvals.c.id == approval_id))
    if not approval:
        raise HTTPException(status_code=404, detail="Approval not found.")
    now = utc_now_iso()
    new_status = "approved" if action == "approve" else "rejected"
    await session.execute(
        update(automation_approvals)
        .where(automation_approvals.c.id == approval_id)
        .values(status=new_status, resolved_by=str(user.get("id") or ""), resolved_at=now)
    )
    run_status = "completed" if action == "approve" else "failed"
    run_result = "Approved and resumed" if action == "approve" else "Rejected by approver"
    await session.execute(
        update(automation_runs)
        .where(automation_runs.c.id == approval.get("run_id"))
        .values(status=run_status, result=run_result, finished_at=now)
    )
    if action == "reject":
        await session.execute(
            insert(automation_exceptions).values(
                id=new_id(),
                workflow_id=approval.get("workflow_id"),
                run_id=approval.get("run_id"),
                exception_type="approval_rejected",
                message=str(payload.get("reason") or "Approval was rejected."),
                status="open",
                payload_json=json.dumps({"approval_id": approval_id}, default=str),
                created_at=now,
            )
        )
    await add_accounting_audit(session, "platform", str(user.get("id") or ""), f"automation_approval_{new_status}", "automation", approval_id, {"run_id": approval.get("run_id")})
    await session.commit()
    return await automation_workspace(session)


@api.post("/admin/automation/exceptions/{exception_id}/{action}")
async def resolve_automation_exception(
    exception_id: str,
    action: str,
    payload: dict = {},
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    if action not in {"retry", "resolve"}:
        raise HTTPException(status_code=400, detail="Exception action must be retry or resolve.")
    exception = await one(session, select(automation_exceptions).where(automation_exceptions.c.id == exception_id))
    if not exception:
        raise HTTPException(status_code=404, detail="Exception not found.")
    now = utc_now_iso()
    if action == "resolve":
        await session.execute(
            update(automation_exceptions)
            .where(automation_exceptions.c.id == exception_id)
            .values(status="resolved", resolution=str(payload.get("resolution") or "Resolved by admin."), resolved_at=now)
        )
    else:
        await session.execute(
            update(automation_exceptions)
            .where(automation_exceptions.c.id == exception_id)
            .values(status="retried", resolution=str(payload.get("resolution") or "Retry requested."), resolved_at=now)
        )
        await session.execute(
            update(automation_runs)
            .where(automation_runs.c.id == exception.get("run_id"))
            .values(status="queued", result="Retry requested", finished_at=None)
        )
    await add_accounting_audit(session, "platform", str(user.get("id") or ""), f"automation_exception_{action}", "automation", exception_id, {"run_id": exception.get("run_id")})
    await session.commit()
    return await automation_workspace(session)


