async def next_ap_supplier_code(session: AsyncSession, client_id: str, name: str) -> str:
    base = re.sub(r"[^A-Z0-9]", "", str(name or "").upper())[:6] or "SUP"
    existing = await many(
        session,
        select(accounting_ap_supplier_profiles.c.supplier_code).where(accounting_ap_supplier_profiles.c.client_id == client_id),
    )
    existing_codes = {str(row.get("supplier_code") or "").upper() for row in existing}
    candidate = base
    counter = 1
    while candidate in existing_codes:
        counter += 1
        candidate = f"{base}{counter:02d}"[:64]
    return candidate


async def next_ap_invoice_number(session: AsyncSession, client_id: str, prefix: str = "PINV") -> str:
    today = datetime.now(timezone.utc).strftime("%Y%m%d")
    base = f"{prefix}-{today}"
    existing = await many(
        session,
        select(accounting_ap_invoices.c.invoice_number).where(
            accounting_ap_invoices.c.client_id == client_id,
            accounting_ap_invoices.c.invoice_number.like(f"{base}-%"),
        ),
    )
    existing_numbers = {str(row.get("invoice_number") or "").upper() for row in existing}
    counter = 1
    while True:
        candidate = f"{base}-{counter:03d}"
        if candidate.upper() not in existing_numbers:
            return candidate
        counter += 1


async def create_native_ap_supplier_profile(
    session: AsyncSession,
    client_id: str,
    payload: dict,
    actor_id: Optional[str],
) -> dict:
    client = await get_client_or_404(session, client_id)
    if not is_native_accounting_client(client):
        raise HTTPException(status_code=400, detail="Enable EPOS native accounting before creating suppliers.")
    name = str(payload.get("supplier_name") or payload.get("vendor_name") or payload.get("name") or payload.get("trading_name") or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="Supplier name is required.")
    ap_settings = await ensure_ap_settings(session, client_id)
    supplier_code = str(payload.get("supplier_code") or payload.get("vendor_account") or "").strip()
    existing_contact = await one(
        session,
        select(accounting_contacts).where(
            accounting_contacts.c.client_id == client_id,
            accounting_contacts.c.contact_type == "supplier",
            func.lower(accounting_contacts.c.name) == name.lower(),
        ),
    )
    if not supplier_code and existing_contact and existing_contact.get("account_code"):
        supplier_code = str(existing_contact.get("account_code") or "").strip()
    if not supplier_code:
        supplier_code = await next_ap_supplier_code(session, client_id, name)
    now = utc_now_iso()
    if existing_contact:
        contact_updates = {
            "email": str(payload.get("supplier_email") or payload.get("email") or existing_contact.get("email") or "").strip(),
            "account_code": str(supplier_code or existing_contact.get("account_code") or "").strip(),
            "active": True,
            "updated_at": now,
        }
        await session.execute(update(accounting_contacts).where(accounting_contacts.c.id == existing_contact["id"]).values(**contact_updates))
        contact = {**existing_contact, **contact_updates}
    else:
        contact = {
            "id": new_id(),
            "client_id": client_id,
            "contact_type": "supplier",
            "name": name,
            "email": str(payload.get("supplier_email") or payload.get("email") or "").strip(),
            "external_id": "",
            "account_code": supplier_code,
            "active": True,
            "raw_json": json.dumps({"source": "submitted_items_review"}),
            "created_at": now,
            "updated_at": now,
        }
        await session.execute(insert(accounting_contacts).values(**contact))
    existing_profile = await one(
        session,
        select(accounting_ap_supplier_profiles).where(
            accounting_ap_supplier_profiles.c.client_id == client_id,
            accounting_ap_supplier_profiles.c.contact_id == contact["id"],
        ),
    )
    try:
        payment_terms_days = int(payload.get("payment_terms_days") or ap_settings.get("default_payment_terms_days") or 30)
    except (TypeError, ValueError):
        raise HTTPException(status_code=400, detail="Supplier payment terms must be a number.")
    values = {
        "supplier_code": supplier_code,
        "trading_name": str(payload.get("trading_name") or name).strip(),
        "phone": str(payload.get("phone") or "").strip(),
        "website": str(payload.get("website") or "").strip(),
        "vat_number": str(payload.get("supplier_vat_number") or payload.get("vat_number") or "").strip(),
        "company_number": str(payload.get("company_number") or "").strip(),
        "payment_terms_days": payment_terms_days,
        "default_currency": str(payload.get("currency") or ap_settings.get("default_currency") or "GBP").strip().upper()[:8],
        "default_purchase_account": nominal_account_code_value(payload.get("default_purchase_account") or payload.get("category"), ap_settings.get("default_purchase_account") or "5000"),
        "default_vat_code": vat_code_value(payload.get("default_vat_code") or payload.get("vat_code") or ap_settings.get("default_vat_code")),
        "status": "active",
        "notes": str(payload.get("notes") or "").strip(),
        "updated_at": now,
    }
    if values["default_vat_code"]:
        await validate_native_vat_code(session, client_id, values["default_vat_code"])
    if existing_profile:
        await session.execute(update(accounting_ap_supplier_profiles).where(accounting_ap_supplier_profiles.c.id == existing_profile["id"]).values(**values))
        profile = {**existing_profile, **values}
    else:
        profile = {"id": new_id(), "client_id": client_id, "contact_id": contact["id"], "created_at": now, **values}
        await session.execute(insert(accounting_ap_supplier_profiles).values(**profile))
    await add_accounting_audit(session, client_id, actor_id, "supplier_saved", "accounts_payable", profile["id"], {"name": name, "source": "submitted_items_review"})
    return serialize_ap_supplier(profile, contact)


async def native_ap_supplier_page(
    session: AsyncSession,
    client_id: str,
    page: int = 1,
    page_size: int = 50,
    search: Optional[str] = None,
    status: Optional[str] = None,
) -> dict:
    page, page_size = pagination_params(page, page_size)
    conditions: list[Any] = [accounting_ap_supplier_profiles.c.client_id == client_id]
    if status and str(status).lower() not in {"all", ""}:
        conditions.append(accounting_ap_supplier_profiles.c.status == str(status).lower())
    if search:
        like = f"%{search}%"
        matching_contacts = await many(
            session,
            select(accounting_contacts.c.id)
            .where(
                accounting_contacts.c.client_id == client_id,
                accounting_contacts.c.contact_type == "supplier",
                or_(accounting_contacts.c.name.ilike(like), accounting_contacts.c.email.ilike(like), accounting_contacts.c.account_code.ilike(like)),
            )
            .limit(500),
        )
        contact_ids = [str(row.get("id")) for row in matching_contacts]
        profile_search = or_(accounting_ap_supplier_profiles.c.supplier_code.ilike(like), accounting_ap_supplier_profiles.c.trading_name.ilike(like))
        conditions.append(or_(profile_search, accounting_ap_supplier_profiles.c.contact_id.in_(contact_ids)) if contact_ids else profile_search)
    rows, total = await paginated_select(
        session,
        accounting_ap_supplier_profiles,
        conditions,
        [accounting_ap_supplier_profiles.c.supplier_code.asc(), accounting_ap_supplier_profiles.c.created_at.asc()],
        page,
        page_size,
    )
    row_contact_ids = [str(row.get("contact_id")) for row in rows if row.get("contact_id")]
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.id.in_(row_contact_ids))) if row_contact_ids else []
    contact_by_id = {str(contact.get("id")): contact for contact in contacts}
    serialized = [serialize_ap_supplier(row, contact_by_id.get(str(row.get("contact_id"))) or {}) for row in rows]
    return paginated_payload(serialized, page, page_size, total, {"supplier_count": total})


async def ap_supplier_match_suggestions(session: AsyncSession, client_id: str, fields: dict, limit: int = 5) -> dict:
    supplier_id = str(fields.get("supplier_id") or "").strip()
    if supplier_id:
        supplier = await get_ap_supplier_or_404(session, client_id, supplier_id)
        contact = await one(session, select(accounting_contacts).where(accounting_contacts.c.id == supplier.get("contact_id")))
        return {"matched": True, "requires_action": False, "suggestions": [serialize_ap_supplier(supplier, contact or {})]}
    supplier_name = str(fields.get("supplier_name") or fields.get("vendor_name") or "").strip().lower()
    supplier_code = str(fields.get("supplier_code") or fields.get("vendor_account") or "").strip().lower()
    supplier_email = str(fields.get("supplier_email") or fields.get("email") or "").strip().lower()
    supplier_vat = str(fields.get("supplier_vat_number") or fields.get("vat_number") or "").strip().lower()
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.client_id == client_id, accounting_contacts.c.contact_type == "supplier"))
    profiles = await many(session, select(accounting_ap_supplier_profiles).where(accounting_ap_supplier_profiles.c.client_id == client_id))
    contact_by_id = {str(contact.get("id")): contact for contact in contacts}
    suggestions = []
    for profile in profiles:
        contact = contact_by_id.get(str(profile.get("contact_id"))) or {}
        name = str(contact.get("name") or profile.get("trading_name") or "").lower()
        code = str(contact.get("account_code") or profile.get("supplier_code") or "").lower()
        email = str(contact.get("email") or "").lower()
        vat = str(profile.get("vat_number") or "").lower()
        score = 0
        reasons = []
        if supplier_code and supplier_code == code:
            score += 95
            reasons.append("supplier_code")
        if supplier_email and supplier_email == email:
            score += 90
            reasons.append("email")
        if supplier_vat and supplier_vat == vat:
            score += 90
            reasons.append("vat_number")
        if supplier_name and supplier_name == name:
            score += 85
            reasons.append("name")
        elif supplier_name and name and (supplier_name in name or name in supplier_name):
            score += 55
            reasons.append("partial_name")
        if score:
            suggestions.append({**serialize_ap_supplier(profile, contact), "match_score": min(score, 100), "match_reasons": reasons})
    suggestions.sort(key=lambda row: int(row.get("match_score") or 0), reverse=True)
    matched = bool(suggestions and int(suggestions[0].get("match_score") or 0) >= 85)
    return {"matched": matched, "requires_action": not matched, "suggestions": suggestions[:limit]}


async def create_ap_invoice_record(
    session: AsyncSession,
    client_id: str,
    payload: dict,
    actor_id: Optional[str] = None,
) -> dict:
    conn = await session.connection()
    await ensure_table_columns(conn, (accounting_ap_invoices, accounting_ap_invoice_lines, accounting_ap_credit_notes, accounting_ap_payments))
    client = await get_client_or_404(session, client_id)
    if not is_native_accounting_client(client):
        raise HTTPException(status_code=400, detail="Enable EPOS native accounting before adding purchase invoices.")
    ap_settings = await ensure_ap_settings(session, client_id)
    settings_row = await ensure_accounting_settings(session, client_id)
    supplier_id = str(payload.get("supplier_id") or "").strip()
    supplier = None
    if supplier_id:
        supplier = await get_ap_supplier_or_404(session, client_id, supplier_id)
    else:
        supplier_name = str(payload.get("supplier_name") or payload.get("vendor_name") or "").strip()
        if not supplier_name:
            raise HTTPException(status_code=400, detail="Supplier is required.")
        contact = await get_or_create_native_contact(session, client_id, supplier_name, "supplier")
        profile = await one(session, select(accounting_ap_supplier_profiles).where(accounting_ap_supplier_profiles.c.contact_id == contact["id"]))
        if not profile:
            now = utc_now_iso()
            profile = {
                "id": new_id(),
                "client_id": client_id,
                "contact_id": contact["id"],
                "supplier_code": contact.get("account_code") or "",
                "trading_name": contact.get("name"),
                "payment_terms_days": int(ap_settings.get("default_payment_terms_days") or 30),
                "default_currency": str(payload.get("currency") or "GBP")[:8],
                "default_purchase_account": ap_settings.get("default_purchase_account") or "5000",
                "default_vat_code": ap_settings.get("default_vat_code") or "",
                "status": "active",
                "created_at": now,
                "updated_at": now,
            }
            await session.execute(insert(accounting_ap_supplier_profiles).values(**profile))
        supplier = serialize_ap_supplier(profile, contact)
    invoice_number = str(payload.get("invoice_number") or payload.get("bill_number") or payload.get("number") or "").strip()
    if not invoice_number:
        if bool(ap_settings.get("automatic_invoice_numbering")):
            invoice_number = f"PINV-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M%S')}"
        else:
            raise HTTPException(status_code=400, detail="Invoice number is required.")
    duplicate = await one(
        session,
        select(accounting_ap_invoices).where(
            accounting_ap_invoices.c.client_id == client_id,
            accounting_ap_invoices.c.supplier_id == supplier["id"],
            func.lower(accounting_ap_invoices.c.invoice_number) == invoice_number.lower(),
            accounting_ap_invoices.c.status != "void",
        ),
    )
    if duplicate and bool(ap_settings.get("duplicate_invoice_warning", True)):
        raise HTTPException(status_code=409, detail={"has_warning": True, "message": f"Possible duplicate: supplier already has invoice {invoice_number}.", "matches": [serialize_ap_invoice(duplicate)]})
    invoice_date = parse_ap_document_date(payload.get("invoice_date") or payload.get("date"), "Invoice date").isoformat()
    due_date_raw = payload.get("due_date")
    if due_date_raw:
        due_date = parse_ap_document_date(due_date_raw, "Due date").isoformat()
    else:
        due_date = (date.fromisoformat(invoice_date) + timedelta(days=int(supplier.get("payment_terms_days") or ap_settings.get("default_payment_terms_days") or 30))).isoformat()
    try:
        payment_terms_days = int(payload.get("payment_terms_days") or supplier.get("payment_terms_days") or ap_settings.get("default_payment_terms_days") or 30)
    except (TypeError, ValueError):
        payment_terms_days = int(ap_settings.get("default_payment_terms_days") or 30)
    default_purchase_account = supplier.get("default_purchase_account") or settings_row.get("default_purchase_account") or "5000"
    header_vat_code = vat_code_value(first_present(payload, "vat_code", "tax_code", "tax_rate_code"))
    lines = [ap_line_values(line, default_purchase_account) for line in (payload.get("lines") or [])]
    if not lines:
        lines = [
            ap_line_values(
                {
                    "description": payload.get("description") or invoice_number,
                    "net_amount": payload.get("net_amount") or payload.get("net"),
                    "vat_amount": payload.get("vat_amount") or payload.get("vat"),
                    "gross_amount": payload.get("gross_amount") or payload.get("total"),
                    "vat_code": header_vat_code or supplier.get("default_vat_code") or ap_settings.get("default_vat_code"),
                    "nominal_account_code": first_present(payload, "nominal_account_code", "purchase_nominal_account_code", "purchase_account_code", "account_code", "category_code", "category"),
                },
                default_purchase_account,
            )
        ]
    header_vat_code = await validate_native_vat_codes_for_document(session, client_id, header_vat_code, lines, "Purchase invoice")
    totals = validate_ap_document_totals(payload, lines, "Purchase invoice")
    now = utc_now_iso()
    status = "awaiting_approval" if bool(ap_settings.get("approval_required", True)) else "approved"
    row = {
        "id": new_id(),
        "client_id": client_id,
        "supplier_id": supplier["id"],
        "contact_id": supplier.get("contact_id"),
        "invoice_number": invoice_number,
        "reference": str(payload.get("reference") or "").strip(),
        "invoice_date": invoice_date,
        "due_date": due_date,
        "payment_terms_days": payment_terms_days,
        "currency": str(payload.get("currency") or supplier.get("default_currency") or "GBP")[:8],
        "status": status,
        "description": str(payload.get("description") or "").strip(),
        "outstanding_amount": totals["gross_amount"],
        "vat_code": header_vat_code,
        "source_submission_id": str(payload.get("source_submission_id") or "").strip(),
        "attachment_path": str(payload.get("attachment_path") or "").strip(),
        "original_filename": str(payload.get("original_filename") or payload.get("filename") or "").strip()[:255],
        "extracted_json": json.dumps(payload.get("extracted_json") or {}, default=str),
        "created_at": now,
        "updated_at": now,
        **totals,
    }
    await session.execute(insert(accounting_ap_invoices).values(**row))
    for index, line in enumerate(lines, start=1):
        await session.execute(insert(accounting_ap_invoice_lines).values(id=new_id(), client_id=client_id, invoice_id=row["id"], line_number=index, created_at=now, updated_at=now, **line))
    await add_accounting_audit(session, client_id, actor_id, "purchase_invoice_created", "accounts_payable", row["id"], {"invoice_number": invoice_number, "status": status})
    return serialize_ap_invoice(row, lines, supplier)


