async def create_ar_customer_profile(session: AsyncSession, client_id: str, payload: dict, actor_id: Optional[str]) -> dict:
    client = await get_client_or_404(session, client_id)
    if not is_native_accounting_client(client):
        raise HTTPException(status_code=400, detail="Enable EPOS native accounting before creating customers.")
    name = str(payload.get("business_name") or payload.get("name") or payload.get("trading_name") or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="Customer business name is required.")
    ar_settings = await ensure_ar_settings(session, client_id)
    customer_code = str(payload.get("customer_code") or payload.get("customer_reference") or payload.get("account_code") or "").strip()
    email = str(payload.get("email") or payload.get("customer_email") or "").strip()
    match_conditions = [func.lower(accounting_contacts.c.name) == name.lower()]
    if email:
        match_conditions.append(func.lower(accounting_contacts.c.email) == email.lower())
    if customer_code:
        match_conditions.append(func.lower(accounting_contacts.c.account_code) == customer_code.lower())
    existing_contact = await one(
        session,
        select(accounting_contacts).where(
            accounting_contacts.c.client_id == client_id,
            accounting_contacts.c.contact_type == "customer",
            or_(*match_conditions),
        ),
    )
    if not customer_code and existing_contact and existing_contact.get("account_code"):
        customer_code = str(existing_contact.get("account_code") or "").strip()
    if not customer_code and bool(ar_settings.get("automatic_customer_numbering", True)):
        customer_code = await next_ar_customer_code(session, client_id, name)
    now = utc_now_iso()
    contact = existing_contact or {
        "id": new_id(),
        "client_id": client_id,
        "contact_type": "customer",
        "name": name,
        "email": email,
        "external_id": str(payload.get("external_id") or "").strip(),
        "account_code": customer_code,
        "active": bool(payload.get("active", True)),
        "raw_json": json.dumps({"source": "native_ar"}),
        "created_at": now,
        "updated_at": now,
    }
    if not existing_contact:
        await session.execute(insert(accounting_contacts).values(**contact))
    else:
        contact_updates = {
            "email": str(email or existing_contact.get("email") or "").strip(),
            "account_code": str(customer_code or existing_contact.get("account_code") or "").strip(),
            "active": bool(payload.get("active", existing_contact.get("active", True))),
            "updated_at": now,
        }
        await session.execute(update(accounting_contacts).where(accounting_contacts.c.id == existing_contact["id"]).values(**contact_updates))
        contact = {**existing_contact, **contact_updates}
    existing_profile = await one(session, select(accounting_ar_customer_profiles).where(accounting_ar_customer_profiles.c.client_id == client_id, accounting_ar_customer_profiles.c.contact_id == contact["id"]))
    values = {
        "customer_code": str(customer_code or contact.get("account_code") or "").strip(),
        "trading_name": str(payload.get("trading_name") or name).strip(),
        "phone": str(payload.get("phone") or "").strip(),
        "website": str(payload.get("website") or "").strip(),
        "vat_number": str(payload.get("customer_vat_number") or payload.get("vat_number") or "").strip(),
        "company_number": str(payload.get("company_number") or "").strip(),
        "payment_terms_days": int(payload.get("payment_terms_days") or ar_settings.get("default_payment_terms_days") or 30),
        "default_currency": str(payload.get("default_currency") or "GBP").strip().upper()[:8],
        "default_sales_account": str(payload.get("default_sales_account") or ar_settings.get("default_sales_account") or "4000"),
        "default_vat_code": vat_code_value(payload.get("default_vat_code") or ar_settings.get("default_vat_code")),
        "credit_limit": money_str(money(payload.get("credit_limit"))),
        "status": str(payload.get("status") or ("active" if bool(payload.get("active", True)) else "inactive")),
        "notes": str(payload.get("notes") or "").strip(),
        "updated_at": now,
    }
    if values["default_vat_code"]:
        await validate_native_vat_code(session, client_id, values["default_vat_code"])
    if existing_profile:
        await session.execute(update(accounting_ar_customer_profiles).where(accounting_ar_customer_profiles.c.id == existing_profile["id"]).values(**values))
        profile = {**existing_profile, **values}
    else:
        profile = {"id": new_id(), "client_id": client_id, "contact_id": contact["id"], "created_at": now, **values}
        await session.execute(insert(accounting_ar_customer_profiles).values(**profile))
    await add_accounting_audit(session, client_id, actor_id, "customer_saved", "accounts_receivable", profile["id"], {"name": name})
    return serialize_ar_customer(profile, contact)


async def create_ar_invoice_record(session: AsyncSession, client_id: str, payload: dict, actor_id: Optional[str]) -> dict:
    conn = await session.connection()
    await ensure_table_columns(conn, (accounting_ar_invoices, accounting_ar_invoice_lines))
    client = await get_client_or_404(session, client_id)
    if not is_native_accounting_client(client):
        raise HTTPException(status_code=400, detail="Enable EPOS native accounting before adding sales invoices.")
    ar_settings = await ensure_ar_settings(session, client_id)
    settings_row = await ensure_accounting_settings(session, client_id)
    customer_id = str(payload.get("customer_id") or "").strip()
    customer = await get_ar_customer_or_404(session, client_id, customer_id) if customer_id else None
    if not customer and str(payload.get("source_submission_id") or "").strip():
        raise HTTPException(status_code=400, detail="Select or create a customer before publishing to Accounts Receivable.")
    if not customer:
        customer = await create_ar_customer_profile(session, client_id, payload, actor_id)
    invoice_number = str(payload.get("invoice_number") or "").strip()
    next_number = int(ar_settings.get("next_invoice_number") or 1)
    if not invoice_number:
        prefix = str(ar_settings.get("invoice_number_prefix") or "SINV")
        while True:
            invoice_number = f"{prefix}{next_number:05d}"
            existing_number = await one(session, select(accounting_ar_invoices.c.id).where(accounting_ar_invoices.c.client_id == client_id, func.lower(accounting_ar_invoices.c.invoice_number) == invoice_number.lower()))
            if not existing_number:
                break
            next_number += 1
        await session.execute(update(accounting_ar_settings).where(accounting_ar_settings.c.client_id == client_id).values(next_invoice_number=next_number + 1, updated_at=utc_now_iso()))
    elif bool(ar_settings.get("duplicate_invoice_warning", True)) and not bool(payload.get("allow_duplicate")):
        duplicate = await one(session, select(accounting_ar_invoices).where(accounting_ar_invoices.c.client_id == client_id, accounting_ar_invoices.c.customer_id == customer["id"], func.lower(accounting_ar_invoices.c.invoice_number) == invoice_number.lower()))
        if duplicate:
            raise HTTPException(status_code=409, detail={"has_warning": True, "message": "A sales invoice with this number already exists for this customer.", "matches": [serialize_ar_invoice(duplicate)]})
    invoice_date = parse_date_or_today(payload.get("invoice_date") or payload.get("date")).isoformat()
    try:
        payment_terms_days = int(payload.get("payment_terms_days") or customer.get("payment_terms_days") or ar_settings.get("default_payment_terms_days") or 30)
    except (TypeError, ValueError):
        payment_terms_days = int(ar_settings.get("default_payment_terms_days") or 30)
    due_date = str(payload.get("due_date") or (date.fromisoformat(invoice_date) + timedelta(days=payment_terms_days)).isoformat())
    default_account = customer.get("default_sales_account") or ar_settings.get("default_sales_account") or settings_row.get("default_sales_account") or "4000"
    lines = [ar_line_values(line, default_account) for line in (payload.get("lines") or [])]
    if not lines:
        lines = [ar_line_values({"description": payload.get("description") or invoice_number, "net_amount": payload.get("net_amount"), "vat_amount": payload.get("vat_amount"), "gross_amount": payload.get("gross_amount"), "vat_code": payload.get("vat_code")}, default_account)]
    header_vat_code = await validate_native_vat_codes_for_document(session, client_id, payload.get("vat_code"), lines, "Sales invoice")
    totals = validate_ar_document_totals(payload, lines, "Sales invoice")
    now = utc_now_iso()
    status = "awaiting_approval" if bool(ar_settings.get("approval_required", True)) else "approved"
    row = {
        "id": new_id(),
        "client_id": client_id,
        "customer_id": customer["id"],
        "contact_id": customer.get("contact_id"),
        "invoice_number": invoice_number,
        "reference": str(payload.get("reference") or "").strip(),
        "invoice_date": invoice_date,
        "due_date": due_date,
        "payment_terms_days": payment_terms_days,
        "currency": str(payload.get("currency") or customer.get("default_currency") or "GBP").strip().upper()[:8],
        "description": str(payload.get("description") or "").strip(),
        "status": status,
        "outstanding_amount": totals["gross_amount"],
        "vat_code": header_vat_code,
        "source_submission_id": str(payload.get("source_submission_id") or "").strip(),
        "attachment_path": str(payload.get("attachment_path") or "").strip(),
        "original_filename": str(payload.get("original_filename") or payload.get("filename") or "").strip()[:255],
        "extracted_json": json.dumps(payload.get("extracted_json") or payload.get("extracted") or {}, default=str),
        "created_at": now,
        "updated_at": now,
        **totals,
    }
    await session.execute(insert(accounting_ar_invoices).values(**row))
    for index, line in enumerate(lines, start=1):
        await session.execute(insert(accounting_ar_invoice_lines).values(id=new_id(), client_id=client_id, invoice_id=row["id"], line_number=index, created_at=now, updated_at=now, **line))
    await add_accounting_audit(session, client_id, actor_id, "sales_invoice_created", "accounts_receivable", row["id"], {"invoice_number": invoice_number, "status": row["status"]})
    return serialize_ar_invoice(row, lines, customer)


def sales_submission_fields(submission: dict, reviewed_fields: Optional[dict] = None) -> dict:
    ai_fields = parse_json_object(submission.get("ai_extracted_fields")) or {}
    coding_fields = parse_json_object(submission.get("coding_fields")) or {}
    source = {**ai_fields, **coding_fields, **(reviewed_fields or {})}
    lines = source.get("lines") if isinstance(source.get("lines"), list) else source.get("line_items")
    if not isinstance(lines, list):
        lines = []
    normalized_lines = []
    for line in lines[:100]:
        if not isinstance(line, dict):
            continue
        normalized_lines.append(
            {
                "description": str(line.get("description") or "").strip(),
                "quantity": str(line.get("quantity") or line.get("units") or "1").strip(),
                "unit_price": str(line.get("unit_price") or line.get("price") or "").strip(),
                "net_amount": str(line.get("net_amount") or line.get("net") or "").strip(),
                "vat_code": str(line.get("vat_code") or source.get("vat_code") or "").strip(),
                "vat_amount": str(line.get("vat_amount") or line.get("vat") or "").strip(),
                "gross_amount": str(line.get("gross_amount") or line.get("gross") or line.get("total") or "").strip(),
                "nominal_account_code": str(line.get("nominal_account_code") or line.get("sales_account_code") or line.get("account_code") or line.get("category") or source.get("sales_account_code") or source.get("category") or "").strip(),
                "sales_account_code": str(line.get("sales_account_code") or line.get("nominal_account_code") or line.get("account_code") or line.get("category") or source.get("sales_account_code") or source.get("category") or "").strip(),
            }
        )
    if not normalized_lines and (source.get("net_amount") or source.get("net") or source.get("gross_amount") or source.get("total") or submission.get("amount")):
        normalized_lines.append(
            {
                "description": str(source.get("description") or submission.get("description") or source.get("invoice_number") or "Sales invoice").strip(),
                "quantity": "1",
                "unit_price": str(source.get("net_amount") or source.get("net") or source.get("gross_amount") or source.get("total") or submission.get("amount") or "").strip(),
                "net_amount": str(source.get("net_amount") or source.get("net") or "").strip(),
                "vat_code": str(source.get("vat_code") or "").strip(),
                "vat_amount": str(source.get("vat_amount") or source.get("vat") or "").strip(),
                "gross_amount": str(source.get("gross_amount") or source.get("gross") or source.get("total") or submission.get("amount") or "").strip(),
                "nominal_account_code": str(source.get("nominal_account_code") or source.get("sales_account_code") or source.get("category") or "").strip(),
                "sales_account_code": str(source.get("sales_account_code") or source.get("nominal_account_code") or source.get("category") or "").strip(),
            }
        )
    try:
        payment_terms_days = int(source.get("payment_terms_days") or 30)
    except (TypeError, ValueError):
        payment_terms_days = 30
    fields = {
        "customer_id": str(source.get("customer_id") or "").strip(),
        "customer_name": str(source.get("customer_name") or source.get("customer_business_name") or source.get("buyer_name") or source.get("bill_to_name") or source.get("invoice_to_name") or source.get("sold_to_name") or source.get("business_name") or "").strip(),
        "customer_email": str(source.get("customer_email") or source.get("email") or "").strip(),
        "customer_vat_number": str(source.get("customer_vat_number") or source.get("vat_number") or "").strip(),
        "customer_address": source.get("customer_address") or source.get("address") or "",
        "customer_reference": str(source.get("customer_reference") or source.get("account_code") or source.get("customer_code") or "").strip(),
        "account_code": str(source.get("account_code") or source.get("customer_reference") or source.get("customer_code") or "").strip(),
        "create_new_customer": bool(source.get("create_new_customer")),
        "invoice_number": str(source.get("invoice_number") or source.get("bill_number") or source.get("reference") or "").strip(),
        "invoice_date": str(source.get("invoice_date") or source.get("date") or submission.get("date") or "").strip(),
        "due_date": str(source.get("due_date") or "").strip(),
        "payment_terms_days": payment_terms_days,
        "currency": str(source.get("currency") or "GBP").strip().upper()[:8] or "GBP",
        "net_amount": str(source.get("net_amount") or source.get("net") or "").strip(),
        "vat_amount": str(source.get("vat_amount") or source.get("vat") or "").strip(),
        "gross_amount": str(source.get("gross_amount") or source.get("gross") or source.get("total") or submission.get("amount") or "").strip(),
        "vat_code": str(source.get("vat_code") or "").strip(),
        "sales_account_code": str(source.get("sales_account_code") or source.get("nominal_account_code") or source.get("category") or "").strip(),
        "description": str(source.get("description") or submission.get("description") or "").strip(),
        "lines": normalized_lines,
        "line_items": normalized_lines,
        "field_confidence_scores": source.get("field_confidence_scores") if isinstance(source.get("field_confidence_scores"), dict) else {},
        "overall_confidence": source.get("overall_confidence") or submission.get("ai_review_status") or "",
        "corrected_fields": source.get("corrected_fields") if isinstance(source.get("corrected_fields"), dict) else {},
        "correction_history": source.get("correction_history") if isinstance(source.get("correction_history"), list) else [],
        "low_confidence_warnings": source.get("low_confidence_warnings") if isinstance(source.get("low_confidence_warnings"), list) else [],
        "reviewer_notes": str(source.get("reviewer_notes") or "").strip(),
        "document_type": "customer_credit_note" if str(source.get("document_type") or "").strip().lower() in {"customer_credit_note", "customer_credit", "sales_credit_note"} else "sales_invoice",
        "document_direction": "sales",
        "accounting_destination": "epos_native_ar",
    }
    return fields


def sales_submission_payload_for_ar(submission: dict, fields: dict, allow_duplicate: bool = False) -> dict:
    return {
        "customer_id": fields.get("customer_id"),
        "business_name": fields.get("customer_name"),
        "name": fields.get("customer_name"),
        "email": fields.get("customer_email"),
        "customer_code": fields.get("customer_reference") or fields.get("account_code"),
        "payment_terms_days": fields.get("payment_terms_days"),
        "default_sales_account": fields.get("sales_account_code"),
        "invoice_number": fields.get("invoice_number"),
        "reference": fields.get("customer_reference") or fields.get("invoice_number"),
        "invoice_date": fields.get("invoice_date") or submission.get("date"),
        "due_date": fields.get("due_date"),
        "currency": fields.get("currency") or "GBP",
        "net_amount": fields.get("net_amount"),
        "vat_amount": fields.get("vat_amount"),
        "gross_amount": fields.get("gross_amount") or submission.get("amount"),
        "vat_code": fields.get("vat_code"),
        "description": fields.get("description") or submission.get("description"),
        "lines": [
            {
                "description": line.get("description"),
                "quantity": line.get("quantity"),
                "unit_price": line.get("unit_price"),
                "net_amount": line.get("net_amount"),
                "vat_amount": line.get("vat_amount"),
                "gross_amount": line.get("gross_amount"),
                "vat_code": line.get("vat_code"),
                "nominal_account_code": line.get("nominal_account_code") or line.get("sales_account_code"),
            }
            for line in fields.get("lines", [])
        ],
        "source_submission_id": str(submission["id"]),
        "attachment_path": submission.get("image_filename") or "",
        "original_filename": submission.get("original_filename") or submission.get("image_filename") or "",
        "extracted_json": fields,
        "allow_duplicate": allow_duplicate,
    }


async def native_ar_customer_page(
    session: AsyncSession,
    client_id: str,
    page: int = 1,
    page_size: int = 50,
    search: Optional[str] = None,
    status: Optional[str] = None,
) -> dict:
    page, page_size = pagination_params(page, page_size)
    conditions: list[Any] = [accounting_ar_customer_profiles.c.client_id == client_id]
    if status and str(status).lower() not in {"all", ""}:
        conditions.append(accounting_ar_customer_profiles.c.status == str(status).lower())
    if search:
        like = f"%{search}%"
        matching_contacts = await many(
            session,
            select(accounting_contacts.c.id)
            .where(
                accounting_contacts.c.client_id == client_id,
                accounting_contacts.c.contact_type == "customer",
                or_(accounting_contacts.c.name.ilike(like), accounting_contacts.c.email.ilike(like), accounting_contacts.c.account_code.ilike(like)),
            )
            .limit(500),
        )
        contact_ids = [str(row.get("id")) for row in matching_contacts]
        profile_search = or_(accounting_ar_customer_profiles.c.customer_code.ilike(like), accounting_ar_customer_profiles.c.trading_name.ilike(like))
        conditions.append(or_(profile_search, accounting_ar_customer_profiles.c.contact_id.in_(contact_ids)) if contact_ids else profile_search)
    rows, total = await paginated_select(
        session,
        accounting_ar_customer_profiles,
        conditions,
        [accounting_ar_customer_profiles.c.customer_code.asc(), accounting_ar_customer_profiles.c.created_at.asc()],
        page,
        page_size,
    )
    row_contact_ids = [str(row.get("contact_id")) for row in rows if row.get("contact_id")]
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.id.in_(row_contact_ids))) if row_contact_ids else []
    contact_by_id = {str(contact.get("id")): contact for contact in contacts}
    serialized = [serialize_ar_customer(row, contact_by_id.get(str(row.get("contact_id"))) or {}) for row in rows]
    return paginated_payload(serialized, page, page_size, total, {"customer_count": total})


async def sales_customer_match_suggestions(session: AsyncSession, client_id: str, fields: dict, limit: int = 5) -> dict:
    customer_id = str(fields.get("customer_id") or "").strip()
    if customer_id:
        customer = await get_ar_customer_or_404(session, client_id, customer_id)
        contact = await one(session, select(accounting_contacts).where(accounting_contacts.c.id == customer.get("contact_id")))
        return {"matched": True, "requires_action": False, "suggestions": [serialize_ar_customer(customer, contact or {})]}
    customer_name = str(fields.get("customer_name") or "").strip().lower()
    customer_email = str(fields.get("customer_email") or "").strip().lower()
    customer_reference = str(fields.get("customer_reference") or fields.get("account_code") or "").strip().lower()
    customer_vat = str(fields.get("customer_vat_number") or fields.get("vat_number") or "").strip().lower()
    contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.client_id == client_id, accounting_contacts.c.contact_type == "customer"))
    profiles = await many(session, select(accounting_ar_customer_profiles).where(accounting_ar_customer_profiles.c.client_id == client_id))
    contact_by_id = {str(contact.get("id")): contact for contact in contacts}
    suggestions = []
    for profile in profiles:
        contact = contact_by_id.get(str(profile.get("contact_id"))) or {}
        name = str(contact.get("name") or profile.get("trading_name") or "").lower()
        email = str(contact.get("email") or "").lower()
        code = str(contact.get("account_code") or profile.get("customer_code") or "").lower()
        vat = str(profile.get("vat_number") or "").lower()
        score = 0
        reasons = []
        if customer_reference and customer_reference == code:
            score += 95
            reasons.append("account_code")
        if customer_email and customer_email == email:
            score += 90
            reasons.append("email")
        if customer_vat and customer_vat == vat:
            score += 90
            reasons.append("vat_number")
        if customer_name and customer_name == name:
            score += 85
            reasons.append("name")
        elif customer_name and (customer_name in name or name in customer_name):
            score += 55
            reasons.append("partial_name")
        if score:
            suggestions.append({**serialize_ar_customer(profile, contact), "match_score": min(score, 100), "match_reasons": reasons})
    suggestions.sort(key=lambda row: int(row.get("match_score") or 0), reverse=True)
    matched = bool(suggestions and suggestions[0].get("match_score", 0) >= 85)
    return {"matched": matched, "requires_action": not matched, "suggestions": suggestions[:limit]}


async def sales_duplicate_warning(session: AsyncSession, client_id: str, fields: dict) -> dict:
    invoice_number = str(fields.get("invoice_number") or "").strip()
    customer_id = str(fields.get("customer_id") or "").strip()
    customer_name = str(fields.get("customer_name") or "").strip().lower()
    gross_amount = money(fields.get("gross_amount"))
    if not invoice_number:
        return {"has_warning": False, "severity": "none", "matches": [], "message": ""}
    conditions = [
        accounting_ar_invoices.c.client_id == client_id,
        func.lower(accounting_ar_invoices.c.invoice_number) == invoice_number.lower(),
        accounting_ar_invoices.c.status != "void",
    ]
    if customer_id:
        conditions.append(accounting_ar_invoices.c.customer_id == customer_id)
    candidates = await many(session, select(accounting_ar_invoices).where(and_(*conditions)).limit(20))
    if not customer_id and customer_name and candidates:
        customer_ids = list({str(row.get("customer_id")) for row in candidates if row.get("customer_id")})
        profiles = await many(session, select(accounting_ar_customer_profiles).where(accounting_ar_customer_profiles.c.id.in_(customer_ids))) if customer_ids else []
        contacts = await many(session, select(accounting_contacts).where(accounting_contacts.c.id.in_([row.get("contact_id") for row in profiles]))) if profiles else []
        contact_by_id = {str(contact.get("id")): contact for contact in contacts}
        profile_by_id = {str(profile.get("id")): profile for profile in profiles if customer_name in str((contact_by_id.get(str(profile.get("contact_id"))) or {}).get("name") or profile.get("trading_name") or "").lower()}
        candidates = [row for row in candidates if str(row.get("customer_id")) in profile_by_id]
    matches = []
    for row in candidates:
        amount_match = gross_amount == Decimal("0.00") or money(row.get("gross_amount")) == gross_amount
        matches.append(
            {
                "invoice_id": row.get("id"),
                "customer_id": row.get("customer_id"),
                "invoice_number": row.get("invoice_number"),
                "gross_amount": row.get("gross_amount"),
                "invoice_date": row.get("invoice_date"),
                "status": row.get("status"),
                "amount_match": amount_match,
            }
        )
    has_warning = bool(matches)
    return {
        "has_warning": has_warning,
        "severity": "warning" if has_warning else "none",
        "matches": matches,
        "message": f"Possible duplicate sales invoice {invoice_number} found in Accounts Receivable." if has_warning else "",
    }


def append_submission_route_event(existing_value: Optional[str], event: dict) -> str:
    history = parse_json_object(existing_value) or {"events": []}
    events = history.get("events") if isinstance(history.get("events"), list) else []
    events.append({"at": utc_now_iso(), **event})
    history["events"] = events[-100:]
    return json.dumps(history)


def submission_route(submission: dict, coding_fields: Optional[dict] = None) -> str:
    fields = coding_fields or {}
    stored_type = str(submission.get("type") or "").strip().lower()
    stored_direction = str(submission.get("document_direction") or "").strip().lower()
    if stored_type == "sales" or stored_direction == "sales":
        return "sales"
    if stored_type == "purchase" or stored_direction == "purchase":
        return "purchase"
    route = str(
        fields.get("route")
        or fields.get("document_direction")
        or ""
    ).strip().lower()
    doc_type = str(fields.get("document_type") or "").strip().lower()
    if route in {"sales", "sales_invoice", "customer_credit_note"} or doc_type in {"sales_invoice", "customer_credit_note"}:
        return "sales"
    if route in {"purchase", "purchase_invoice", "bill", "supplier_credit_note"} or doc_type in {"bill", "purchase_invoice", "supplier_credit_note"}:
        return "purchase"
    if route in {"unclassified", "receipt", "receipt_payment_evidence", "not_accounting_document", "needs_more_information"}:
        return "unclassified"
    return "unclassified"


def normalize_submission_review_status(status: str, route: str, fields: Optional[dict] = None) -> str:
    value = str(status or "").strip().lower()
    if value == "needs_clarification":
        return "needs_review"
    if value == "published":
        if route not in {"purchase", "sales"}:
            return "needs_review"
        return "published_to_ar" if route == "sales" else "published_to_ap"
    if value == "reviewed":
        if route == "sales":
            fields = fields or {}
            return "sales_ready_to_publish" if fields.get("invoice_number") and fields.get("customer_id") else "sales_review"
        if route != "purchase":
            return "needs_review"
        return "purchase_ready_to_publish"
    return value


def accounting_publish_contract(accounting_publish: Optional[dict]) -> dict:
    if not accounting_publish:
        return {}
    entity = accounting_publish.get("entity")
    destination = accounting_publish.get("destination")
    if not destination:
        destination = "accounts_receivable" if entity == "SalesInvoice" else "accounts_payable" if entity == "PurchaseInvoice" else ""
    return {
        **accounting_publish,
        "provider": accounting_publish.get("provider") or "epos_native",
        "destination": destination,
        "id": accounting_publish.get("id"),
        "reference": accounting_publish.get("reference") or accounting_publish.get("doc_number"),
        "status": accounting_publish.get("status"),
        "gross_amount": accounting_publish.get("gross_amount"),
    }


def submitted_item_publish_response(accounting_publish: dict, invoice: Optional[dict] = None, already_published: bool = False) -> dict:
    contract = accounting_publish_contract(accounting_publish)
    entity = contract.get("entity")
    route = "sales" if entity == "SalesInvoice" else "purchase"
    destination = "accounts_receivable" if route == "sales" else "accounts_payable"
    publish_status = "published_to_ar" if route == "sales" else "published_to_ap"
    invoice_id_key = "ar_invoice_id" if route == "sales" else "ap_invoice_id"
    return {
        "ok": True,
        "route": route,
        "destination": destination,
        "publish_status": publish_status,
        invoice_id_key: contract.get("id"),
        "invoice": invoice or {},
        "summary": contract,
        "accounting_publish": contract,
        "already_published": already_published,
    }


@api.post("/admin/accounting/clients/{client_id}/ap/suppliers")
async def create_ap_supplier(
    client_id: str,
    payload: dict,
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    client = await get_client_or_404(session, client_id)
    if not is_native_accounting_client(client):
        raise HTTPException(status_code=400, detail="Enable EPOS native accounting before adding suppliers.")
    name = str(payload.get("name") or payload.get("trading_name") or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="Supplier name is required.")
    existing_contact = await one(
        session,
        select(accounting_contacts).where(
            accounting_contacts.c.client_id == client_id,
            accounting_contacts.c.contact_type == "supplier",
            func.lower(accounting_contacts.c.name) == name.lower(),
        ),
    )
    now = utc_now_iso()
    contact = existing_contact or {
        "id": new_id(),
        "client_id": client_id,
        "contact_type": "supplier",
        "name": name,
        "email": str(payload.get("email") or "").strip(),
        "external_id": str(payload.get("external_id") or "").strip(),
        "account_code": str(payload.get("supplier_code") or "").strip(),
        "active": bool(payload.get("active", True)),
        "raw_json": json.dumps({"source": "native_ap"}),
        "created_at": now,
        "updated_at": now,
    }
    if not existing_contact:
        await session.execute(insert(accounting_contacts).values(**contact))
    else:
        await session.execute(
            update(accounting_contacts)
            .where(accounting_contacts.c.id == existing_contact["id"])
            .values(
                email=str(payload.get("email") or existing_contact.get("email") or "").strip(),
                account_code=str(payload.get("supplier_code") or existing_contact.get("account_code") or "").strip(),
                active=bool(payload.get("active", existing_contact.get("active", True))),
                updated_at=now,
            )
        )
        contact = {**existing_contact, "email": str(payload.get("email") or existing_contact.get("email") or "").strip(), "account_code": str(payload.get("supplier_code") or existing_contact.get("account_code") or "").strip()}
    ap_settings = await ensure_ap_settings(session, client_id)
    profile = {
        "id": new_id(),
        "client_id": client_id,
        "contact_id": contact["id"],
        "supplier_code": str(payload.get("supplier_code") or contact.get("account_code") or "").strip(),
        "trading_name": str(payload.get("trading_name") or name).strip(),
        "phone": str(payload.get("phone") or "").strip(),
        "website": str(payload.get("website") or "").strip(),
        "vat_number": str(payload.get("vat_number") or "").strip(),
        "company_number": str(payload.get("company_number") or "").strip(),
        "payment_terms_days": int(payload.get("payment_terms_days") or ap_settings.get("default_payment_terms_days") or 30),
        "default_currency": str(payload.get("default_currency") or "GBP").strip().upper()[:8],
        "default_purchase_account": str(payload.get("default_purchase_account") or ap_settings.get("default_purchase_account") or "5000"),
        "default_vat_code": vat_code_value(payload.get("default_vat_code") or ap_settings.get("default_vat_code")),
        "bank_name": str(payload.get("bank_name") or "").strip(),
        "bank_sort_code": str(payload.get("bank_sort_code") or "").strip(),
        "bank_account_number": str(payload.get("bank_account_number") or "").strip(),
        "cis_registered": bool(payload.get("cis_registered", False)),
        "reverse_charge": bool(payload.get("reverse_charge", False)),
        "status": "active" if bool(payload.get("active", True)) else "inactive",
        "notes": str(payload.get("notes") or "").strip(),
        "created_at": now,
        "updated_at": now,
    }
    if profile["default_vat_code"]:
        await validate_native_vat_code(session, client_id, profile["default_vat_code"])
    await session.execute(insert(accounting_ap_supplier_profiles).values(**profile))
    await add_accounting_audit(session, client_id, user.get("id"), "supplier_created", "accounts_payable", profile["id"], {"name": name})
    await session.commit()
    return serialize_ap_supplier(profile, contact)


