@api.post("/admin/accounting/clients/{client_id}/bank/transfers")
async def create_bank_transfer(
    client_id: str,
    payload: dict,
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    accounts = await ensure_native_accounting_client(session, client_id)
    from_account = await resolve_bank_card_or_404(session, client_id, str(payload.get("from_bank_account_id") or ""))
    to_account = await resolve_bank_card_or_404(session, client_id, str(payload.get("to_bank_account_id") or ""))
    if bank_card_matches_id(from_account, str(to_account.get("id") or "")):
        raise HTTPException(status_code=400, detail="Choose two different bank accounts.")
    amount = money(payload.get("amount"))
    if amount <= 0:
        raise HTTPException(status_code=400, detail="Transfer amount must be greater than zero.")
    transfer_date = parse_date_or_today(payload.get("transfer_date")).isoformat()
    from_nominal = find_native_account(accounts, from_account.get("nominal_account_code"), "1200")
    to_nominal = find_native_account(accounts, to_account.get("nominal_account_code"), "1200")
    transfer_id = new_id()
    journal = await post_native_journal(
        session,
        client_id,
        "bank_transfer",
        transfer_id,
        transfer_date,
        str(payload.get("reference") or f"Transfer {transfer_date}"),
        f"Transfer from {from_account.get('account_name')} to {to_account.get('account_name')}",
        [
            {"account": to_nominal, "debit": money_str(amount), "credit": "0.00", "description": "Bank transfer"},
            {"account": from_nominal, "debit": "0.00", "credit": money_str(amount), "description": "Bank transfer"},
        ],
        user.get("id"),
    )
    now = utc_now_iso()
    row = {"id": transfer_id, "client_id": client_id, "from_bank_account_id": from_account.get("bank_account_id") or from_account.get("id") or from_account.get("account_id"), "to_bank_account_id": to_account.get("bank_account_id") or to_account.get("id") or to_account.get("account_id"), "transfer_date": transfer_date, "reference": str(payload.get("reference") or ""), "amount": money_str(amount), "status": "posted", "posted_journal_id": journal.get("id"), "created_at": now, "updated_at": now}
    await session.execute(insert(accounting_bank_transfers).values(**row))
    await add_accounting_audit(session, client_id, user.get("id"), "bank_transfer_posted", "banking", transfer_id, row)
    await session.commit()
    return serialize_bank_transfer(row)


@api.post("/admin/accounting/clients/{client_id}/vat-returns/prepare")
async def prepare_native_vat_return(
    client_id: str,
    payload: dict,
    user: dict = Depends(require_admin),
    session: AsyncSession = Depends(get_db),
):
    client = await get_client_or_404(session, client_id)
    if not is_native_accounting_client(client):
        raise HTTPException(status_code=400, detail="Enable EPOS native accounting before preparing VAT returns.")
    period_start = str(payload.get("period_start") or "").strip()
    period_end = str(payload.get("period_end") or "").strip()
    period_id = str(payload.get("period_id") or "").strip()
    if period_id:
        period = await one(session, select(accounting_vat_periods).where(accounting_vat_periods.c.client_id == client_id, accounting_vat_periods.c.id == period_id))
        if not period:
            raise HTTPException(status_code=404, detail="VAT period not found.")
        period_start = str(period.get("period_start") or "")
        period_end = str(period.get("period_end") or "")
    if not period_start or not period_end:
        raise HTTPException(status_code=400, detail="Period start and end are required.")
    transactions = [
        item for item in await vat_transactions_for_client(session, client_id)
        if period_start <= str(item.get("date") or "") <= period_end
    ]
    boxes = calculate_vat_boxes(transactions)
    now = utc_now_iso()
    row = {
        "id": new_id(),
        "client_id": client_id,
        "period_start": period_start,
        "period_end": period_end,
        "status": "draft",
        "vat_due_sales": money_str(boxes["box1"] + boxes["box2"]),
        "vat_reclaimed_purchases": money_str(boxes["box4"]),
        "net_vat_due": money_str(boxes["box5"]),
        "sales_net": money_str(boxes["box6"] + boxes["box8"]),
        "purchase_net": money_str(boxes["box7"] + boxes["box9"]),
        "box1": money_str(boxes["box1"]),
        "box2": money_str(boxes["box2"]),
        "box3": money_str(boxes["box3"]),
        "box4": money_str(boxes["box4"]),
        "box5": money_str(boxes["box5"]),
        "box6": money_str(boxes["box6"]),
        "box7": money_str(boxes["box7"]),
        "box8": money_str(boxes["box8"]),
        "box9": money_str(boxes["box9"]),
        "prepared_json": json.dumps({"transaction_count": len(transactions), "source": "vat_engine"}),
        "created_at": now,
        "updated_at": now,
    }
    await session.execute(insert(accounting_vat_returns).values(**row))
    if period_id:
        await session.execute(update(accounting_vat_periods).where(accounting_vat_periods.c.id == period_id).values(status="locked", output_vat=row["vat_due_sales"], input_vat=row["vat_reclaimed_purchases"], net_vat=row["net_vat_due"], transaction_count=len(transactions), updated_at=now))
    await add_accounting_audit(session, client_id, user.get("id"), "vat_return_prepared", "vat_return", row["id"], row)
    await session.commit()
    return serialize_vat_return(row)


